  !****************************************************************************
  !*
  !*  ABSTRACT: This subroutine is an error handling routine for NetCDF-
  !*      related functions.
  !*
  !****************************************************************************
  subroutine handle_netcdf_err (status)

    implicit none

    include "netcdf.inc"

    integer :: status

    if (status /= nf_noerr) then
      print *, ' '
      print *, 'Tracker NetCDF error: '
      print *, nf_strerror(status)
      stop 'Stopped'
    endif

  end subroutine handle_netcdf_err

  !****************************************************************************
  !*
  !*  ABSTRACT: This subroutine checks the bitmap for non-existent data values.
  !*      Since the data from the regional models have been interpolated
  !*      from either a polar stereographic or lambert conformal grid
  !*      onto a lat/lon grid, there will be some gridpoints around the
  !*      edges of this lat/lon grid that have no data; these grid
  !*      points have been bitmapped out by Mark Iredell's interpolater.
  !*      To provide another means of checking for invalid data points
  !*      later in the program, set these bitmapped data values to a
  !*      value of -999.0.  The min and max of this array are also
  !*      returned if a user wants to check for reasonable values.
  !*
  !****************************************************************************
  subroutine bitmapchk (n, ld, d, dmin, dmax)

    implicit none

    logical(1) :: ld
    dimension  :: ld(n), d(n) !CAITLYN - i have never seen this data type before

    dmin = 1.0E15
    dmax = -1.0E15

    do i = 1, n
      if (ld(i)) then
        dmin = min(dmin, d(i))
        dmax = max(dmax, d(i))
      else
        d(i) = -999.0
      endif
    enddo

    return

  end subroutine bitmapchk

  !****************************************************************************
  !*
  !*  ABSTRACT: This subroutine converts a 1-dimensional input
  !*      array of logical data (lb1d) into a 2-dimensional output
  !*      array (dimension imax,jmax) of logical data (lb2d).
  !*
  !*  This subroutine was updated in 6/2000 to add the scanning mode
  !*      flag (iscanflag) as an input.  This is in order to handle grids
  !*      that are flipped.  Most grids -- NCEP, UKMET, ECMWF -- have
  !*      point (1,1) as the uppermost left point on the grid, and the
  !*      data goes from north to south.  Some grids -- GFDL and the new
  !*      NAVGEM grid -- are flipped; their point (1,1) is the lowermost
  !*      left point, and their data goes from south to north.  So if
  !*      the scanning mode flag indicates northward scanning data
  !*      (bit 2 in the flag is turned on), we catch it in this
  !*      subroutine and flip the data ourselves for our own arrays,
  !*      since this whole program is structured around the data going
  !*      from north to south.  As of the writing of this, only the
  !*      first 3 bits of the scanning flag are used, which is why we
  !*      can use the mod statement in the code below.
  !*
  !*  INPUT:
  !*      imax      :: Number of gridpoints in i direction in input box
  !*      jmax      :: Number of gridpoints in j direction in input box
  !*      lb1d      :: 1-d array containing logical bitmap values
  !*      iscanflag :: This is kgds(11), an integer value in the GDS,
  !*                   which holds the scanning mode for the data values
  !*
  !*  OUTPUT:
  !*      lb2d      :: 2-d array containing logical bitmap values
  !*
  !****************************************************************************
  subroutine conv1d2d_logic (imax, jmax, lb1d, lb2d, need_to_flip_lats)

    implicit none

    logical(1) :: lb1d(imax*jmax), lb2d(imax,jmax)
    logical(1) :: need_to_flip_lats
    integer    :: ilat, ilatix, ilon, imax, jmax

    if (need_to_flip_lats) then
      ! input data is south to north; flip the data while converting to 2-d grid
      do ilat = 1, jmax
        ilatix = jmax - ilat + 1
        do ilon = 1, imax
          lb2d(ilon, ilatix) = lb1d(ilon + (ilat-1) * imax)
        enddo
      enddo
    else
      ! Input data is north to south; convert the data onto a 2-d grid, do not flip it
      do ilat = 1, jmax
        do ilon = 1, imax
          lb2d(ilon, ilat) = lb1d(ilon + (ilat - 1) * imax)
        enddo
      enddo
    endif

    return

  end subroutine conv1d2d_logic

  !****************************************************************************
  !*
  !*  ABSTRACT: The purpose of this routine is to create a 2-d logical
  !*      bitmap to be used for masking out regions with missing data,
  !*      such as for a regional grid with irregular boundaries (such as
  !*      we've seen for the regional / nested FV3).  This bitmap will
  !*      have the same functionality as a GRIB1/GRIB2 bitmap.  The trick
  !*      is that NetCDF does not have a logical bitmap within its
  !*      definition, so we need to make one.  We do this by reading in
  !*      the "missing_value" attribute for any variable, then here we
  !*      scan through all the data values retrieved from the NetCDF read,
  !*      and then for all grid points with missing values we set the
  !*      valid_pt flag to .false.
  !*
  !*  Note the use of the need_to_flip_lats flag.  This is in order to
  !*      handle grids that are flipped.  Most grids -- NCEP, UKMET, ECMWF
  !*      -- have point (1,1) as the uppermost left point on the grid, and
  !*      the data goes from north to south.  Some grids -- GFDL and the
  !*      new NAVGEM grid -- are flipped; their point (1,1) is the lowermost
  !*      left point, and their data goes from south to north.  So if
  !*      the need_to_flip_lats flag was set to TRUE in getgridinfo, meaning
  !*      that we have northward scanning data, we catch it in this
  !*      subroutine and flip the data ourselves for our own arrays,
  !*      since this whole program is structured around the data going
  !*      from north to south.
  !*
  !*  INPUT:
  !*      imax              :: Number of gridpoints in i direction in input box
  !*      jmax              :: Number of gridpoints in j direction in input box
  !*      dat1d             :: 1-d array containing floating point data values
  !*      xmissing_val      :: real value of missing value for the given variable
  !*                           that was read in for the calling routine
  !*      need_to_flip_lats :: logical flag, set in getgridinfo, that
  !*                           indicates if data is correctly N-to-S, or if it is
  !*                           S-to-N and needs to be flipped.
  !*
  !*  OUTPUT:
  !*      lb2d              :: 2-d array containing logical bitmap values
  !*
  !****************************************************************************
  subroutine conv1d2d_logic_netcdf (imax, jmax, dat1d, lb2d, xmissing_val, need_to_flip_lats)

    use verbose_output

    implicit none

    logical(1) :: lb2d(imax,jmax)
    logical(1) :: need_to_flip_lats
    integer    :: ilat, ilatix, ilon, imax, jmax, tct, fct, mct
    real       :: dat1d(imax*jmax)
    real       :: xmissing_val

    tct = 0
    fct = 0
    mct = 0

    if (verb >= 3) then
      print *, ' '
      print *, 'TOP of conv1d2d_logic_netcdf, xmissing_val = ', xmissing_val
      print *, ' '
    endif

    if (need_to_flip_lats) then
      ! input data is south to north; flip the data while converting to 2-d grid
      do ilat = 1, jmax
        ilatix = jmax - ilat + 1
        do ilon = 1, imax
          if (dat1d(ilon + (ilat-1) * imax) == xmissing_val) then
            lb2d(ilon, ilatix) = .false.
            fct = fct + 1
          else
            lb2d(ilon, ilatix) = .true.
            tct = tct + 1
          endif
        enddo
      enddo

    else
      ! input data is north to south; convert the data onto a 2-d grid, do not flip it
      do ilat = 1, jmax
        do ilon = 1, imax
          if (dat1d(ilon + (ilat-1) * imax) == xmissing_val) then
            lb2d(ilon, ilat) = .false.
            fct = fct + 1
          else
            lb2d(ilon, ilat) = .true.
            tct = tct + 1
          endif
        enddo
      enddo
    endif

    print *, ' '
    print *, ' LB STATS: tct = ', tct, ' fct = ', fct, ' mct = ', mct

    return

  end subroutine conv1d2d_logic_netcdf

  !****************************************************************************
  !*
  !*  ABSTRACT: This subroutine converts a 1-dimensional input
  !*      array of real data (dat1d) into a 2-dimensional output
  !*      array (dimension imax,jmax) of real data (dat2d).
  !*
  !*  This subroutine was updated in 6/2000 to add the scanning mode
  !*      flag (iscanflag) as an input.  This is in order to handle grids
  !*      that are flipped.  Most grids -- NCEP, UKMET, ECMWF -- have
  !*      point (1,1) as the uppermost left point on the grid, and the
  !*      data goes from north to south.  Some grids -- GFDL and the new
  !*      NAVGEM grid -- are flipped; their point (1,1) is the lowermost
  !*      left point, and their data goes from south to north.  So if
  !*      the scanning mode flag indicates northward scanning data
  !*      (bit 2 in the flag is turned on), we catch it in this
  !*      subroutine and flip the data ourselves for our own arrays,
  !*      since this whole program is structured around the data going
  !*      from north to south.  As of the writing of this, only the
  !*      first 3 bits of the scanning flag are used, which is why we
  !*      can use the mod statement in the code below.
  !*
  !*
  !*  INPUT:
  !*      imax              :: Number of gridpoints in i direction in input box
  !*      jmax              :: Number of gridpoints in j direction in input box
  !*      dat1d             :: 1-d real array of data
  !*      need_to_flip_lats :: logical flag, set in getgridinfo, that
  !*                           indicates if data is correctly N-to-S, or if it is
  !*                           S-to-N and needs to be flipped.
  !*
  !*  OUTPUT:
  !*      dat2d             :: 2-d real array of data
  !*
  !****************************************************************************
  subroutine conv1d2d_real (imax, jmax, dat1d, dat2d, need_to_flip_lats)

    implicit none

    logical(1) :: need_to_flip_lats
    real       :: dat1d(imax*jmax), dat2d(imax,jmax)

    if (need_to_flip_lats) then

      ! input data is south to north; flip the data while converting to 2-d grid
      do ilat = 1, jmax
        ilatix = jmax - ilat + 1
        do ilon = 1, imax
          dat2d(ilon, ilatix) = dat1d(ilon + (ilat-1) * imax)
        enddo
      enddo

    else
      ! input data is north to south; convert the data onto a 2-d grid, do not flip it
      do ilat = 1, jmax
        do ilon = 1, imax
          dat2d(ilon, ilat) = dat1d(ilon + (ilat-1) * imax)
        enddo
      enddo
    endif

    return

  end subroutine conv1d2d_real

  !****************************************************************************
  !*
  !*  ABSTRACT: This subroutine converts a 1-dimensional input
  !*      array of real data (dat1d) into a 2-dimensional output
  !*      array (dimension imax,jmax) of real data (dat2d).
  !*
  !*  This subroutine was updated in 6/2000 to add the scanning mode
  !*      flag (iscanflag) as an input.  This is in order to handle grids
  !*      that are flipped.  Most grids -- NCEP, UKMET, ECMWF -- have
  !*      point (1,1) as the uppermost left point on the grid, and the
  !*      data goes from north to south.  Some grids -- GFDL and the new
  !*      NAVGEM grid -- are flipped; their point (1,1) is the lowermost
  !*      left point, and their data goes from south to north.  So if
  !*      the scanning mode flag indicates northward scanning data
  !*      (bit 2 in the flag is turned on), we catch it in this
  !*      subroutine and flip the data ourselves for our own arrays,
  !*      since this whole program is structured around the data going
  !*      from north to south.  As of the writing of this, only the
  !*      first 3 bits of the scanning flag are used, which is why we
  !*      can use the mod statement in the code below.
  !*
  !*  INPUT:
  !*      imax              :: Number of gridpoints in i direction in input box
  !*      jmax              :: Number of gridpoints in j direction in input box
  !*      dat1d             :: 1-d real array of data
  !*      need_to_flip_lats :: logical flag, set in getgridinfo, that
  !*                           indicates if data is correctly N-to-S, or if it is
  !*                           S-to-N and needs to be flipped.
  !*
  !*  OUTPUT:
  !*      dat2d             :: 2-d real array of data
  !*
  !****************************************************************************
  subroutine conv1d2d_real_netcdf (imax, jmax, dat1d, dat2d, need_to_flip_lats)

    implicit none

    logical(1) :: need_to_flip_lats
    real       :: dat1d(imax*jmax)
    real       :: dat2d(imax,jmax)

    if (need_to_flip_lats) then

      ! input data is south to north; flip the data while converting to 2-d grid
      do ilat = 1, jmax
        ilatix = jmax - ilat + 1
        do ilon = 1, imax
          dat2d(ilon, ilatix) = dat1d(ilon + (ilat-1) * imax)
        enddo
      enddo

    else
      ! input data is north to south; convert the data onto a 2-d grid, do not flip it
      do ilat = 1, jmax
        do ilon = 1, imax
          dat2d(ilon, ilat) = dat1d(ilon + (ilat-1) * imax)
        enddo
      enddo
    endif

    return
     !CAITLYN - can these be merged together?
  end subroutine conv1d2d_real_netcdf

  !****************************************************************************
  !*
  !*  ABSTRACT: This subroutine simply reads in the namelists that are
  !*      created in the shell script.  Namelist datein contains the
  !*      starting date information, plus the model identifier.  Namelist
  !*      stswitch contains the flags for processing for each storm.
  !*
  !****************************************************************************
  subroutine read_nlists (inp, trkrinfo, netcdfinfo, lunml)

    use inparms;             use set_max_parms;  use atcf;        use trkrparms; use phase
    use structure;           use gfilename_info; use contours;    use sst_diags
    use verbose_output;      use waitfor_parms;  use netcdf_parms
    use tracking_parm_prefs; use shear_diags;    use genesis_diags

    implicit none

    type (datecard)    :: inp
    type (trackstuff)  :: trkrinfo
    type (netcdfstuff) :: netcdfinfo
    logical(1)         :: namelist_file_exists
    integer            :: ifh, lunml

    namelist /datein_nml/       inp
    namelist /atcfinfo_nml/     atcfnum, atcfname, atcfymdh, atcffreq
    namelist /trackerinfo_nml/  trkrinfo
    namelist /phaseinfo_nml/    phaseflag, phasescheme, wcore_depth
    namelist /structinfo_nml/   structflag, ikeflag, radii_pctile, radii_free_pass_pctile, radii_width_thresh
    namelist /fnameinfo_nml/    gmodname, rundescr, atcfdescr
    namelist /cintinfo_nml/     contint_grid_bound_check
    namelist /verbose_nml/      verb, verb_g2
    namelist /waitinfo_nml/     use_waitfor, wait_min_age, wait_min_size, wait_max_wait, wait_sleeptime, &
                                use_per_fcst_command, per_fcst_command
    namelist /netcdflist_nml/   netcdfinfo
    namelist /parmpreflist_nml/ user_wants_to_track_zeta850, user_wants_to_track_zeta700, user_wants_to_track_wcirc850, &
                                user_wants_to_track_wcirc700, user_wants_to_track_gph850, user_wants_to_track_gph700,   &
                                user_wants_to_track_mslp, user_wants_to_track_wcircsfc, user_wants_to_track_zetasfc,    &
                                user_wants_to_track_thick500850, user_wants_to_track_thick200500, user_wants_to_track_thick200850
    namelist /sheardiaginfo_nml/ shearflag
    namelist /sstdiaginfo_nml/   sstflag
    namelist /gendiaginfo_nml/   genflag, gen_read_rh_fields, need_to_compute_rh_from_q, smoothe_mslp_for_gen_scan

    ! set namelist default values
    use_per_fcst_command   = 't'
    per_fcst_command       = ' '
    atcffreq               = 600
    trkrinfo%enable_timing = 1
    trkrinfo%want_oci      = .false.
    trkrinfo%gribver       = 1   ! set to GRIB1 as default, can be set to something else in the namelist input

    inquire (file = "namelist.gettrk", exist = namelist_file_exists)

    if (namelist_file_exists) then
      if (verb .ge. 3) then
        print *, ' '
        print *, '+++ Namelist file namelist.gettrk exists.'
        print *, 'Namelist file will be opened with unit = lunml = ', lunml
      endif

      open (unit = lunml, file = "namelist.gettrk", status = 'old', err = 787)

      if (verb .ge. 3) then
        print *, ' '
        print *, '+++ namelist.gettrk file has successfully'
        print *, '    been opened with unit = lunml = ', lunml
      endif
    else
      print *, ' '
      print *, '!!! ERROR in read_nlists.  The fortran inquire'
      print *, '!!! statement indicates that the namelist file for'
      print *, '!!! gettrk does NOT exist in this working directory.'
      print *, '!!! Check to see that there is a namelist file in '
      print *, '!!! the working directory named namelist.gettrk.'
      print *, '!!! STOPPING....'
      print *, ' '
      stop 99
      return
    endif

    read (lunml, nml = datein, END = 801)
801 continue
    read (lunml, nml = atcfinfo, END = 807)
807 continue
    print *, 'just before trackerinfo read namelist'
    read (lunml, nml = trackerinfo, END = 809)
809 continue
    print *, 'just after trackerinfo read namelist'
    read (lunml, nml = phaseinfo, end = 811)
811 continue
    read (lunml, nml = structinfo, end = 815)
815 continue
    read (lunml, nml = fnameinfo, end = 817)
817 continue
    read (lunml, nml = cintinfo, end = 831)
831 continue
    read (lunml, nml = waitinfo, end = 821)
821 continue
    read (lunml, nml = netcdflist, end = 823)
823 continue
    read (lunml, nml = parmpreflist, end = 825)
825 continue
    read (lunml, nml = verbose, end = 819, err = 833)
819 continue
    goto 837
833 continue
    verb = 1
837 continue
    read (lunml, nml = sheardiaginfo, end = 839)
839 continue
    read (lunml, nml = sstdiaginfo, end = 840)
840 continue
    read (lunml, nml = gendiaginfo, end = 841)
841 continue

    close (lunml)

    print *, 'in read_nlists, verb = ', verb

    if (verb .ge. 0) then
      print *, ' '
      print *, 'After datein namelist in trak.f, namelist parms follow:'
      print *, 'Forecast initial year                = byy      = ', inp%byy
      print *, 'Forecast initial month               = bmm      = ', inp%bmm
      print *, 'Forecast initial day                 = bdd      = ', inp%bdd
      print *, 'Forecast initial hour                = bhh      = ', inp%bhh
      print *, 'Forecast model identifier            = model    = ', inp%model
      print *, 'Forecast model type                  = modtyp   = ', inp%modtyp
      print *, 'Forecast model data lead time units  = lt_units = ', inp%lt_units
      print *, 'Forecast model data sequencing setup = file_seq = ', inp%file_seq
      print *, 'Forecast model nest type             = ',            inp%nesttyp

      print *, ' '
      print *, 'Values read in from atcfinfo namelist: '
      write (6,89) atcfnum, atcfname
      write (6,90) atcfymdh
      write (6,92) atcffreq
