      print *, 'Values read in from waitinfo namelist:'
      write (6,151) use_waitfor
      write (6,152) wait_min_age
      write (6,153) wait_min_size
      write (6,154) wait_max_wait
      write (6,155) wait_sleeptime
      if (len_trim(per_fcst_command) > 0) then
        write (6,156) trim(per_fcst_command)
      else
        ! no command specified, so disable the feature
        se_per_fcst_command = 'n'
      endif
 
 151  format ('Flag for input file waiting = use_waitfor = ', a1)
 152  format ('min age (time in seconds since last mod) = wait_min_age = ', i8)
 153  format ('min file size in bytes = wait_min_size = ', i12)
 154  format ('max number of seconds to wait for each file = wait_max_wait = ', i6)
 155  format ('number of seconds to sleep between checks = wait_sleeptime = ', i6)
 156  format ('command to run after every forecast time = "', A, '"')

      if (use_waitfor == 'y') then
        if (inp%file_seq == 'multi') then
          continue
        else
          print *, ' '
          print *, '!!! ERROR: The use_waitfor flag is set to "y".'
          print *, '    This requires that the inp%file_seq flag be'
          print *, '    set to "multi", but you have specified '
          print *, '    something else.  '
          print *, '    inp%file_seq = ', inp%file_seq
          print *, '    STOPPING....'
          print *, ' '
          STOP 95
        endif
      endif

      print *, ' '
      print *, 'Values read in from sheardiaginfo namelist: '
      write (6,161) shearflag
 161  format ('Shear flag = shearflag = ', a1)
      print *, ' '

      print *, ' '
      print *, 'Values read in from sstdiaginfo namelist: '
      write (6,162) sstflag
 162  format ('SST flag = sstflag = ', a1)
      print *, ' '

      print *, ' '
      print *, 'Values read in from gendiaginfo namelist: '
      write (6,163) genflag
 163  format ('Genesis flag = genflag = ', a1)
      write (6,165) gen_read_rh_fields
 165  format ('Flag to directly read RH fields = gen_read_rh_fields = ', a1)
      write (6,167) need_to_compute_rh_from_q
 167  format ('Flag for whether or not to compute RH from q = need_to_compute_rh_from_q = ', a1)
      write (6,169) smoothe_mslp_for_gen_scan
 169  format ('Flag for whether or not to smoothe the MSLP data before scanning for new storms = ', &
          // 'smoothe_mslp_for_gen_scan = ', a1)

      if (genflag == 'y' .or. genflag == 'Y') then
        genflag = 'y'
      else
        genflag = 'n'
      endif

      if (gen_read_rh_fields == 'y' .or. gen_read_rh_fields == 'Y') then
        gen_read_rh_fields = 'y'
      else
        gen_read_rh_fields = 'n'
      endif

      if (need_to_compute_rh_from_q == 'y' .or. need_to_compute_rh_from_q == 'Y') then
        need_to_compute_rh_from_q = 'y'
      else
        need_to_compute_rh_from_q = 'n'
      endif

      if (smoothe_mslp_for_gen_scan == 'y' .or. smoothe_mslp_for_gen_scan == 'Y') then
        smoothe_mslp_for_gen_scan = 'y'
      else
        smoothe_mslp_for_gen_scan = 'n'
      endif
    endif

    goto 944
787 continue

    if (verb .ge. 1) then
      print *, '!!!  '
      print *, '!!! ERROR in read_nlists opening gettrk namelist'
      print *, '!!! file named namelist.gettrk.  A file with'
      print *, '!!! that name needs to be in your working directory.'
      print *, '!!! It should contain the namelist needed for '
      print *, '!!! running the gettrk executable.'
    endif

    stop 97
    return

944 continue

    return

  end subroutine read_nlists

  !****************************************************************************
  !*
  !*  ABSTRACT: This subroutine reads in a text file that contains the
  !*      forecast times that will be read in.  The format of the file is
  !*      in "MMMMM", i.e., minutes, for example, for a forecast going out
  !*      to 120h, the file would look like this:
  !*
  !*  For reference, here are the times that match up 
  !*      with the minutes on the left:
  !*
  !*      1        0                    0:00
  !*      2      240                    4:00
  !*      3      270                    4:30
  !*      4      300                    5:00
  !*      5      330                    5:30
  !*      6      360                    6:00
  !*      7      600                   10:00
  !*      8      630                   10:30
  !*      9      660                   11:00
  !*     10      690                   11:30
  !*     11      720                   12:00
  !*     12      960                   16:00
  !*     13      990                   16:30
  !*      .       .                      .
  !*      .       .                      .
  !*      .       .                      .
  !*     87     7200                  120:00
  !*
  !*     Note that we are now allowing for sub-hourly time intervals.
  !*
  !****************************************************************************
  subroutine read_fhours (ifhmax)

    use tracked_parms; use verbose_output

    implicit none

    integer, parameter :: iunit_fh = 15
    integer            :: itmphrs(750), itmpmins(750), input_mins(750), itmpltix(750)
    integer            :: ifhmax, inphr, inpmin, ict, i, ifa, ifma, icma, ira, inpltix, ila
    real               :: xminfract

    itmphrs  = -99
    itmpmins = -99

    if (allocated(ifhours))      deallocate (ifhours)
    if (allocated(iftotalmins))  deallocate (iftotalmins)
    if (allocated(ifclockmins))  deallocate (ifclockmins)
    if (allocated(fhreal))       deallocate (fhreal)
    if (allocated(ltix))         deallocate (ltix)

    ict = 0
    do while (.true.)

      if (verb .ge. 3) then
        print *, 'Top of while loop in read_fhours'
      endif

      read (iunit_fh, 85, end = 130) inpltix, inpmin
      write (6,85) inpltix, inpmin

      if (inpmin >= 0 .and. inpmin < 150000) then
        ict             = ict + 1
        itmpltix(ict)   = inpltix
        itmphrs(ict)    = inpmin / 60
        itmpmins(ict)   = mod(inpmin, 60)
        input_mins(ict) = inpmin
      else
        if (verb .ge. 1) then
          print *, ' '
          print *, '!!! ERROR: Input minutes not between 0 and 150000'
          print *, '!!!        inpmin = ', inpmin
          print *, '!!! STOPPING EXECUTION'
        endif
        STOP 91
      endif

      if (verb .ge. 3) then
        print *, 'readloop, ict = ', ict, ' inpmin = ', inpmin
      endif

    enddo

130 continue

    ifhmax = ict

85  format (i4, 1x, i5)

    allocate (ifhours(ifhmax),     stat = ifa)
    allocate (iftotalmins(ifhmax), stat = ifma)
    allocate (ifclockmins(ifhmax), stat = icma)
    allocate (fhreal(ifhmax),      stat = ira)
    allocate (ltix(ifhmax),        stat = ila)

    if (ifa /= 0 .or. ifma /= 0 .or. icma /= 0 .or. ira /= 0 .or. ila /= 0) then
      if (verb .ge. 1) then
        print *, ' '
        print *, '!!! ERROR in read_fhours allocating either ifhours,'
        print *, '!!! iftotalmins, ifclockmins or fhreal.'
        print *, '!!! ifa  = ', ifa,  ' ifma = ', ifma, ' ira = ', ira
        print *, '!!! icma = ', icma, ' ila  = ',  ila
        print *, '!!! STOPPING EXECUTION'
      endif
      STOP 91
    endif

    do i = 1 , ifhmax
      ltix(i)        = itmpltix(i)
      xminfract      = real(itmpmins(i)) / 60.0
      fhreal(i)      = real(itmphrs(i)) + xminfract
      ifhours(i)     = itmphrs(i)
      ifclockmins(i) = itmpmins(i)
      iftotalmins(i) = input_mins(i)

      if (i > 1) then
        if (fhreal(i) > fhreal(i-1)) then
          continue
        else
          if (verb .ge. 3) then
            print *, ' '
            print *, '!!! ERROR: In read_fhours, the time read in '
            print *, '!!! is not greater than the previous time.'
            print *, '!!! i           = ', i
            print *, '!!! fhreal(i)   = ', fhreal(i)
            print *, '!!! fhreal(i-1) = ', fhreal(i-1)
            print *, '!!! STOPPING EXECUTION'
          endif
          STOP 91
        endif
      endif

      if (verb .ge. 3) then
        write (6,87) i, ltix(i), iftotalmins(i), fhreal(i), ifhours(i), ifclockmins(i)
      endif

    enddo

87  format (1x, 'i = ', i3, 'input lead time index = ', i4, ' minutes = ', i5, ' real_lead_time = ', &
           f6.2, ' clock_lead_time = ', i3, ':', i2)

    return

  end subroutine read_fhours

  !****************************************************************************
  !*
  !*  ABSTRACT: This subroutine reads in the updated TC Vitals file
  !*      for the current time and prints out those cards (storms)
  !*      that have been selected to be processed.  It also
  !*      takes the initial positions from the tcv card for each
  !*      storm and puts them into the slonfg & slatfg arrays.
  !*      Note that this routine is reading in vitals in the
  !*      standard format for TCs only.  Any genesis vitals are
  !*      read in in subroutine  read_gen_vitals.
  !*
  !*  INPUT:
  !*      lucard      :: integer unit number for tcvitals card
  !*      trkrinfo    :: derived type that contains info on the type of
  !*                     tracker run that we are performing.
  !*
  !*  OUTPUT:
  !*      maxstorm    :: max # of storms to be handled for this case
  !*      numtcv      :: number of storms read off of the input tcvitals file
  !*      iret        :: return code from this subroutine
  !*
  !*  OTHER:
  !*      stormswitch :: 1,2 or 3 (see more description under Main pgm section)
  !*      slonfg      :: first guess array for longitude
  !*      slatfg      :: first guess array for latitude
  !*      storm       :: contains the tcvitals info
  !*     
  !*      (storm, stormswitch, slonfg and slatfg are allocatable and are
  !*      defined in module def_vitals)
  !*
  !****************************************************************************
  subroutine read_tcv_card (lucard, maxstorm, trkrinfo, numtcv, iret)

    use def_vitals; use set_max_parms; use trkrparms; use verbose_output

    implicit none

    type (tcvcard)    :: tmpstorm(maxstorm_tc)
    type (trackstuff) :: trkrinfo
    logical(1)        :: vit_file_exists
    integer           :: isa, issa, ioa, iaa, ita, iret, ict, maxstorm
    integer           :: i, ii, lucard, numtcv


    ! check to see if the TC Vitals file exists. If so, then open it using the unit specified in lucard.
    inquire (file = "tcvit_rsmc_storms.txt", exist = vit_file_exists)

    if (vit_file_exists) then
      if (verb .ge. 3) then
        print *, ' '
        print *, '+++ TC Vitals file for existing, RSMC-numbered storms exists and will be opened with unit = '
        print *, 'lucard = ', lucard
      endif
      open (unit = lucard, file = "tcvit_rsmc_storms.txt", status = 'old', err = 887)
      if (verb .ge. 3) then
        print *, ' '
        print *, '+++ TC vitals file tcvit_rsmc_storms.txt has '
        print *, '    been opened with unit = lucard = ', lucard
      endif

    else
      if (trkrinfo%type == 'tracker') then
        if (verb .ge. 1) then
          print *, ' '
          print *, '!!! ERROR in read_tcv_card.  The fortran inquire'
          print *, '!!! statement indicates that the tcvitals file for'
          print *, '!!! already-existing, RSMC-numbered storms does '
          print *, '!!! NOT exist.  This TC Vitals file is needed for'
          print *, '!!! a tracker case.  Check to see that the '
          print *, '!!! TC Vitals file exists in this directory and'
          print *, '!!! is named tcvit_rsmc_storms.txt'
          print *, '!!! STOPPING....'
          print *, '!!! '
        endif
        iret = 99
        return

      else
        if (verb .ge. 1) then
          print *, ' '
          print *, '!!! NOTE:  In read_tcv_card, the fortran inquire'
          print *, '!!! statement indicates that the tcvitals file for'
          print *, '!!! already-existing, RSMC-numbered storms does '
          print *, '!!! NOT exist.  While this TC Vitals file is '
          print *, '!!! needed for tracker cases, you are running'
          print *, '!!! either a midlat or tcgen case here, and so '
          print *, '!!! that file is not needed... although you can '
          print *, '!!! run with using tc vitals for those genesis'
          print *, '!!! cases if you want to.  You may want to check'
          print *, '!!! and make sure this is what you intend.  If '
          print *, '!!! you do want to use it, the TC Vitals file '
          print *, '!!! should be in this directory and it should be'
          print *, '!!! named tcvit_rsmc_storms.txt'
          print *, '!!! '
        endif
      endif
    endif

    ii = 1

    if (vit_file_exists) then
      do while (.true. .and. ii <= maxstorm_tc)
        read (lucard, 21, end = 801, err = 891) tmpstorm(ii)
        ii = ii + 1
      enddo
21    format (a4, 1x, a3, 1x, a9, 1x, i8, 1x, i4, 1x, i3, a1, 1x, i4, a1, 1x, i3, 1x, i3, 3(1x, i4), 1x, i2, 1x, i3, &
              1x, 4(i4, 1x), a1)
801   continue
    endif

    numtcv = ii - 1

    if (trkrinfo%type == 'midlat' .or. trkrinfo%type == 'tcgen') then
      ! For the mid-latitude or tc genesis cases, the max number of storms (maxstorm) allowed 
      ! to be tracked throughout a forecast is defined in module set_max_parms.
      if (verb .ge. 3) then
        print *, ' '
        print *, 'In read_tcv_card, tracker type of "midlat" or '
        print *, '"tcgen" indicates that this run of the  tracker is'
        print *, 'for a midlat or a tcgen case....'
      endif

      maxstorm = maxstorm_mg

      allocate (stormswitch(maxstorm),     stat = isa)
      allocate (storm(maxstorm),           stat = issa)
      allocate (slonfg(maxstorm, maxtime), stat = ioa)
      allocate (slatfg(maxstorm, maxtime), stat = iaa)
      allocate (stcvtype(maxstorm),        stat = ita)

      if (isa /= 0 .or. ioa /= 0 .or. iaa /= 0 .or. issa /= 0 .or. ita /= 0) then
        if (verb .ge. 1) then
          print *, ' '
          print *, '!!! ERROR in read_tcv_card allocating stormswitch,'
          print *, '!!! slonfg, storm, slatfg or stcvtype arrays.  '
          print *, '!!! isa = ', isa,  ' ioa = ', ioa, ' iaa = ', iaa, ' issa = '
          print *, '!!! ',       issa, ' ita = ', ita
        endif
        iret = 97
        return
      endif

      slonfg      = 0.0; slatfg = 0.0
      stcvtype    = 'FOF'   ! Found On the Fly by tracker (not on tcvitals)
      stormswitch = 3       ! Initialize whole array to case of '3'

      if (numtcv > 0) then
        if (verb .ge. 3) then
          print *, ' '
          print *, 'Following are the already-existing storms that'
          print *, 'were read in from the tc vitals file: '
          print *, ' '
        endif

        ict = 0

        do i = 1, numtcv
          stormswitch(i) = 1
          storm(i)       = tmpstorm(i)
          ict = ict + 1

          if (verb .ge. 3) then
            write (*,31) storm(i)
          endif

          if (storm(i)%tcv_lonew == 'W') then
            slonfg(i, 1) =  360.0 - real(storm(i)%tcv_lon) / 10.0
          else
            slonfg(i, 1) = real(storm(i)%tcv_lon) / 10.0
          endif
          if (storm(i)%tcv_latns == 'S') then
            slatfg(i, 1) = -1.0 * real(storm(i)%tcv_lat) / 10.0
          else
            slatfg(i, 1) = real(storm(i)%tcv_lat) / 10.0
          endif
          stcvtype(i) = 'TCV' ! storm listed on tcvitals
        enddo
      endif
      iret = 0
      return
    else
      ! For the  tracker cases, the max number of storms (maxstorm) allowed to be tracked throughout 
      ! a forecast is defined by the number of vitals read in above.
      maxstorm = numtcv

      if (maxstorm > 0) then
        continue
      else
        if (verb .ge. 1) then
          print *, ' '
          print *, '!!! ERROR in read_tcv_card, num storms to be '
          print *, '!!! processed is not greater than 0 for a tracker'
          print *, '!!! case.  Check to see that the TC Vitals file'
          print *, '!!! has been created and exists in the working'
          print *, '!!! directory.  That TC vitals file should be'
          print *, '!!! named tcvit_rsmc_storms.txt'
          print *, '!!! STOPPING...'
          print *, '!!! '
        endif
        iret = 99
        return
      endif

      allocate (stormswitch(maxstorm),     stat = isa)
      allocate (storm(maxstorm),           stat = issa)
      allocate (slonfg(maxstorm, maxtime), stat = ioa)
      allocate (slatfg(maxstorm, maxtime), stat = iaa)
      allocate (stcvtype(maxstorm),        stat = ita)

      if (isa /= 0 .or. ioa /= 0 .or. iaa /= 0 .or. issa /= 0 .or. ita /= 0) then
        if (verb .ge. 1) then
          print *, ' '
          print *, '!!! ERROR in read_tcv_card allocating stormswitch,'
          print *, '!!! slonfg, storm, slatfg or stcvtype arrays.  '
          print *, '!!! isa = ', isa,  ' ioa = ', ioa, ' iaa = ', iaa, ' issa = '
          print *, '!!! ',       issa, ' ita = ', ita
        endif
        iret = 97
        return
      endif

      if (verb .ge. 3) then
        print *, ' '
        print *, 'Following are the storms to be processed: '
        print *, ' '
      endif

      slonfg   = 0.0; slatfg = 0.0
      stcvtype = '   '  ! Not needed for regular tracker run
      ict      = 0

      do i = 1, maxstorm
        stormswitch(i) = 1
        storm(i)       = tmpstorm(i)
        ict = ict + 1

        if (verb .ge. 3) then
          write (*,31) storm(i)
        endif

        ! TC vitals contain positions in either a "W" or "E" framework.  Convert them here for 
        ! the slonfg array so that they are in a uniform, 0-360E framework for all vitals.
        if (storm(i)%tcv_lonew == 'W') then
          slonfg(i, 1) =  360.0 - real(storm(i)%tcv_lon) / 10.0
        else
          slonfg(i, 1) = real(storm(i)%tcv_lon) / 10.0
        endif
        if (storm(i)%tcv_latns == 'S') then
          slatfg(i, 1) = -1.0 * real(storm(i)%tcv_lat) / 10.0
        else
          slatfg(i, 1) = real(storm(i)%tcv_lat) / 10.0
        endif
      enddo

      if (ict .gt. 0) then
        iret = 0
        return
      else

        if (verb .ge. 1) then
          print *, ' '
          print *, '!!! ERROR in read_tcv_card, num storms to be '
          print *, '!!! processed is not greater than 0 for a tracker'
          print *, '!!! case.  Check to see that the TC Vitals file'
          print *, '!!! has been created and exists in the working'
          print *, '!!! directory.  That TC vitals file should be'
          print *, '!!! named tcvit_rsmc_storms.txt'
          print *, '!!! Stopping....'
          print *, ' '
        endif

        iret = 99
        return
      endif
    endif

31  format (a4, 1x, a3, 1x, a9, 1x, i8.8, 1x, i4.4, 1x, i3, a1, 1x, i4, a1, 1x, i3, 1x, i3, 3(1x, i4), 1x, i2, 1x, &
            i3, 1x, 4(i4, 1x), a1)

887 continue

    if (verb .ge. 1) then
      print *, '!!! ERROR in read_tcv_card opening rsmc TC vitals'
      print *, '!!! file named tcvit_rsmc_storms.txt.  A file with'
      print *, '!!! that name needs to be in your working directory.'
      print *, '!!! It should contain the input TC vitals for '
      print *, '!!! already-existing storms that have rsmc-issued'
      print *, '!!! storm IDs.'
    endif

    iret = 97
    return

891 continue

    if (verb .ge. 1) then
      print *, '!!! ERROR in read_tcv_card reading unit ', lucard
    endif

    iret = 98
    return

  end subroutine read_tcv_card

  !****************************************************************************
  !*
  !*  ABSTRACT: This subroutine reads in a modified TC Vitals file
  !*      for the current time and prints out those cards (storms) that
  !*      have been selected to be processed.  It also takes the initial
  !*      positions from the tcv card for each storm and puts them into
  !*      the slonfg & slatfg arrays.
  !*
  !*  The reason that these are referred to as modified tcvitals is
  !*      that the format is different from standard TC vitals format.
  !*      These vitals are created by a previous run of this tracker
  !*      executable, and the storm identifier is different than that
  !*      for a standard tcvitals.  The storm
  !*      identifier contains the date/time that the storm was first
  !*      identified, and the lat/lon position at which it was first
  !*      identified.
  !*
  !*  EXAMPLE:  The following is a standard TC Vitals record, split
  !*      up over 3 lines:
  !*
  !*      NHC  01L ALBERTO   20060614 1200 343N 0807W 035 093 1004 1012
  !*           0278 15 222 -999 -999 -999 -999 M -999 -999 -999 -999 72
  !*           520N  410W  -999 -999 -999 -999
  !*
  !*  EXAMPLE:  The following is the format for the "genesis" vitals,
  !*      split over 3 lines, for the same system:
  !*
  !*      2006061000_F000_210N_0853W_01L 20060614 1200 343N 0807W 035 093
  !*           1004 1012 0278 15 222 -999 -999 -999 -999 M -999 -999
  !*           -999 -999 72 520N  410W  -999 -999 -999 -999
  !*
  !*  EXAMPLE:  If the vitals record is for a non-officially numbered
  !*      system (i.e., any system that's not a TC being tracked
  !*      by NHC or JTWC), then the storm number is replaced
  !*      by the characters "FOF", for "Found On the Fly" by
  !*      the  tracker.
  !*
  !*      2006071500_F000_150N_0681W_FOF 20060718 1200 185N 0792W 035 093
  !*           1004 1012 0278 15 222 -999 -999 -999 -999 M -999 -999
  !*           -999 -999 72 520N  410W  -999 -999 -999 -999
  !*
  !*  NOTE: The "F000" in there at character positions 12-15 are to
  !*      indicate the forecast hour within that forecast cycle
  !*      that the storm was first detected.  For a vitals record,
  !*      this is always going to be 000 for fhr=0h, and really,
  !*      it's not even needed.  However, I'm keeping it in there
  !*      in order to keep the storm ID format exactly the same
  !*      as the  output_atcf_sink forecast track record, which
  !*      does have a use for that "FXXX" identifier in the output.
  !*
  !*  INPUT:
  !*      lgvcard  :: integer unit number for tcgen-tcvitals card
  !*
  !*  OUTPUT:
  !*      maxstorm    :: max # of storms to be handled for this case
  !*      iret        :: return code from this subroutine
  !*
  !*  INPUT/OUTPUT:
  !*      numtcv      :: As an input, this variable contains the number of
  !*                     *tropical* cyclone vitals (i.e., regular tcvitals) that
  !*                     were read off of the input tcvitals file in subroutine
  !*                     read_tcv_card.  This variable will be incremented for
  !*                     each "modified" vitals record that is read in this
  !*                     subroutine, and so as output, this variable will
  !*                     contain the combined total of tcvitals and modified
  !*                     vitals records.
  !*
  !*  OTHER:
  !*      stormswitch :: 1,2 or 3 (see more description under Main pgm section)
  !*      slonfg      :: first guess array for longitude
  !*      slatfg      :: first guess array for latitude
  !*      storm       :: contains the tcvitals info
  !*      
  !*      (storm, stormswitch, slonfg and slatfg are allocatable and are
  !*      defined in module def_vitals)
  !*
  !****************************************************************************
  subroutine read_gen_vitals (lgvcard, maxstorm, trkrinfo, numtcv, iret)

    use def_vitals; use set_max_parms; use trkrparms; use gen_vitals; use verbose_output

    implicit none

    type (gencard)    :: tmpstorm(maxstorm_mg)
    type (trackstuff) :: trkrinfo
    logical(1)        :: vit_file_exists
    integer           :: iret, maxstorm
    integer           :: i, ii, lgvcard, numtcv, num_mod_vit, vitix, iga


    ! check to see if the genesis TC Vitals file exists. If so, then open it using the unit specified in lgvcard.
    inquire (file = "tcvit_genesis_storms.txt", exist = vit_file_exists)

    if (vit_file_exists) then
      if (verb .ge. 3) then
        print *, ' '
        print *, '+++ TC Vitals file for genesis storms exists and will be opened with unit = lgvcard = ', lgvcard
      endif
      open (unit = lgvcard, file = "tcvit_genesis_storms.txt", status = 'old', err = 887)
      if (verb .ge. 3) then
        print *, ' '
        print *, '+++ TC vitals file tcvit_genesis_storms.txt has '
        print *, '    been opened with unit = lgvcard = ', lgvcard
      endif
    endif

    ! read in all of the "genesis vitals" into a temp array
    ii = numtcv + 1

    if (vit_file_exists) then
      do while (.true. .and. ii <= maxstorm_mg)
        read (lgvcard, 24, end = 801, err = 891) tmpstorm(ii)
        ii = ii + 1
      enddo
24    format (i10, 2x, i3, 1x, i3, a1, 1x, i4, a1, 1x, a3, 1x, i8, 1x, i4, 1x, i3, a1, 1x, i4, a1, 1x, &
              i3, 1x, i3, 3(1x, i4), 1x, i2, 1x, i3, 1x, 4(i4, 1x), a1)
801   continue
    endif

    num_mod_vit = ii - numtcv - 1
    allocate (gstorm(maxstorm_mg), stat = iga)

    if (iga /= 0) then
      if (verb .ge. 1) then
        print *, ' '
        print *, '!!! ERROR in read_gen_vitals allocating gstorm array'
        print *, '!!! iga = ', iga
      endif
      iret = 97
      return
    endif

    do i = 1, maxstorm_mg
      gstorm(i)%gv_gen_date = 99999
    enddo

    if (numtcv > 0) then
      do i = 1, numtcv
        gstorm(i)%gv_gen_date  = storm(i)%tcv_ymd * 100 + storm(i)%tcv_hhmm / 100
        gstorm(i)%gv_gen_fhr   = 0
        gstorm(i)%gv_gen_lat   = storm(i)%tcv_lat
        gstorm(i)%gv_gen_latns = storm(i)%tcv_latns
        gstorm(i)%gv_gen_lon   = storm(i)%tcv_lon
        gstorm(i)%gv_gen_lonew = storm(i)%tcv_lonew
        gstorm(i)%gv_gen_type  = storm(i)%tcv_storm_id
        gstorm(i)%gv_obs_ymd   = storm(i)%tcv_ymd
        gstorm(i)%gv_obs_hhmm  = storm(i)%tcv_hhmm
        gstorm(i)%gv_obs_lat   = storm(i)%tcv_lat
        gstorm(i)%gv_obs_latns = storm(i)%tcv_latns
        gstorm(i)%gv_obs_lon   = storm(i)%tcv_lon
        gstorm(i)%gv_obs_lonew = storm(i)%tcv_lonew
        if (verb .ge. 3) then
          write (*,34) gstorm(i)
        endif
      enddo
    endif

    if (num_mod_vit > 0) then
      if (verb .ge. 3) then
        print *, ' '
        print *, 'Following are the vitals for storms that were'
        print *, 'read in from the modified (genesis) tc vitals file: '
        print *, ' '
      endif

      do i = 1, num_mod_vit
        vitix = i + numtcv
        stormswitch(vitix) = 1
        ! fill the array gstorm
        gstorm(vitix) = tmpstorm(vitix)

        if (verb .ge. 3) then
          write (*,34) gstorm(vitix)
        endif

        write (storm(vitix)%tcv_storm_id,'(i4.4)') vitix
        write (storm(vitix)%tcv_storm_name,'(i4.4)') vitix

        storm(vitix)%tcv_ymd   = gstorm(vitix)%gv_obs_ymd
        storm(vitix)%tcv_hhmm  = gstorm(vitix)%gv_obs_hhmm
        storm(vitix)%tcv_lat   = gstorm(vitix)%gv_obs_lat
        storm(vitix)%tcv_latns = gstorm(vitix)%gv_obs_latns
        storm(vitix)%tcv_lon   = gstorm(vitix)%gv_obs_lon
        storm(vitix)%tcv_lonew = gstorm(vitix)%gv_obs_lonew
        storm(vitix)%tcv_stdir = gstorm(vitix)%gv_stdir
        storm(vitix)%tcv_stspd = gstorm(vitix)%gv_stspd

        if (trkrinfo%type == 'midlat') then
          storm(vitix)%tcv_center = 'MIDL'
        else if (trkrinfo%type == 'tcgen') then
          storm(vitix)%tcv_center = 'TCG '
        endif

        if (gstorm(vitix)%gv_obs_lonew == 'W') then
          slonfg(vitix, 1) =  360.0 - real(gstorm(vitix)%gv_obs_lon) / 10.0
        else
          slonfg(vitix, 1) = real(gstorm(vitix)%gv_obs_lon) / 10.0
        endif
        if (gstorm(vitix)%gv_obs_latns == 'S') then
          slatfg(vitix, 1) = -1.0 * real(gstorm(vitix)%gv_obs_lat) / 10.0
        else
          slatfg(vitix,1) = real(gstorm(vitix)%gv_obs_lat) / 10.0
        endif
        stcvtype(vitix) = 'FOF' ! Storm "Found On the Fly" by tracker
      enddo
    endif

34  format (i10, 1x, 'F', i3.3, 1x, i3.3, a1, 1x, i4.4, a1, 1x, a3, 1x, i8, 1x, i4.4, 1x, i3.3, a1, 1x, i4.4, &
            a1, 1x, i3, 1x, i3, 3(1x, i4), 1x, i2, 1x, i3, 1x, 4(i4, 1x), a1)

    ! update the total number of vitals that have been read in
    numtcv = numtcv + num_mod_vit

    goto 895
887 continue

    if (verb .ge. 1) then
      print *, '!!! ERROR in read_gen_vitals opening genesis vitals'
      print *, '!!! file named tcvit_genesis_storms.txt'
    endif

    iret = 97
    return
891 continue

    if (verb .ge. 1) then
      print *, '!!! ERROR in read_gen_vitals reading unit ', lgvcard
    endif

    iret = 98
895 continue
    return

  end subroutine read_gen_vitals

  !****************************************************************************
  !*
  !*  ABSTRACT: The purpose of this subroutine is just to get the max
  !*      values of i and j and the dx and dy grid spacing intervals for the
  !*      grid to be used in the rest of the program.  So just read the
  !*      grib file to get the lon and lat data.  Also, get the info for
  !*      the data grid's boundaries.  This boundary information will be
  !*      used later in the tracking algorithm, and is accessed via Module
  !*      grid_bounds.
  !*
  !****************************************************************************
  subroutine getgridinfo_grib (imax, jmax, ifh, dx, dy, lugb, lugi, trkrinfo, need_to_flip_lats, &
                              & need_to_flip_lons, inp, gm_wrap_flag, iggret)

    use grid_bounds;    use trkrparms; use tracked_parms; use inparms
    use verbose_output; use params;    use grib_mod

    implicit none

    type (trackstuff) :: trkrinfo
    type (datecard)   :: inp
    type(gribfield)   :: gfld

    logical(1)               :: need_to_flip_lats, need_to_flip_lons
    logical(1), allocatable  :: lb(:)
    logical                  :: unpack = .true.
    logical                  :: open_grb = .false.
    character(len=8)         :: pabbrev
    character(len=*)         :: gm_wrap_flag
    integer, dimension(200)  :: jids, jpdt, jgdt
    integer, parameter       :: jf = 40000000
    integer                  :: listsec1(13)
    integer                  :: pdt_4p0_vert_level, pdt_4p0_vtime
    real                     :: xhold, xlondiff, xlatdiff, temp, firstval, lastval
    real, allocatable        :: f(:)
    real, allocatable        :: tmplon(:), tmplat(:)
    real, intent(out)        :: dx, dy
    integer                  :: jpds(200), jgds(200), igetpds(200), igetgds(200)
    integer, intent(in)      :: ifh
    integer, intent(out)     :: imax, jmax
    integer                  :: iia, ija, ila, midi, midj, i, j, iix, jix, ifa, iret
    integer                  :: iscanflag, iggret, kf, k, lugb, lugi, jskp, jdisc
    integer                  :: jpdtn, jgdtn, npoints, icount, ipack, krec
    integer                  :: listsec0(2) = (/0,2/)
    integer                  :: igds(5) = (/0,0,0,0,0/), previgds(5)
    integer                  :: idrstmpl(200)
    integer                  :: currlen = 1000000

    iggret       = 0

    gm_wrap_flag = 'none'

    allocate (lb(jf), stat = ila); allocate (f(jf), stat = ifa)
    if (ila /= 0 .or. ifa /= 0) then
      if (verb .ge. 1) then
        print *, ' '
        print *, '!!! ERROR in getgridinfo allocating either lb or f'
        print *, '!!! ila = ', ila, ' ifa = ', ifa
      endif
      iggret = 97
      return
    endif

    if (trkrinfo%gribver == 2) then

      ! search for a record from a GRIB2 file; initialize Variables
      gfld%idsect     => NULL()
      gfld%local      => NULL()
      gfld%list_opt   => NULL()
      gfld%igdtmpl    => NULL()
      gfld%ipdtmpl    => NULL()
      gfld%coord_list => NULL()
      gfld%idrtmpl    => NULL()
      gfld%bmap       => NULL()
      gfld%fld        => NULL()

      jdisc = 0                 ! meteorological products
      jids  = -9999
      jpdtn = trkrinfo%g2_jpdtn ! 0 = analysis or forecast; 1 = ens fcst
      jgdtn = 0                 ! lat/lon grid
      jgdt  = -9999
      jpdt  = -9999

      npoints = 0
      icount  = 0
      jskp    = 0

      ! search for Temperature or GP Height by production template
      jpdt(1:15) = (/-9999, -9999, -9999, -9999, -9999, -9999, -9999, -9999,  &
                     -9999, -9999, -9999, -9999, -9999, -9999, -9999/)

      ! request a record on a lat/lon grid.
      jgdtn = 0

      ! request a record at the current forecast lead time
      if (inp%lt_units == 'minutes') then
        jpdt(8) = 0
        jpdt(9) = iftotalmins(ifh)
      else
        jpdt(8) = 1
        jpdt(9) = ifhours(ifh)
      endif

      if (verb >= 3) then
        print *, 'before getgb2 call, lugb = ', lugb, ' lugi = ', lugi
      endif

      call getgb2 (lugb, lugi, jskp, jdisc, jids, jpdtn, jpdt, jgdtn, jgdt, unpack, krec, gfld, iret)

      if (iret .ne. 0) then
        print *, ' '
        print *, ' ERROR: getgb2 error in getgridinfo = ', iret
        print *, ' FATAL ERROR: cannot proceed without info '
        print *, ' from getgridinfo.  STOPPING....'
        stop 95
      endif

      ! determine packing information from GRIB2 file; The default packing is 40  JPEG 2000
      ipack = 40
      if (verb_g2 .ge. 1) then
        print *, ' '
        print *, ' -- BEGIN getgridinfo diagnostics for GRIB2 file ---'
        print *, ' --       at ifh = ', ifh
        print *, ' '
        print *, ' gfld%idrtnum = ', gfld%idrtnum
      endif

      ! set DRT info ( packing info )
      if (gfld%idrtnum .eq. 0) then      ! simple packing
        ipack = 0
      elseif (gfld%idrtnum .eq. 2) then  ! complex packing
        ipack = 2
      elseif (gfld%idrtnum .eq. 3) then  ! complex & spatial packing
        ipack = 31
      elseif (gfld%idrtnum .eq. 40 .or. gfld%idrtnum .eq. 15) then
        ! JPEG 2000 packing
        ipack = 40
      elseif (gfld%idrtnum .eq. 41) then  ! PNG packing
        ipack = 41
      endif

      if (verb_g2 .ge. 1) then
        print *, 'After check of idrtnum,     ipack = ', ipack
        print *, 'Number of gridpts  = gfld%ngrdpts = ', gfld%ngrdpts
        print *, 'Number of elements = gfld%igdtlen = ', gfld%igdtlen
        print *, 'PDT num            = gfld%ipdtnum = ', gfld%ipdtnum
        print *, 'GDT num            = gfld%igdtnum = ', gfld%igdtnum
      endif

      imax = gfld%igdtmpl(8)
      jmax = gfld%igdtmpl(9)
      dx   = real(gfld%igdtmpl(17)) / 1.0E6
      dy   = real(gfld%igdtmpl(17)) / 1.0E6
      kf   = gfld%ngrdpts

      if (verb_g2 .ge. 1) then
        print *, ' '
        print *, ' SECTION 0: discipl = ', gfld%discipline, ' gribver = ', gfld%version
        print *, ' '
        print *, ' SECTION 1: '

        do j = 1, gfld%idsectlen
          print *, 'sect1, j = ', j, ' gfld%idsect(j) = ', gfld%idsect(j)
        enddo

        if (associated(gfld%local) .and. gfld%locallen .gt. 0) then
          print *, ' '
          print *, ' SECTION 2: ', gfld%locallen, ' bytes'
        else
          print *, ' '
          print *, ' SECTION 2 DOES NOT EXIST IN THIS RECORD'
        endif

        print *, ' '
        print *, ' SECTION 3: griddef    = ', gfld%griddef
        print *, '            ngrdpts    = ', gfld%ngrdpts
        print *, '            numoct_opt = ', gfld%numoct_opt
        print *, '            interp_opt = ', gfld%interp_opt
        print *, '            igdtnum    = ', gfld%igdtnum
        print *, '            igdtlen    = ', gfld%igdtlen
        print *, ' '
        print '(a17,i3,a2)', ' GRID TEMPLATE 3.', gfld%igdtnum, ': '

        do j = 1, gfld%igdtlen
          print *, '    j = ', j, ' gfld%igdtmpl(j) = ', gfld%igdtmpl(j)
        enddo

        ! get parameter abbrev for record that was retrieved
        print *, ' '
        print *, '     PDT num (gfld%ipdtnum) = ',  gfld%ipdtnum
        print *, ' '
        print '(a20,i3,a2)',' PRODUCT TEMPLATE 4.', gfld%ipdtnum, ': '
        do j = 1, gfld%ipdtlen
          print *, '   sect 4  j = ', j, ' gfld%ipdtmpl(j) = ', gfld%ipdtmpl(j)
        enddo
      endif

      pdt_4p0_vtime      = gfld%ipdtmpl(9)
      pdt_4p0_vert_level = gfld%ipdtmpl(12)
      pabbrev  = param_get_abbrev(gfld%discipline, gfld%ipdtmpl(1), gfld%ipdtmpl(2))
      firstval = gfld%fld(1)
      lastval  = gfld%fld(kf)

      if (verb .ge. 3) then
        print *, ' '
        write (6,131)
 131    format (' rec#   param     level  byy  bmm  bdd  bhh  fhr      npts  firstval    lastval')
        print '(i5,3x,a8,2x,6i5,2x,i8,4g12.4)', krec, pabbrev, pdt_4p0_vert_level/100, gfld%idsect(6)
        print '(i5,3x,a8,2x,6i5,2x,i8,4g12.4)', gfld%idsect(7), gfld%idsect(8), gfld%idsect(9)
        print '(i5,3x,a8,2x,6i5,2x,i8,4g12.4)', pdt_4p0_vtime, gfld%ngrdpts, firstval, lastval
      endif

      if (verb_g2 .ge. 1) then
        print *, ' '
        print *, ' -- END getgridinfo diagnostics for GRIB2 file ---'
        print *, ' --     at ifh = ', ifh
        print *, ' '
        print *, ' '
        print *, ' '
      endif

      need_to_flip_lons = .false.
      iscanflag = gfld%igdtmpl(19)

      if (mod(iscanflag, 128) >= 64) then
        ! input data is south to north
        glatmin = real(gfld%igdtmpl(12)) / 1.0E6
        glatmax = real(gfld%igdtmpl(15)) / 1.0E6
        need_to_flip_lats = .true.
      else
        ! input data is north to south
        glatmin = real(gfld%igdtmpl(15)) / 1.0E6
        glatmax = real(gfld%igdtmpl(12)) / 1.0E6
        need_to_flip_lats = .false.
      endif

      glonmin = real(gfld%igdtmpl(13)) / 1.0E6
      glonmax = real(gfld%igdtmpl(16)) / 1.0E6

      if (verb .ge. 3) then
        print *, 'In getgridinfo: glatmin = ', glatmin
        print *, '                glatmax = ', glatmax
        print *, '                glonmin = ', glonmin
        print *, '                glonmax = ', glonmax
      endif

      call gf_free (gfld)

    else
      ! search for a record from a GRIB1 file
      jpds    = -1
      jgds    = -1
      jgds(1) = 0   ! request a record that's on a lat/lon grid

      if (verb .ge. 3) then
        print *, 'before getgb in getgridinfo, ifh = ', ifh
        write (6,402) ifhours(ifh), ifclockmins(ifh)
 402    format (1x, '*       Forecast hour:  ', i4, ':', i2.2)
        print *,'            ifhours(ifh) = ', ifhours(ifh)
        print *,'        iftotalmins(ifh) = ', iftotalmins(ifh)
      endif

      ! request a record at the current forecast lead time
      if (inp%lt_units == 'minutes') then
        jpds(14) = iftotalmins(ifh)
      else
        jpds(14) = ifhours(ifh)
      endif

      j = 0

      write(*,980) jpds(1),  jpds(2)
      write(*,981) jpds(3),  jpds(4)
      write(*,982) jpds(5),  jpds(6)
      write(*,983) jpds(7),  jpds(8)
      write(*,984) jpds(9),  jpds(10)
      write(*,985) jpds(11), jpds(12)
      write(*,986) jpds(13), jpds(14)
      write(*,987) jpds(15), jpds(16)
      write(*,988) jpds(17), jpds(18)
      write(*,989) jpds(19), jpds(20)
      write(*,990) jpds(21), jpds(22)
      write(*,991) jpds(23), jpds(24)
      write(*,992) jpds(25)
      write(*,880) jgds(1),  jgds(2)
      write(*,881) jgds(3),  jgds(4)
      write(*,882) jgds(5),  jgds(6)
      write(*,883) jgds(7),  jgds(8)
      write(*,884) jgds(9),  jgds(10)
      write(*,885) jgds(11), jgds(12)
      write(*,886) jgds(13), jgds(14)
      write(*,887) jgds(15), jgds(16)
      write(*,888) jgds(17), jgds(18)
      write(*,889) jgds(19), jgds(20)
      write(*,890) jgds(21), jgds(22)

980   format('    jpds(1)  = ', i7,'  jpds(2)  = ', i7)
981   format('    jpds(3)  = ', i7,'  jpds(4)  = ', i7)
982   format('    jpds(5)  = ', i7,'  jpds(6)  = ', i7)
983   format('    jpds(7)  = ', i7,'  jpds(8)  = ', i7)
984   format('    jpds(9)  = ', i7,'  jpds(10) = ', i7)
985   format('    jpds(11) = ', i7,'  jpds(12) = ', i7)
986   format('    jpds(13) = ', i7,'  jpds(14) = ', i7)
987   format('    jpds(15) = ', i7,'  jpds(16) = ', i7)
988   format('    jpds(17) = ', i7,'  jpds(18) = ', i7)
989   format('    jpds(19) = ', i7,'  jpds(20) = ', i7)
990   format('    jpds(21) = ', i7,'  jpds(22) = ', i7)
991   format('    jpds(23) = ', i7,'  jpds(24) = ', i7)
992   format('    jpds(25) = ', i7)
880   format('    jgds(1)  = ', i7,'  jgds(2)  = ', i7)
881   format('    jgds(3)  = ', i7,'  jgds(4)  = ', i7)
882   format('    jgds(5)  = ', i7,'  jgds(6)  = ', i7)
883   format('    jgds(7)  = ', i7,'  jgds(8)  = ', i7)
884   format('    jgds(9)  = ', i7,'  jgds(10) = ', i7)
885   format('    jgds(11) = ', i7,'  jgds(12) = ', i7)
886   format('    jgds(13) = ', i7,'  jgds(14) = ', i7)
887   format('    jgds(15) = ', i7,'  jgds(16) = ', i7)
888   format('    jgds(17) = ', i7,'  jgds(18) = ', i7)
889   format('    jgds(19) = ', i7,'  jgds(20) = ', i7)
890   format('    jgds(20) = ', i7,'  jgds(22) = ', i7)

      print *, 'lugb = ', lugb,    ' lugi = ', lugi
      print *, 'before ggi getgb jpds(14) = ', jpds(14)
      print *, 'before ggi getgb jgds(1)  = ', jgds(1)

      call getgb (lugb, lugi, jf, j, jpds, jgds, kf, k, igetpds, igetgds, lb, f, iret)

      if (iret .ne. 0) then
        if (verb .ge. 1) then
          print *, ' '
          print *, '!!! ERROR in getgridinfo calling getgb'
          print *, '!!! Return code from getgb = iret = ', iret
        endif
        iggret = iret
      else
        iggret = 0
        imax   = igetgds(2)
        jmax   = igetgds(3)
        dx     = real(igetgds(9)) / 1000.0
        dy     = real(igetgds(10)) / 1000.0
      endif

      if (verb .ge. 3) then
        print *, ' '
        print *, 'In getgridinfo, grid dimensions follow:'
        print *, 'imax = ', imax, ' jmax = ', jmax
        print *, '  dx = ', dx,   '  dy  = ', dy
      endif

      need_to_flip_lons = .false.
      iscanflag = igetgds(11)

      if (mod(iscanflag, 128) >= 64) then
        ! input data is south to north
        glatmin = real(igetgds(4)) / 1000.0
        glatmax = real(igetgds(7)) / 1000.0
        need_to_flip_lats = .true.
      else
        ! input data is north to south
        glatmin = real(igetgds(7)) / 1000.0
        glatmax = real(igetgds(4)) / 1000.0
        need_to_flip_lats = .false.
      endif

      glonmin = real(igetgds(5)) / 1000.0
      glonmax = real(igetgds(8)) / 1000.0
    endif

    if (glonmin >= 0.0 .and. glonmax >= 0.0) then
      if (glonmin > glonmax) then
        if (verb .ge. 3) then
          print *, ' '
          print *, 'NOTE:  For this file, the GRIB PDS indicates that'
          print *, '       the min longitude (glonmin) is greater'
          print *, '       than the max longitude (glonmax) where both'
          print *, '       longitudes are greater than 0.'
          print *, '       This means that the grid is spanning '
          print *, '       across the GM.'
          print *, '       We will adjust glonmax by adding 360 to it'
          print *, '       so that, in the end, glonmax > glonmin.'
          print *, '       '
          print *, '       GRID MIN & MAX LON (ORIGINAL):'
          print *, '         original glonmin = ', glonmin
          print *, '         original glonmax = ', glonmax
          print *, '       '
          print *, '       '
          print *, '       GRID MIN & MAX LON '
          print *, '         (MODIFIED FOR GM WRAPPING):'
          print *, '         glonmin (same as original) = ', glonmin
          print *, '         glonmax (modified) =         ', glonmax
          print *, '       '
        endif
        glonmax      = glonmax + 360.0
        gm_wrap_flag = 'maxplus360'
      endif

    elseif (glonmin < 0.0 .and. glonmax >= 0.0) then
      if (verb .ge. 3) then
        print *, ' '
        print *, 'NOTE: glonmin is < 0, glonmax > 0, so glonmin'
        print *, '      will be converted to be > 0 and 360 will'
        print *, '      be added to glonmax.'
        print *, '      BEFORE CONVERSION: '
        print *, '         glonmin = ', glonmin
        print *, '         glonmax = ', glonmax
      endif

      glonmin = 360.0 - abs(glonmin)
      glonmax = 360.0 + abs(glonmax)
      gm_wrap_flag = 'minminus360maxplus360'
      if (verb .ge. 3) then
        print *, '      AFTER CONVERSION: '
        print *, '              glonmin = ', glonmin
        print *, '              glonmax = ', glonmax
      endif

    elseif (glonmin < 0.0 .and. glonmax < 0.0) then
      ! examples of this are GFDL and HWRF; In this case, make both glonmin and glonmax positive.
      if (verb .ge. 3) then
        print *, ' '
        print *, 'NOTE: glonmin is < 0 and glonmax < 0, so both'
        print *, '      will be converted to be > 0.'
        print *, '      BEFORE CONVERSION: '
        print *, '               glonmin = ', glonmin
        print *, '               glonmax = ', glonmax
      endif

      glonmin = 360.0 - abs(glonmin)
      glonmax = 360.0 - abs(glonmax)
      gm_wrap_flag = 'minmaxboth360minus'
      if (verb .ge. 3) then
        print *, '      AFTER CONVERSION: '
        print *, '              glonmin = ', glonmin
        print *, '              glonmax = ', glonmax
      endif

    elseif (glonmin >= 0.0 .and. glonmax < 0.0) then
      if (verb .ge. 3) then
        print *, ' '
        print *, 'NOTE: glonmin is >= 0 and glonmax < 0, so'
        print *, '      glonmax will be converted to be > 0.'
        print *, '      BEFORE CONVERSION: '
        print *, '               glonmin = ', glonmin
        print *, '               glonmax = ', glonmax
      endif

      glonmax      = 360.0 - abs(glonmax)
      gm_wrap_flag = 'max360minus'
      if (verb .ge. 3) then
        print *, '      AFTER CONVERSION: '
        print *, '              glonmin = ', glonmin
        print *, '              glonmax = ', glonmax
      endif
    endif

    if (glatmax < glatmin) then
      temp    = glatmax
      glatmax = glatmin
      glatmin = temp
    endif

    if (glonmin > 200.0 .and. glonmin <= 360.0) then
      if (glonmax < 50.0) then
        ! likely GM-wrapping in current record
        glonmax = glonmax + 360.0
      endif
    endif

    if (verb .ge. 3) then
      print *, ' '
      print *, 'Data Grid Lat/Lon boundaries follow:'
      write (6,81) glatmin, glonmin
 81   format (' Min Lat: ', f8.3, '  Min Lon: ', f8.3)
      write (6,83) glatmax, glonmax
 83   format (' Max Lat: ', f8.3, '  Max Lon: ', f8.3)
      print *, ' '
      print *, 'NOTE: For regional grids, valid data points might'
      print *, 'NOT extend all the way to the gds-defined grid '
      print *, 'boundary, due to the fact that data have been '
      print *, 'interpolated from a NPS or Lamb-Conf grid onto a '
      print *, 'lat/lon grid.  This program checks the logical '
      print *, 'bitmap for valid data points, but just keep this in'
      print *, 'mind if trying to debug errors that occur near the'
      print *, 'grid boundaries for regional models.'
    endif

    if (allocated(glat)) deallocate(glat)
    if (allocated(glon)) deallocate(glon)

    allocate (glat(jmax), stat = ija)
    allocate (glon(imax), stat = iia)

    if (ija /= 0 .or. iia /= 0) then

      if (verb .ge. 1) then
        print *, ' '
        print *, '!!! ERROR in getgridinfo allocating glon or glat'
        print *, '!!! ija = ', ija, ' iia = ', iia
      endif

      if (allocated(lb)) deallocate (lb, stat = ila)
      if (allocated(f))  deallocate (f,  stat = ifa)

      if (ila /= 0 .or. ifa /= 0) then
        print *, ' '
        print *, '!!! ERROR in getgridinfo deallocating arrays.'
        print *, '!!! ila = ', ila, ' ifa = ', ifa
        print *, '!!! EXITING....'
        stop 98
      endif
      iggret = 96
      return
    endif

    do j = 1, jmax
      glat(j) = glatmax - (j-1) * dy
    enddo
    do i = 1, imax
      glon(i) = glonmin + (i-1) * dx
    enddo

    if (allocated(lb)) deallocate (lb, stat=ila)
    if (allocated(f))  deallocate (f, stat=ifa)

    if (ila /= 0 .or. ifa /= 0) then
      print *, ' '
      print *, '!!! ERROR in getgridinfo deallocating arrays.'
      print *, '!!! ila = ', ila, ' ifa = ', ifa
      print *, '!!! EXITING....'
      stop 98
    endif

    if (trkrinfo%gridtype == 'regional' .and. trkrinfo%type /= 'tracker') then

      if (trkrinfo%eastbd > glonmax) then
        xhold = trkrinfo%eastbd
        trkrinfo%eastbd = glonmax - 5.0
        if (verb .ge. 3) then
          !CAITLYN - can we remove all these 'writes' and the ones below?
          write (6,97) 'EASTERN LONGITUDE'
          write (6,98) xhold
          write (6,99) trkrinfo%eastbd
          write (6,91)
        endif
      endif

      if (trkrinfo%westbd < glonmin) then
        xhold = trkrinfo%westbd
        trkrinfo%westbd = glonmin + 5.0
        if (verb .ge. 3) then
          write (6,97) 'WESTERN LONGITUDE'
          write (6,98) xhold
          write (6,99) trkrinfo%westbd
          write (6,91)
        endif
      endif

      if (trkrinfo%northbd > glatmax) then
        xhold = trkrinfo%northbd
        trkrinfo%northbd = glatmax - 5.0
        if (verb .ge. 3) then
          write (6,97) 'NORTHERN LATITUDE'
          write (6,98) xhold
          write (6,99) trkrinfo%northbd
          write (6,91)
        endif
      endif

      if (trkrinfo%southbd < glatmin) then
        xhold = trkrinfo%southbd
        trkrinfo%southbd = glatmin + 5.0
        if (verb .ge. 3) then
          write (6,97) 'SOUTHERN LATITUDE'
          write (6,98) xhold
          write (6,99) trkrinfo%southbd
          write (6,91)
        endif
      endif
    endif

90  format (//)
91  format (' *********************************************')
92  format (' WARNING: A USER-REQUESTED BOUNDARY IS BEYOND')
93  format (' THE BOUNDARY OF THE DATA, AS DEFINED IN THE ')
94  format (' GRIB FILE.  THE USER BOUNDARY WILL BE MODIFIED')
95  format (' TO MATCH THE BOUNDARY OF THE DATA FILE.')
96  format (' ')
97  format (' USER-INPUT BOUNDARY AT FAULT: ', A20)
98  format (' USER-INPUT BOUNDARY VALUE: ', f8.2)
99  format (' NEW BOUNDARY VALUE: ', f8.2)

    return

  end subroutine getgridinfo_grib

  !****************************************************************************
  !*
  !*  ABSTRACT: The purpose of this subroutine is just to get the max
  !*      values of i and j and the dx and dy grid spacing intervals for the
  !*      grid to be used in the rest of the program.  So just query the
  !*      netcdf file to get the lon and lat data.  Also, get the info for
  !*      the data grid's boundaries.  This boundary information will be
  !*      used later in the tracking algorithm, and is accessed via Module
  !*      grid_bounds.
  !*
  !****************************************************************************
  subroutine getgridinfo_netcdf (ncfile_id, imax, jmax, dx, dy, trkrinfo, need_to_flip_lats, &
                                & need_to_flip_lons, inp, netcdfinfo, iggret)

    use grid_bounds; use trkrparms; use inparms; use verbose_output; use netcdf_parms

    implicit none

    type (trackstuff)  :: trkrinfo
    type (netcdfstuff) :: netcdfinfo
    type (datecard)    :: inp

    logical(1)                :: need_to_flip_lats, need_to_flip_lons
    real                      :: xhold, xlondiff, xlatdiff
    real, allocatable         :: tmplon(:), tmplat(:)
    real(kind=4), allocatable :: temp_tmplon4(:), temp_tmplat4(:)
    real(kind=8), allocatable :: temp_tmplon8(:), temp_tmplat8(:)
    real, intent(out)         :: dx, dy
    integer                   :: iscanflag, iggret
    integer, intent(in)       :: ncfile_id
    integer, intent(out)      :: imax, jmax
    integer                   :: iia, ija, midi, midj, i, j, iix, jix, xtype, ignrret
    integer                   :: ii4a, ii8a, ij4a, ij8a

    iggret = 0

    call get_ncdim1 (ncfile_id, netcdfinfo%lon_name, imax)
    call get_ncdim1 (ncfile_id, netcdfinfo%lat_name, jmax)

    if (allocated(tmplon)) deallocate (tmplon)
    if (allocated(tmplat)) deallocate (tmplat)
    allocate (tmplon(imax), stat = iia)
    allocate (tmplat(jmax), stat = ija)

    if (iia /= 0 .or. ija /= 0) then
      print *, ' '
      print *, '!!! ERROR in sub getgridinfo_netcdf allocating arrays.'
      print *, '!!! iia = ', iia, ' ija = ', ija
      iggret = 94
      return
    endif

    if (allocated(temp_tmplon4)) deallocate (temp_tmplon4)
    if (allocated(temp_tmplon8)) deallocate (temp_tmplon8)
    if (allocated(temp_tmplat4)) deallocate (temp_tmplat4)
    if (allocated(temp_tmplat8)) deallocate (temp_tmplat8)
    allocate (temp_tmplon4(imax), stat = ii4a)
    allocate (temp_tmplon8(imax), stat = ii8a)
    allocate (temp_tmplat4(jmax), stat = ij4a)
    allocate (temp_tmplat8(jmax), stat = ij8a)

    if (ii4a /= 0 .or. ii8a /= 0 .or. ij4a /= 0 .or. ij8a /= 0) then
      print *, ' '
      print *, '!!! ERROR in sub getgridinfo_netcdf allocating'
      print *, '!!! temp_tmplon or temp_tmplat arrays.'
      print *, '!!! ii4a = ', ii4a, ' ii8a = ', ii8a
      print *, '!!! ij4a = ', ij4a, ' ij8a = ', ij8a
      iggret = 94
      return
    endif

    if (verb .ge. 1) then
      print *, 'in getgridinfo_netcdf, ncfile_id = ', ncfile_id
    endif

    ! get type (32/64-bit) of longitude, then read longitude into correctly sized array
    call get_netcdf_real_type (ncfile_id, netcdfinfo%lon_name, xtype, ignrret)

    if (xtype == 5) then
      call get_var1_one_dim4 (ncfile_id, netcdfinfo%lon_name, imax, temp_tmplon4)
      tmplon = temp_tmplon4
    else
      call get_var1_one_dim8 (ncfile_id, netcdfinfo%lon_name, imax, temp_tmplon8)
      tmplon = temp_tmplon8
    endif

    if (allocated(temp_tmplon4)) deallocate (temp_tmplon4)
    if (allocated(temp_tmplon8)) deallocate (temp_tmplon8)

    ! get type (32/64-bit) of latitude, then read latitude into correctly sized array
    call get_netcdf_real_type (ncfile_id, netcdfinfo%lat_name, xtype, ignrret)

    if (xtype == 5) then
      call get_var1_one_dim4 (ncfile_id, netcdfinfo%lat_name, jmax, temp_tmplat4)
      tmplat = temp_tmplat4
    else
      call get_var1_one_dim8 (ncfile_id, netcdfinfo%lat_name, jmax, temp_tmplat8)
      tmplat = temp_tmplat8
    endif

    if (allocated(temp_tmplat4)) deallocate (temp_tmplat4)
    if (allocated(temp_tmplat8)) deallocate (temp_tmplat8)


    ! compute the dx and dy by picking values out of the middle of the lat and lon arrays
    midi = imax / 2
    midj = jmax / 2

    dx = abs(tmplon(midi) - tmplon(midi-1))
    dy = abs(tmplat(midj) - tmplat(midj-1))

    if (verb .ge. 1) then
      print *, ' '
      print *, 'In getgridinfo, grid dimensions follow:'
      print *, 'imax = ', imax, ' jmax = ', jmax
      print *, 'dx   = ', dx,   ' dy   = ',   dy
      print *, ' '
      write (6,112) midi, dx
      write (6,113) midj, dy
112   format(1x, ' DX:  midi = ', i4, ' dx = ', f8.4)
113   format(1x, ' DY:  midj = ', i4, ' dy = ', f8.4)
    endif

    if (tmplon(imax) > tmplon(1)) then
      glonmin = tmplon(1)
      glonmax = tmplon(imax)
    else
      glonmin = tmplon(imax)
      glonmax = tmplon(1)
    endif

    if (tmplat(1) > tmplon(jmax)) then
      glatmax = tmplat(1)
      glatmin = tmplat(jmax)
    else
      glatmax = tmplat(jmax)
      glatmin = tmplat(1)
    endif

    print *, ' '
    print *, 'Data Grid Lat/Lon boundaries follow:'
    write (6,81) glatmin, glonmin
81  format (' Min Lat: ', f8.3, '  Min Lon: ', f8.3)
    write (6,83) glatmax,glonmax
83  format (' Max Lat: ', f8.3, '  Max Lon: ', f8.3)

    if (allocated(glon)) deallocate (glon)
    if (allocated(glat)) deallocate (glat)
    allocate (glat(jmax), stat = ija)
    allocate (glon(imax), stat = iia)

    if (ija /= 0 .or. iia /= 0) then
      print *, ' '
      print *, '!!! ERROR in getgridinfo allocating glon or glat'
      print *, '!!! ija = ', ija, ' iia = ', iia
      iggret = 96
      return
    endif

    need_to_flip_lats = .false.
    need_to_flip_lons = .false.

    if (tmplat(1) > tmplon(jmax)) then
      do j = 1, jmax
        glat(j) = tmplat(j)
      enddo
    else
      do j = 1, jmax
        jix = jmax - j + 1
        glat(jix) = tmplat(j)
      enddo
      need_to_flip_lats = .true.
    endif

    if (tmplon(imax) > tmplon(1)) then
      do i = 1, imax
        glon(i) = tmplon(i)
      enddo
    else
      do i = 1, imax
        iix = imax - i + 1
        glon(iix) = tmplon(i)
      enddo
      need_to_flip_lons = .true.
    endif

    if (trkrinfo%gridtype == 'regional' .and. trkrinfo%type /= 'tracker') then
      if (trkrinfo%eastbd > glonmax) then
        xhold = trkrinfo%eastbd
        trkrinfo%eastbd = glonmax - 5.0
        write (6,97) 'EASTERN LONGITUDE'
        write (6,98) xhold
        write (6,99) trkrinfo%eastbd
        write (6,91)
      endif

      if (trkrinfo%westbd < glonmin) then
        xhold = trkrinfo%westbd
        trkrinfo%westbd = glonmin + 5.0
        write (6,97) 'WESTERN LONGITUDE'
        write (6,98) xhold
        write (6,99) trkrinfo%westbd
        write (6,91)
      endif

      if (trkrinfo%northbd > glatmax) then
        xhold = trkrinfo%northbd
        trkrinfo%northbd = glatmax - 5.0
        write (6,97) 'NORTHERN LATITUDE'
        write (6,98) xhold
        write (6,99) trkrinfo%northbd
        write (6,91)
      endif

      if (trkrinfo%southbd < glatmin) then
        xhold = trkrinfo%southbd
        trkrinfo%southbd = glatmin + 5.0
        write (6,97) 'SOUTHERN LATITUDE'
        write (6,98) xhold
        write (6,99) trkrinfo%southbd
        write (6,91)
      endif

    endif

90  format (//)
91  format (' *********************************************')
92  format (' WARNING: A USER-REQUESTED BOUNDARY IS BEYOND')
93  format (' THE BOUNDARY OF THE DATA, AS DEFINED IN THE ')
94  format (' GRIB FILE.  THE USER BOUNDARY WILL BE MODIFIED')
95  format (' TO MATCH THE BOUNDARY OF THE DATA FILE.')
96  format (' ')
97  format (' USER-INPUT BOUNDARY AT FAULT: ', A20)
98  format (' USER-INPUT BOUNDARY VALUE: ', f8.2)
99  format (' NEW BOUNDARY VALUE: ', f8.2)

    return

  end subroutine getgridinfo_netcdf

  !****************************************************************************
  !*
  !*  ABSTRACT: The purpose of this subroutine is to read the "time"
  !*      dimension and "time data" from the NetCDF file so that we know
  !*      how many time levels there are and what those time levels are.
  !*      One reason for doing this is that some models, like the GFDL
  !*      FV3, do not output hour 0 data, so we need to check this first
  !*      before running through the tracking processing for the various
  !*      hours.  We will take the list of hours read in here directly from
  !*      the NetCDF file and compare that against the *requested* list of
  !*      forecast hours that the user has entered.  The user might not be
  !*      aware that there is no hour 0 data for a given model.  We compare
  !*      these two lists of forecast hours and then write a message if
  !*      there is a lead time that is not in the NetCDF file.
  !*
  !*  INPUT:
  !*      ncfile           :: character name of NetCDF file
  !*      ncfile_id        :: integer id associated with NetCDF file after open
  !*      ifhmax           :: integer max number of lead times that the user has
  !*                          requested on the input lead times data file.  This
  !*                          value was set in subroutine read_fhours.
  !*      netcdfinfo       :: variable of user-defined type netcdfstuff (from
  !*                          module netcdf_parms).
  !*
  !*  OUTPUT:
  !*      ncfile_tmax      :: integer max number of lead times that are in the
  !*                          NetCDF file, as read in from this subroutine
  !*      ncfile_has_hour0 :: character flag (y|n) that tells whether or not
  !*                          the input NetCDF data file actually has an hour0
  !*                          record in it or not.
  !*
  !****************************************************************************
  subroutine read_netcdf_hours (ncfile, ncfile_id, ncfile_tmax, ifhmax, &
                               & ncfile_has_hour0, netcdfinfo, irnhret)

    use netcdf_parms; use tracked_parms; use verbose_output

    implicit none

    type (netcdfstuff) :: netcdfinfo

    character(len=180)        :: ncfile
    character(len=1)          :: ncfile_has_hour0, match_check
    real(kind=4), allocatable :: temp_nc_time_vals_r4(:)
    real(kind=8), allocatable :: temp_nc_time_vals_r8(:)
    integer, intent(in)       :: ncfile_id
    integer, intent(out)      :: ncfile_tmax
    integer                   :: infta, k, m, n, ifhmax, irnhret, usertime, xtype, ignrret


    irnhret = 0
    ncfile_has_hour0 = 'n'

    ! first read the NetCDF file to get the number of time levels, which will be returned in "ncfile_tmax"
    print *, ' '
    print *, 'in read_netcdf_hours...'
    print *, 'ncfile_id            = ',            ncfile_id
    print *, 'netcdfinfo%time_name = ', netcdfinfo%time_name
    print *, 'ncfile_tmax          = ',          ncfile_tmax

    call get_ncdim1 (ncfile_id, netcdfinfo%time_name, ncfile_tmax)

    if (verb .ge. 1) then
      print *, 'in getgridinfo_netcdf, ncfile_id    = ',   ncfile_id
      print *, 'Num netcdf time levs =  ncfile_tmax = ', ncfile_tmax
    endif

    if (allocated(netcdf_file_time_values)) then
      deallocate (netcdf_file_time_values)
    endif

    if (allocated(temp_nc_time_vals_r4)) then
      deallocate (temp_nc_time_vals_r4)
    endif

    if (allocated(temp_nc_time_vals_r8)) then
      deallocate (temp_nc_time_vals_r8)
    endif

    allocate (netcdf_file_time_values(ncfile_tmax), stat = infta)
    if (infta /= 0) then
      print *, ' '
      print *, '!!! ERROR in sub read_netcdf_hours allocating'
      print *, '!!! netcdf_file_time_values array.  infta = ', infta
      irnhret = 94
      return
    endif

    allocate (temp_nc_time_vals_r4(ncfile_tmax), stat = infta)
    if (infta /= 0) then
      print *, ' '
      print *, '!!! ERROR in sub read_netcdf_hours allocating'
      print *, '!!! temp_nc_time_vals_r4 array.  infta = ', infta
      irnhret = 94
      return
    endif

    allocate (temp_nc_time_vals_r8(ncfile_tmax), stat = infta)
    if (infta /= 0) then
      print *, ' '
      print *, '!!! ERROR in sub read_netcdf_hours allocating'
      print *, '!!! temp_nc_time_vals_r8 array.  infta = ', infta
      irnhret = 94
      return
    endif

    ! now read in the actual time values that are stored in the NetCDF file
    call get_netcdf_real_type (ncfile_id, netcdfinfo%time_name, xtype, ignrret)

    if (xtype == 5) then
      call get_var1_one_dim4 (ncfile_id, netcdfinfo%time_name, ncfile_tmax, temp_nc_time_vals_r4)
      netcdf_file_time_values = temp_nc_time_vals_r4
    else
      call get_var1_one_dim8 (ncfile_id, netcdfinfo%time_name, ncfile_tmax, temp_nc_time_vals_r8)
      netcdf_file_time_values = temp_nc_time_vals_r8
    endif

    if (verb .ge. 1) then
      do k = 1, ncfile_tmax
        print *, 'k = ', k, ' netcdf_file_time_values(k) = ', netcdf_file_time_values(k)
      enddo
    endif

    if (allocated(temp_nc_time_vals_r4)) then
      deallocate (temp_nc_time_vals_r4)
    endif

    if (allocated(temp_nc_time_vals_r8)) then
      deallocate (temp_nc_time_vals_r8)
    endif

    if (allocated(nctotalmins)) then
      deallocate (nctotalmins)
    endif

    allocate (nctotalmins(ncfile_tmax), stat = infta)
    if (infta /= 0) then
      print *, ' '
      print *, '!!! ERROR in sub read_netcdf_hours allocating '
      print *, '!!! nctotalmins array.  infta = ', infta
      irnhret = 94
      return
    endif

    do k = 1, ncfile_tmax
      if (netcdfinfo%time_units == 'hours') then
        nctotalmins(k) = int(netcdf_file_time_values(k) * 60.0)
      elseif (netcdfinfo%time_units == 'days') then
        nctotalmins(k) = int(netcdf_file_time_values(k) * 60.0 * 24.0)
      else
        print *, ' '
        print *, '!!! ERROR: In read_netcdf_hours, the value of'
        print *, '    netcdfinfo%time_units is neither hours nor days.'
        print *, '    netcdfinfo%time_units = ', netcdfinfo%time_units
        print *, '    STOPPING....'
        print *, ' '
        stop 99
      endif

      if (verb .ge. 1) then
        write (6,71) k, netcdf_file_time_values(k), nctotalmins(k)
      endif
    enddo

71  format (1x, i5, '  netcdf_file_time_values(k) = ', f8.4, '  nctotalmins(k) = ', i10)

    do n = 1, ifhmax ! userloop
      usertime    = iftotalmins(n)
      match_check = 'n'

      do m = 1, ncfile_tmax  ! netcdfloop
        if (usertime == nctotalmins(m)) then
          if (verb .ge. 1) then
            print *, '+++ Time match for usertime = ', usertime
          endif
          match_check = 'y'
        endif
      enddo ! netcdfloop

      if (match_check == 'n') then

        if (usertime == 0) then
          print *, ' '
          print *, 'Warning: For a NetCDF file, the user has requested'
          print *, 'to read in an hour 0 file, however a scan of the'
          print *, 'time data values in the NetCDF file indicates'
          print *, 'that there is no hour 0 data in this file. '
          print *, 'We will substitute either missing values or '
          print *, 'the values from the TC Vitals data in the '
          print *, 'hour 0 record and then start searching at the '
          print *, 'next lead time.'
          ncfile_has_hour0 = 'n'
        else
          print *, ' '
          print *, '!!! ERROR: For a NetCDF file, the user has'
          print *, '  requested to process a particular lead time that'
          print *, '  does not exist in the NetCDF list of time '
          print *, '  values.'
          print *, '  n = ', n
          print *, '  usertime = iftotalmins(n) = ', iftotalmins(n)
          print *, '  STOPPING....'
          stop 99
        endif

      elseif (match_check == 'y') then

        if (usertime == 0) then
          if (verb .ge. 1) then
            print *, ' '
            print *, '+++ For the input NetCDF file, an hour0 data '
            print *, '    record exists in the data file.'
          endif
          ncfile_has_hour0 = 'y'
        endif
      endif
    enddo ! userloop

    return

  end subroutine read_netcdf_hours

  !****************************************************************************
  !*
  !*  ABSTRACT: This subroutine checks to see if the input lat/lon
  !*      point is associated with four surrounding (i,j) locations that
  !*      have valid data.  The writing of this routine was prompted by the
  !*      HFIP project in February, 2009.  Some of their high resolution
  !*      data for their inner nests contained grids that had been rotated
  !*      from native map projections to regular lat/lon grids, but that
  !*      rotation left "empty" spots on the lat/lon grid where there is
  !*      no data.  Then when searching in find_maxmin, we were running
  !*      barnes iterations from these lat/lon locations where there was
  !*      no data, which would give artificially low values at those
  !*      lat/lon locations (because the  barnes scheme would only include
  !*      points that were relatively far away where there was valid data).
  !*      So in this routine, we call subroutine  fix_latlon_to_ij in order
  !*      to get the nearest (i,j) coordinates, and then we check all of
  !*      these points to make sure that valid data exist.
  !*
  !*  INPUT:
  !*      imax         :: Num pts in i-direction on grid
  !*      jmax         :: Num pts in j-direction on grid
  !*      dx           :: grid spacing in i-direction
  !*      dy           :: grid spacing in j-direction
  !*      fxy          :: real array of input data values
  !*      cmaxmin      :: character that tells if searching for max or min
  !*      valid_pt     :: Logical; bitmap indicating if valid data at that pt
  !*      rlatt, rlont :: input lat/lon about which we will check the
  !*                      surrounding (i,j) locations for valid data.
  !*      grid_maxlat  :: northernmost latitude on the input grid being sent to
  !*                      this routine. This grid may be a subset of the original
  !*                      full grid from the original dataset.
  !*      grid_minlat  :: southernmost latitude on the input grid being sent to
  !*                      this routine. This grid may be a subset of the original
  !*                      full grid from the original dataset.
  !*      grid_maxlon  :: easternmost longitude on the input grid being sent to
  !*                      this routine. This grid may be a subset of the original
  !*                      full grid from the original dataset.
  !*      grid_minlon  :: westernmost longitude on the input grid being sent to
  !*                      this routine. This grid may be a subset of the original
  !*                      full grid from the original dataset.
  !*      trkrinfo     :: derived type containing grid info on user boundaries
  !*
  !*  OUTPUT:
  !*      icvpret      :: return code from this routine.  A value of 0 means that
  !*                      all is okay and the input point is surrounded by valid
  !*                      data.
  !*
  !****************************************************************************
  subroutine check_valid_point (imax, jmax, dx, dy, fxy, cmaxmin, valid_pt, rlont, rlatt, grid_maxlat, &
                               & grid_minlat, grid_maxlon, grid_minlon, trkrinfo, icvpret)

    use trkrparms

    implicit none

    type (trackstuff) :: trkrinfo

    integer          :: imax, jmax, ifix, jfix
    integer          :: ifilret, icvpret
    character(len=*) :: cmaxmin
    logical(1)       :: valid_pt(imax,jmax)
    real             :: fxy(imax,jmax)
    real             :: rlont, rlatt, xdum, gridpoint_maxmin
    real             :: dx, dy, grid_maxlat, grid_minlat, grid_maxlon, grid_minlon

    call fix_latlon_to_ij (imax, jmax, dx, dy, fxy, cmaxmin, valid_pt, rlont, rlatt, xdum, ifix, jfix, &
         & gridpoint_maxmin, 'checker', 'checker', grid_maxlat, grid_minlat, grid_maxlon, grid_minlon, &
         & trkrinfo, ifilret)

    if (ifilret /= 0) then
      icvpret = 99
      return
    endif

    if (valid_pt(ifix,jfix)) then
      icvpret = 0
    else
      icvpret = 99
    endif

    return

  end subroutine check_valid_point

  !****************************************************************************
  !*
  !*  ABSTRACT: This subroutine takes an input lat/lon position and
  !*      assigns it to a nearby (i,j) gridpoint.  If this is being used
  !*      before the call to check_closed_contour after the  barnes analysis
  !*      to see if we have a storm or not, then the lat/lon position that
  !*      is input into this subroutine is one which was obtained from a
  !*      barnes analysis, so it is essentially an area-weighted average
  !*      of nearby points.  What we need to do in this subroutine is find
  !*      the actual nearby gridpoint which does have the actual raw max or
  !*      min value.  Then we return the (i,j) coordinates of that point as
  !*      well as that raw data value at that point.
  !*
  !*  We want to do a simple search in the very few points around
  !*      this (ipfix,jpfix) point to find the raw max or min data
  !*      value.  First we need to set up a 4x4 box to search:
  !*
  !*            o     o     o     o
  !*
  !*
  !*             o     a     b     o
  !*                    +
  !*
  !*             o     c     d     o
  !*
  !*
  !*             o     o     o     o
  !*
  !*  In the above diagram, if "+" is the lat/lon location of our
  !*      barnes-found point (i.e., the input (parmlon,parmlat)), and
  !*      a-b-c-d is the square of points surrounding "+", we only want
  !*      to look out 1 layer of points further.  So first we need to
  !*      know, for each case we're looking at, if "+" got assigned to
  !*      a or b or c or d.  By the way, if the parmlon falls directly
  !*      on a gridpoint in either the i or j direction, we will only
  !*      look at the 2 gridpoints on either side of that point, as
  !*      opposed to having 4 points set up as in the box above.
  !*
  !*  NOTE: For fine resolution grids, it is
  !*      possible to have the gridpoint max/min be more than 1 or 2 grid
  !*      points away from the  barnes-averaged max.  So allow for this
  !*      here, with a check of grdspc ((dx+dy)/2) below and the
  !*      addition of the "grfact" multiplier for fine resolution grids.
  !*
  !*  INPUT:
  !*      imax             :: Num pts in i-direction on grid
  !*      jmax             :: Num pts in j-direction on grid
  !*      dx               :: grid spacing of the data grid in i-direction
  !*      dy               :: grid spacing of the data grid in j-direction
  !*      fxy              :: real array of input data values
  !*      cmaxmin          :: character that tells if searching for max or min
  !*      valid_pt         :: Logical; bitmap indicating if valid data at that pt
  !*      parmlon          :: lon at which input parameter center was found, or the lon
  !*                          for the mean storm center fix (check calling routine)
  !*      parmlat          :: lat at which input parameter center was found, or the lat
  !*                          for the mean storm center fix (check calling routine)
  !*      xdataval         :: barnes-obtained value of parameter at (parmlon,parmlat)
  !*      ccall            :: character that tells if this call is part of a tracker
  !*                          fix routine or just from the check_valid_point routine
  !*                          ('tracker' or 'checker')
  !*      grid_maxlat      :: northernmost latitude on the input grid being sent to
  !*                          this routine. This grid may be a subset of the original
  !*                          full grid from the original dataset, or it may be the
  !*                          original grid itself.
  !*      grid_minlat      :: southernmost latitude on the input grid being sent to
  !*                          this routine. This grid may be a subset of the original
  !*                          full grid from the original dataset, or it may be the
  !*                          original grid itself.
  !*      grid_maxlon      :: easternmost longitude on the input grid being sent to
  !*                          this routine. This grid may be a subset of the original
  !*                          full grid from the original dataset, or it may be the
  !*                          original grid itself.
  !*      grid_minlon      :: westernmost longitude on the input grid being sent to
  !*                          this routine. This grid may be a subset of the original
  !*                          full grid from the original dataset, or it may be the
  !*                          original grid itself.
  !*      trkrinfo         :: derived type containing grid info on user boundaries
  !*      stopcheck        :: character, if set to gptmslp, then there is a check that
  !*                          will ignore MSLP values that are erroneously reporting
  !*                          values < 0, which is due to a grid transformation issue
  !*                          that very occasionally occurs in HWRF.
  !*
  !*  OUTPUT:
  !*      ifix             :: i-index for gridpoint to which the max or min is assigned
  !*      jfix             :: j-index for gridpoint to which the max or min is assigned
  !*      gridpoint_maxmin :: value of fxy at (ifix,jfix).  This will be
  !*                          different from the input value xdataval, which came from
  !*                          the  barnes averaging.  This is the raw value at the
  !*                          gridpoint.
  !*
  !****************************************************************************
  subroutine fix_latlon_to_ij (imax, jmax, dx, dy, fxy, cmaxmin, valid_pt, parmlon, parmlat, xdataval,    &
                              & ifix, jfix, gridpoint_maxmin, ccall, stopcheck, grid_maxlat, grid_minlat, &
                              & grid_maxlon, grid_minlon, trkrinfo, ifilret)

    use grid_bounds; use trkrparms; use verbose_output

    implicit none

    type (trackstuff) :: trkrinfo

    integer           :: imax, jmax, istart, iend, jstart, jend, ifix, jfix
    integer           :: ipfix, jpfix, i, j, ifilret, iix, jix, grfact
    character(len=*)  :: cmaxmin, ccall, stopcheck
    logical(1)        :: valid_pt(imax,jmax)
    real              :: fxy(imax,jmax)
    real              :: parmlon, parmlat, xdataval, gridpoint_maxmin
    real              :: xplon, yplat, dmin, dmax, dx, dy, grdspc
    real              :: grid_maxlat, grid_minlat, grid_maxlon, grid_minlon

    ifilret = 0

    ! fix parmlat to the *nearest* j-point
    if (parmlat >= 0.0) then    ! N. Hemisphere
      jpfix = int((grid_maxlat - parmlat) / dy + 1.0 + 0.5)
    else                        ! S. Hemisphere
      jpfix = ceiling((grid_maxlat - parmlat) / dy + 1.0 - 0.5)
    endif

    ! fix parmlon to the *nearest* i-point
    ipfix = int((parmlon - grid_minlon) / dx + 1.0 + 0.5)

    ! calculate the longitude and latitude of these ipfix and jpfix points
    xplon = grid_minlon + (ipfix - 1.0) * dx
    yplat = grid_maxlat - (jpfix - 1.0) * dy

    grdspc = (dx+dy) * 0.5
    if (grdspc <= 0.025) then
      grfact = 20
    else if (grdspc > 0.025 .and. grdspc <= 0.05) then
      grfact = 12
    else if (grdspc > 0.05  .and. grdspc <= 0.10) then
      grfact = 6
    else if (grdspc > 0.10  .and. grdspc <= 0.20) then
      grfact = 3
    else if (grdspc > 0.20  .and. grdspc <= 0.30) then
      grfact = 2
     else
      grfact = 1
    endif

    if (xplon < parmlon) then         !(ipfix is at either a or c)
      istart = ipfix - (1 * grfact)
      iend   = ipfix + (2 * grfact)
    else if (xplon > parmlon) then    !(ipfix is at either b or d)
      istart = ipfix - (2 * grfact)
      iend   = ipfix + (1 * grfact)
    else if (xplon == parmlon) then   !(parmlon is exactly ipfix)
      istart = ipfix - (1 * grfact)
      iend   = ipfix + (1 * grfact)
    endif

    if (yplat < parmlat) then         !(jpfix is at either c or d)
      jstart = jpfix - (2 * grfact)
      jend   = jpfix + (1 * grfact)
    else if (yplat > parmlat) then    !(jpfix is at either a or b)
      jstart = jpfix - (1 * grfact)
      jend   = jpfix + (2 * grfact)
    else if (yplat == parmlat) then   !(parmlat is exactly jpfix)
      jstart = jpfix - (1 * grfact)
      jend   = jpfix + (1 * grfact)
    endif

    ! make sure the edges of our box are within the grid bounds
    if (jstart > jmax ) then
      if (verb .ge. 1) then
        print *, '!!! ERROR in fix_latlon_to_ij, jstart > jmax'
        print *, '!!! ', ccall, '  jstart = ', jstart, ' jmax = ', jmax
      endif
      ifilret = 99
      return
    endif

    if (jend < 1) then
      if (verb .ge. 1) then
        print *, '!!! ERROR in fix_latlon_to_ij, ', ccall, ' jend < 1, jend = ', jend
      endif
      ifilret = 98
      return
    endif
    
    if (jstart < 1) jstart = 1
    if (jend > jmax) jend = jmax

    if (istart > imax ) then
      if (trkrinfo%gridtype == 'global') then
        continue  ! GM wrapping will be handled in loop below
      else
        if (verb .ge. 1) then
          print *, '!!! ERROR in fix_latlon_to_ij, istart > imax'
          print *, '!!! istart = ', istart, ' imax = ', imax
        endif
        ifilret = 97
        return
      endif
    endif

    if (iend < 1) then
      if (trkrinfo%gridtype == 'global') then
        continue  ! GM wrapping will be handled in loop below
      else
        if (verb .ge. 1) then
          print *, '!!! ERROR in fix_latlon_to_ij, iend < 1, iend = ', iend, ' call type = ', ccall
        endif
        ifilret = 96
        return
      endif
    endif

    if (iend > imax) then
      if (trkrinfo%gridtype == 'global') then
        continue  ! GM wrapping will be handled in loop below
      else
        iend = imax  ! for a regional grid, just cut it off
      endif
    endif

    if (istart < 1) then
      if (trkrinfo%gridtype == 'global') then
        continue  ! GM wrapping will be handled in loop below
      else
        istart = 1  ! for a regional grid, just cut it off
      endif
    endif

    ! now look for the max or min value
    dmax = -9.99E12
    dmin =  9.99E12
    ifix = ipfix
    jfix = jpfix

    do iix = istart, iend ! iloop
      do jix = jstart, jend ! jloop
        i = iix
        j = jix

        if (i < 1) then
          i = iix + imax  ! GM wrapping
        endif
        if (i > imax) then
          i = iix - imax  ! GM wrapping
        endif

        if (valid_pt(i,j)) then
          continue
        else
          ifilret = 95
          return
        endif

        if (cmaxmin == 'min') then
          if (fxy(i,j) < 0.0) then
            if (stopcheck == 'gptmslp') then
              print *, ' '
              print *, '!!! GRIDPOINT MSLP < 0 : Likely grid edge'
              print *, '!!! mismatch issue in fix_latlon_ij.'
              print *, '!!! i = ', i, ' j = ', j, ' fxy(i,j) = ', fxy(i,j)
              print *, '!!! This point will be skipped while trying to'
              print *, '!!! get the grid point min MSLP value.'
              print *, ' '
              cycle   ! jloop
            endif
          endif
          if (fxy(i,j) < dmin) then
            dmin = fxy(i,j)
            ifix = i
            jfix = j
          endif
        else
          if (fxy(i,j) > dmax) then
            dmax = fxy(i,j)
            ifix = i
            jfix = j
          endif
        endif

      enddo ! jloop
    enddo ! iloop

    if (cmaxmin == 'min') then
      gridpoint_maxmin = dmin
    else
      gridpoint_maxmin = dmax
    endif

    return

  end subroutine fix_latlon_to_ij

  !****************************************************************************
  !*
  !*  ABSTRACT: This routine calculates the relative vorticity (zeta)
  !*      from u,v on a lat/lon grid. Centered finite
  !*      differences are used on the interior points and one-sided
  !*      differences are used on the boundaries.
  !*
  !*  NOTE: There are 3 critical arrays in this subroutine, the first
  !*      being zeta and the 2nd and 3rd being u and v.  There is a
  !*      critical difference in the array indexing for the levels.  For
  !*      zeta, the array is dimensioned with levels from 1 to 3, with
  !*      1 = 850, 2 = 700, 3 = sfc.  However, there are extra levels
  !*      for the winds, such that the level dimension goes 1 = 850,
  !*      2 = 700, 3 = 500, 4 = 200, 5 = sfc, and this is annotated now
  !*      by the use of the "nlev850", "nlev700" and "levsfc" variables
  !*      from module level_parms.  So we need to be sure to properly
  !*      annotate that in this routine.
  !*
  !****************************************************************************
  subroutine rvcal (imax, jmax, dlon, dlat, z, vp)

    use tracked_parms; use trig_vals; use grid_bounds; use verbose_output; use level_parms

    implicit none

    dimension  :: cosfac(jmax), tanfac(jmax) !CAITLYN - i still have never seen this data type
    real       :: tmpzeta(imax,jmax)
    real       :: xlondiff, xlatdiff, dlon, dlat, dfix
    real       :: dlat_edge, dlat_inter, dlon_edge, dlon_inter
    real       :: rlat(jmax), cosfac, tanfac
    integer    :: z, iscanflag, nlat, nlon, i, j, imax, jmax, w
    integer    :: ii, jj
    logical(1) :: vp(imax,jmax)

    ! figure out what level of data we have and what the array indices should be
    if (z == 1) then
      ! z = 1 for 850 mb zeta, w = 1 for 850 mb winds
      w = nlev850
    else if (z == 2) then
      ! z = 2 for 700 mb zeta, w = 2 for 700 mb winds
      w = nlev700
    else if (z == 3) then
      ! z = 3 for sfc zeta, w = 5 for sfc (10m) winds
      w = levsfc
    endif

    ! calculate grid increments for interior and edge points
    if (dtk < 750.0) then    ! if dtk was defined as km, then x1000
      dfix = 1000.0
    else                     ! dtk was already defined as meters
      dfix = 1.0
    endif

    dlon_edge  = dtk * dfix * dlon         ! Di dist over 1 grid pt
    dlat_edge  = dtk * dfix * dlat         ! Dj dist over 1 grid pt
    dlon_inter = dtk * dfix * 2.0 * dlon   ! Di dist over 2 grid pts
    dlat_inter = dtk * dfix * 2.0 * dlat   ! Dj dist over 2 grid pts

    do j = 2, jmax-1
      rlat(j)   = glatmax - ((j-1) * dlat)
      cosfac(j) = cos(dtr * rlat(j))
      tanfac(j) = tan(dtr * rlat(j)) / erad
    enddo

    cosfac(1)    = cosfac(2)
    tanfac(1)    = tanfac(2)
    cosfac(jmax) = cosfac(jmax-1)
    tanfac(jmax) = tanfac(jmax-1)

    if (verb .ge. 3) then
      print *, 'Just before inter rvcalc, dlon_inter = ', dlon_inter, ' dlat_inter = ', dlat_inter
    endif

    ! interior points
    do j = 2, jmax-1
      do i = 2, imax-1
        if (vp(i,j) .and. vp(i+1,j) .and. vp(i-1,j) .and. vp(i,j+1) .and. vp(i,j-1)) then
        zeta(i, j, z) = (v(i+1, j, w) - v(i-1, j, w)) / (dlon_inter * cosfac(j)) - (u(i, j-1, w) &
                      - u(i, j+1, w)) / (dlat_inter) + tanfac(j) * u(i, j, w)
        else
          zeta(i, j, z) = 2.0 * omega * sin(rlat(j) * dtr)
        endif
      enddo
    enddo

    ! bottom (Southernmost) points
    j = jmax
    do i = 2, imax-1
      if (vp(i,j) .and. vp(i+1,j) .and. vp(i-1,j) .and. vp(i,j-1)) then
        zeta(i, j, z) = (v(i+1, j, w) - v(i-1, j, w)) / (dlon_inter * cosfac(j)) - (u(i, j-1, w) &
                      - u(i, j, w)) / (dlat_edge) + tanfac(j) * u(i, j, w)
      else
        zeta(i, j, z) = 2.0 * omega * sin(rlat(j) * dtr)
      endif
    enddo

    ! top (Northernmost) points
    j = 1
    do i = 2, imax-1
      if (vp(i,j) .and. vp(i+1,j) .and. vp(i-1,j) .and. vp(i,j+1)) then
        zeta(i, j, z) = (v(i+1, j, w) - v(i-1, j, w)) / (dlon_inter * cosfac(j)) - (u(i, j, w) &
                      - u(i, j+1, w)) / (dlat_edge) + tanfac(j) * u(i, j, w)
      else
        zeta(i, j, z) = 2.0 * omega * sin(rlat(j) * dtr)
      endif
    enddo

    ! left edge (Westernmost) points
    i = 1
    do j = 2, jmax-1
      if (vp(i,j) .and. vp(i+1,j) .and. vp(i,j+1) .and. vp(i,j-1)) then
        zeta(i, j, z) = (v(i+1, j, w) - v(i, j, w)) / (dlon_edge * cosfac(j)) - (u(i, j-1, w) &
                      - u(i, j+1, w)) / (dlat_inter) + tanfac(j) * u(i, j, w)
      else
        zeta(i, j, z) = 2.0 * omega * sin(rlat(j) * dtr)
      endif
    enddo

    ! right edge (Easternmost) points
    i = imax
    do j = 2, jmax-1
      if (vp(i,j) .and. vp(i-1,j) .and. vp(i,j+1) .and. vp(i,j-1)) then
         zeta(i, j, z) = (v(i, j, w) - v(i-1, j, w)) / (dlon_edge * cosfac(j)) - (u(i, j-1, w) &
                       - u(i, j+1, w)) / (dlat_inter) + tanfac(j) * u(i, j, w)
      else
        zeta(i, j, z) = 2.0 * omega * sin(rlat(j) * dtr)
      endif
    enddo

    ! SW corner
    i = 1
    j = jmax
    if (vp(i,j) .and. vp(i+1,j) .and. vp(i,j-1)) then
      zeta(i, j, z) = (v(i+1, j, w) - v(i, j, w)) / (dlon_edge * cosfac(j)) - (u(i, j-1, w) &
                    - u(i, j, w)) / (dlat_edge) + tanfac(j) * u(i, j, w)
    else
      zeta(i, j, z) = 2.0 * omega * sin(rlat(j) * dtr)
    endif

    ! NW corner
    i = 1
    j = 1
    if (vp(i,j) .and. vp(i+1,j) .and. vp(i,j+1)) then
      zeta(i, j, z) = (v(i+1, j, w) - v(i, j, w)) / (dlon_edge * cosfac(j)) - (u(i, j, w) &
                    - u(i, j+1, w)) / (dlat_edge) + tanfac(j) * u(i, j, w)
    else
      zeta(i, j, z) = 2.0 * omega * sin(rlat(j) * dtr)
    endif

    ! NE corner
    i = imax
    j = 1
    if (vp(i,j) .and. vp(i-1,j) .and. vp(i,j+1)) then
      zeta(i, j, z) = (v(i, j, w) - v(i-1, j, w)) / (dlon_edge * cosfac(j)) - (u(i, j, w) &
                    - u(i, j+1, w)) / (dlat_edge) + tanfac(j) * u(i, j, w)
    else
      zeta(i, j, z) = 2.0 * omega * sin(rlat(j) * dtr)
    endif

    ! SE corner
    i = imax
    j = jmax
    if (vp(i,j) .and. vp(i-1,j) .and. vp(i,j-1)) then
      zeta(i, j, z) = (v(i, j, w) - v(i-1, j, w)) / (dlon_edge * cosfac(j)) - (u(i, j-1, w) &
                  - u(i, j, w)) / (dlat_edge) + tanfac(j) * u(i, j, w)
    else
      zeta(i, j, z) = 2.0 * omega * sin(rlat(j) * dtr)
    endif

    do ii = 1, imax
      do jj = 1, jmax
        tmpzeta(ii, jj) = zeta(ii, jj, z) * 1.0E5
      enddo
    enddo

    return

  end subroutine rvcal

  !****************************************************************************
  !*
  !*  ABSTRACT: This routine calculates the divergence
  !*      from u,v on a lat/lon grid. Centered finite
  !*      differences are used on the interior points and one-sided
  !*      differences are used on the boundaries.
  !*
  !*  NOTE: There are 3 critical arrays in this subroutine, the first
  !*      being divergence and the 2nd and 3rd being u and v.  There is a
  !*      critical difference in the array indexing for the levels.  For
  !*      divergence, the array is dimensioned with levels from 1 to 3, with
  !*      1 = 850, 2 = 700, 3 = sfc.  However, there are extra levels
  !*      for the winds, such that the level dimension goes 1 = 850,
  !*      2 = 700, 3 = 500, 4 = 200, 5 = sfc, and this is annotated now
  !*      by the use of the "nlev850", "nlev700" and "levsfc" variables
  !*      from module level_parms.  So we need to be sure to properly
  !*      annotate that in this routine.
  !*
  !*  INPUT:
  !*      imax    :: integer max number of pts in x-direction on input grid
  !*      jmax    :: integer max number of pts in y-direction on input grid
  !*      dlon    :: real grid spacing in x-direction
  !*      dlat    :: real grid spacing in y-direction
  !*      vp      :: Logical; bitmap array used for regional grids
  !*      w       :: integer indicates which index to use for the vertical
  !*                 level, with 1=850, as described in the doc block above.
  !*
  !*  OUTPUT
  !*      divx4   :: real array with divergence values to be returned to the
  !*                 calling routine, scaled up by 1e4
  !*      idvcret :: integer return code from this routine
  !*
  !****************************************************************************
  subroutine divcal (imax, jmax, dlon, dlat, divx4, vp, w, idvcret)

    use trig_vals; use grid_bounds; use verbose_output; use level_parms; use tracked_parms

    implicit none

    real, parameter   :: xsmalldiff = 0.0
    dimension         :: cosfac(jmax),tanfac(jmax)
    real, allocatable :: div(:,:)
    real              :: divx4(imax,jmax)
    real              :: xlondiff, xlatdiff, dlon, dlat, dfix
    real              :: dlat_edge, dlat_inter, dlon_edge, dlon_inter
    real              :: rlat(jmax), cosfac, tanfac
    integer           :: nlat, nlon, i, j, imax, jmax, w
    integer           :: ii, jj, idvcret, ida
    logical(1)        :: vp(imax,jmax)

    if (allocated(div)) deallocate (div)
    allocate (div(imax,jmax), stat = ida)
    if (ida /= 0) then
      print *, ' '
      print *, '!!! ERROR in sub divcal allocating '
      print *, '!!! div array.  ida = ', ida
      idvcret = 94
      return
    endif

    print *, ' '
    print *, 'top of divcal, imax = ',  imax, ' jmax = ', jmax
    print *, 'dlon = ', dlon, ' dlat = ', dlat

    if (dtk < 750.0) then    ! dtk was defined as km, x1000
      dfix = 1000.0
    else                     ! dtk was already defined as meters
      dfix = 1.0
    endif

    dlon_edge  = dtk * dfix * dlon         ! Di dist over 1 grid pt
    dlat_edge  = dtk * dfix * dlat         ! Dj dist over 1 grid pt
    dlon_inter = dtk * dfix * 2.0 * dlon   ! Di dist over 2 grid pts
    dlat_inter = dtk * dfix * 2.0 * dlat   ! Dj dist over 2 grid pts

    do j = 2, jmax-1
      rlat(j)   = glatmax - ((j-1) * dlat)
      cosfac(j) = cos(dtr * rlat(j))
      tanfac(j) = tan(dtr * rlat(j)) / erad
    enddo

      cosfac(1)    = cosfac(2)
      tanfac(1)    = tanfac(2)
      cosfac(jmax) = cosfac(jmax-1)
      tanfac(jmax) = tanfac(jmax-1)

    ! interior points
    if (verb .ge. 3) then
      print *, 'Just before inter divcal, dlon_inter = ', dlon_inter, ' dlat_inter = ', dlat_inter
    endif

    do j = 2, jmax-1
      do i = 2, imax-1
        if (vp(i,j) .and. vp(i+1,j) .and. vp(i-1,j) .and. vp(i,j+1) .and. vp(i,j-1)) then
          div(i, j) = (u(i+1, j, w) - u(i-1, j, w)) / (dlon_inter * cosfac(j)) + (v(i, j-1, w) &
                    - v(i, j+1, w)) / (dlat_inter) - tanfac(j) * v(i, j, w)
        else
          div(i, j) = xsmalldiff / (dlon_inter * cosfac(j)) + xsmalldiff / (dlat_inter)
        endif
      enddo
    enddo

    ! bottom (Southernmost) points
    j = jmax
    do i = 2, imax-1
      if (vp(i,j) .and. vp(i+1,j) .and. vp(i-1,j) .and. vp(i,j-1)) then
        div(i, j) = (u(i+1, j, w) - u(i-1, j, w)) / (dlon_inter * cosfac(j)) + (v(i, j-1, w) &
                  - v(i, j, w)) / (dlat_edge) - tanfac(j) * v(i, j, w)
      else
        div(i, j) = xsmalldiff / (dlon_inter * cosfac(j)) + xsmalldiff / dlat_inter
      endif
    enddo

    ! top (Northernmost) points
    j = 1
    do i = 2, imax-1
      if (vp(i,j) .and. vp(i+1,j) .and. vp(i-1,j) .and. vp(i,j+1)) then
        div(i, j) = (u(i+1, j, w) - u(i-1, j, w)) / (dlon_inter * cosfac(j)) + (v(i, j, w) &
                  - v(i, j+1, w)) / (dlat_edge) - tanfac(j) * v(i, j, w)
      else
        div(i, j) = xsmalldiff / (dlon_inter * cosfac(j)) + xsmalldiff / (dlat_inter)
      endif
    enddo

    ! left edge (Westernmost) points
    i = 1
    do j = 2, jmax-1
      if (vp(i,j) .and. vp(i+1,j) .and. vp(i,j+1) .and. vp(i,j-1)) then
        div(i, j) = (u(i+1, j, w) - u(i, j, w)) / (dlon_edge * cosfac(j)) + (v(i, j-1, w) &
                  - v(i, j+1, w)) / (dlat_inter) - tanfac(j) * v(i, j, w)
      else
        div(i, j)= xsmalldiff / (dlon_inter * cosfac(j)) + xsmalldiff / (dlat_inter)
      endif
    enddo

    ! right edge (Easternmost) points
    i = imax
    do j = 2, jmax-1
      if (vp(i,j) .and. vp(i-1,j) .and. vp(i,j+1) .and. vp(i,j-1)) then
        div(i, j) = (u(i, j, w) - u(i-1, j, w)) / (dlon_edge * cosfac(j)) + (v(i, j-1, w) &
                  - v(i, j+1, w)) / (dlat_inter) - tanfac(j) * v(i, j, w)
      else
        div(i, j) = xsmalldiff / (dlon_inter * cosfac(j)) + xsmalldiff / (dlat_inter)
      endif
    enddo

    ! SW corner
    i = 1
    j = jmax
    if (vp(i,j) .and. vp(i+1,j) .and. vp(i,j-1)) then
      div(i, j) = (u(i+1, j, w) - u(i, j, w)) / (dlon_edge * cosfac(j)) + (v(i, j-1, w) &
                - v(i, j, w)) / (dlat_edge) - tanfac(j) * v(i, j, w)
    else
      div(i, j) = xsmalldiff / (dlon_inter * cosfac(j)) + xsmalldiff / (dlat_inter)
    endif

    ! NW corner
    i = 1
    j = 1
    if (vp(i,j) .and. vp(i+1,j) .and. vp(i,j+1)) then
      div(i, j) = (u(i+1, j, w) - u(i, j, w)) / (dlon_edge * cosfac(j)) + (v(i, j, w) &
                - v(i, j+1, w)) / (dlat_edge) - tanfac(j) * v(i, j, w)
    else
      div(i, j) = xsmalldiff / (dlon_inter * cosfac(j)) + xsmalldiff / (dlat_inter)
    endif

    ! NE corner
    i = imax
    j = 1
    if (vp(i,j) .and. vp(i-1,j) .and. vp(i,j+1)) then
      div(i, j) = (u(i, j, w) - u(i-1, j, w)) / (dlon_edge * cosfac(j)) + (v(i, j, w) &
                - v(i, j+1, w)) / (dlat_edge) - tanfac(j) * v(i, j, w)
    else
      div(i, j) = xsmalldiff / (dlon_inter * cosfac(j)) + xsmalldiff / (dlat_inter)
    endif

    ! SE corner
    i = imax
    j = jmax
    if (vp(i,j) .and. vp(i-1,j) .and. vp(i,j-1)) then
      div(i, j) = (u(i, j, w) - u(i-1, j, w)) / (dlon_edge * cosfac(j)) + (v(i, j-1, w) &
                - v(i, j, w)) / (dlat_edge) - tanfac(j) * v(i, j, w)
    else
      div(i, j) = xsmalldiff / (dlon_inter * cosfac(j)) + xsmalldiff / (dlat_inter)
    endif

    do ii = 1, imax
      do jj = 1, jmax
        divx4(ii, jj) = div(ii, jj) * 1.0E4
      enddo
    enddo

    if (allocated(div)) deallocate (div)

    return

  end subroutine divcal

  !****************************************************************************
  !*
  !*  ABSTRACT: This routine computes one smoothed value of a value from
  !*      an input real array.  It does this using the  Barnes analysis and
  !*      values of re and ri that are also specified in the calling
  !*      routine.
  !*
  !*  INPUT:
  !*      xcenlon    :: real value of center position at which to compute average
  !*      xcenlat    :: real value of center position at which to compute average
  !*      ist        :: Storm number currently being processed
  !*      ifh        :: Forecast hour currently being processed
  !*      imax       :: Max number of pts in x-direction for this grid
  !*      jmax       :: Max number of pts in y-direction for this grid
  !*      xarray     :: real array with data values that will be searched here
  !*      cvar       :: character string that contains variable being searched
  !*      dx         :: grid-spacing of the model in the i-direction
  !*      dy         :: grid-spacing of the model in the j-direction
  !*      valid_pt   :: Logical; bitmap indicating if valid data at that pt.
  !*      maxstorm   :: Max # of storms that can be handled in this run
  !*      re         :: real e-folding radius
  !*      ri         :: real radius of influence
  !*      trkrinfo   :: derived type detailing user-specified grid info
  !*
  !*  OUTPUT:
  !*      xsmoothval :: real smoothed value of the input variable, centered
  !*                    on the input (xcenlon,xcenlat) point.
  !*      igsvret    :: integer return code from this routine
  !*
  !****************************************************************************
  subroutine get_smooth_value_at_pt (xcenlon, xcenlat, ist, ifh, imax, jmax, xarray, cvar, dx, dy, &
                                    & valid_pt, maxstorm, re, ri, trkrinfo, xsmoothval, igsvret)

    use def_vitals;    use grid_bounds; use trig_vals
    use tracked_parms; use trkrparms;   use verbose_output

    implicit none

    type (trackstuff) :: trkrinfo

    integer           :: ist, ifh, imax, jmax, maxstorm, igsvret, npts, bskip, icut
    integer           :: ilonfix, jlatfix, ibeg, jbeg, iend, jend, igiret, icutmax
    integer           :: icount, ibret
    real              :: xarray(imax,jmax)
    real              :: re, ri, xsmoothval, xcenlon, xcenlat, dx, dy, reold, riold
    logical(1)        :: valid_pt(imax,jmax)
    character(len=1)  :: in_grid
    character(len=*)  :: cvar

    xsmoothval = -9999.0

    if (verb >= 3) then
      print *, ' '
      print *, ' --- Top of get_smooth_value_at_pt for '
      print *, '     variable = ', cvar
    endif

    npts = ceiling(ri / (dtk * ((dx+dy) / 2)))

    if (verb >= 3) then
      print *, ' '
      print *, ' In get_smooth_value_at_pt for cvar = ', cvar
      print *, ' *** BEFORE *** call to get_ij_bounds'
      print *, ' npts    = ', npts,    ' ri      = ', ri
      print *, ' imax    = ', imax,    ' jmax    = ', jmax
      print *, ' dx      = ', dx,      ' dy      = ', dy
      print *, ' glatmax = ', glatmax, ' glatmin = ', glatmin
      print *, ' glonmax = ', glonmax, ' glonmin = ', glonmin
      print *, ' xcenlon = ', xcenlon, ' xcenlat = ', xcenlat
      print *, ' '
    endif

    call get_ij_bounds (npts, 0, ri, imax, jmax, dx, dy, glatmax, glatmin, glonmax, glonmin,  &
         & xcenlon, xcenlat, trkrinfo, ilonfix, jlatfix, ibeg, jbeg, iend, jend, igiret)

    if (verb >= 3) then
      print *, ' '
      print *, ' In get_smooth_value_at_pt for cvar = ', cvar
      print *, ' *** AFTER *** call to get_ij_bounds'
      print *, ' npts    = ', npts,    ' ri      = ', ri
      print *, ' imax    = ', imax,    ' jmax    = ', jmax
      print *, ' dx      = ', dx,      ' dy      = ', dy
      print *, ' glatmax = ', glatmax, ' glatmin = ', glatmin
      print *, ' glonmax = ', glonmax, ' glonmin = ', glonmin
      print *, ' xcenlon = ', xcenlon, ' xcenlat = ', xcenlat
      print *, ' ilonfix = ', ilonfix, ' jlatfix = ', jlatfix
      print *, ' ibeg    = ', ibeg,    ' iend    = ', iend
      print *, ' jbeg    = ', jbeg,    ' jend    = ', jend, ' igiret = ', igiret
      print *, ' '
    endif

    if (igiret /= 0) then
      if (verb .ge. 1) then
        print *, ' '
        print *, '!!! ERROR in get_smooth_value_at_pt from call to'
        print *, '!!! get_ij_bounds, STOPPING processing for '
        print *, '!!! storm number ', ist
      endif
      igsvret = 92
      return
    endif

    if (verb >= 3) then
      print *, ' '
      print *, ' +++ In get_smooth_value_at_pt after call'
      print *, '     to get_ij_bounds getting bounds for '
      print *, '     the  barnes analysis...'
      print *, '     cvar    = ',    cvar
      print *, '     glatmax = ', glatmax, '  glatmin = ', glatmin
      print *, '     glonmax = ', glonmax, '  glonmin = ', glonmin
      print *, '     xcenlon = ', xcenlon, '  xcenlat = ', xcenlat
      print *, '     ilonfix = ', ilonfix, '  jlatfix = ', jlatfix
      print *, '     ibeg    = ',    ibeg, '  iend    = ',    iend
      print *, '     jbeg    = ',    jbeg, '  jend    = ',    jend
    endif

    ! barnes analysis centered at one point; set bskip = 1
    bskip   = 1
    icut    = 0
    in_grid = 'n'

    if (trkrinfo%type == 'midlat') then
      icutmax = 2
    else
      icutmax = 1
    endif

    do while (icut <= icutmax .and. in_grid == 'n') ! radmaxloop
      ibret = 0

      if (cvar == 'sst') then
        call sst_barnes (xcenlon, xcenlat, glon, glat, imax, jmax, ibeg, jbeg, iend, jend, &
             & sst(1,1), valid_pt, bskip, re, ri, xsmoothval, icount, 'vitals', trkrinfo, ibret)
        print *, 'After call to sst_barnes, xsmoothval = ', xsmoothval
      else
        call barnes (xcenlon, xcenlat, glon, glat, imax, jmax, ibeg, jbeg, iend, jend, &
             & xarray(1,1), valid_pt, bskip, re, ri, xsmoothval, icount, cvar, trkrinfo, ibret)
        print *, 'After call to barnes, xsmoothval = ', xsmoothval
      endif

      if (ibret == 0) then
        in_grid = 'y'

        if (verb >= 3) then
          print *, ' '
          print *, ' --- In get_smooth_value_at_pt, after call to '
          print *, '     get smoothval.  mean stats follow:'
          print *, '     If cvar = sst, then the call was to'
          print *, '     sst_barnes, for all others it was to barnes.'
          print *, '     cvar    = ',    cvar,    ' xsmoothval = ', xsmoothval
          print *, '     xcenlon = ', xcenlon,    '  xcenlat   = ', xcenlat
        endif

      else
        ibret = 96
        reold = re
        riold = ri
        re    = 0.5 * re
        ri    = 0.5 * ri

        if (verb .ge. 3) then
          print *, ' '
          print *, 'NOTE: While attempting to use the  barnes '
          print *, 'analysis called from get_smooth_value_at_pt,'
          print *, 'the algorithm tried to access a grid point'
          print *, 'that does not have valid data, meaning that'
          print *, 'too large a radius is being searched.  So, the'
          print *, 'two radii, re and ri, are being halved and, if'
          print *, 'the value of icutmax > 0,  the algorithm will'
          print *, 'be run again.  Otherwise, if icutmax = 0, only'
          print *, 'the extrapolation method will be used.'
          print *, 'ibret  = ',   ibret, '                 icut = ', icut
          print *, 'Old re = ', reold, ' New re (for next loop) = ', re
          print *, 'Old ri = ', riold, ' New ri (for next loop) = ', ri
        endif

        icut = icut + 1
      endif
    enddo  ! radmaxloop

    return

  end subroutine get_smooth_value_at_pt

  !****************************************************************************
  !*
  !*ABSTRACT: This routine computes smoothed values of RH, averaged
  !*     over multiple layers, initially 1000-925 mb and 800-600 mb.
  !*     It does this by first calling a routine that will average the
  !*     data from various vertical levels together, then by calling a
  !*     a routine that uses the  Barnes analysis and values of re and ri
  !*     that are also specified in the calling routine.
  !*
  !*     INPUT:
  !*     xcenlon real value of center position at which to compute average
  !*     xcenlat real value of center position at which to compute average
  !*     ist     Storm number currently being processed
  !*     ifh     Forecast hour currently being processed
  !*     imax    Max number of pts in x-direction for this grid
  !*     jmax    Max number of pts in y-direction for this grid
  !*     dx      grid-spacing of the model in the i-direction
  !*     dy      grid-spacing of the model in the j-direction
  !*     valid_pt Logical; bitmap indicating if valid data at that pt.
  !*     maxstorm Max # of storms that can be handled in this run
  !*     re      real e-folding radius
  !*     ri      real radius of influence
  !*     trkrinfo derived type detailing user-specified grid info
  !*     readgenflag logical array, indicates if a genesis parm was read in
  !*     already_computed_domain_wide_rh character (y/n) indicates if RH
  !*             has already been computed across the whole domain for this
  !*             forecast hour (this keeps us from re-computing it for
  !*             every storm at each lead time).
  !*
  !*     OUTPUT:
  !*     rh_1000_925_smooth real value of the smoothed value of
  !*                 barnes-averaged RH in the 1000-925 mb layer.
  !*     rh_800_600_smooth  real value of the smoothed value of
  !*                 barnes-averaged RH in the 800-600 mb layer.
  !*     igsvret integer return code from this routine
  !*
  !****************************************************************************
  subroutine get_rh_at_center (xcenlon, xcenlat, ist, ifh, imax, jmax, dx, dy, valid_pt, maxstorm, re, ri, &
                              & trkrinfo, rh_1000_925_smooth, rh_800_600_smooth, readgenflag,              &
                              & already_computed_domain_wide_rh, igrhret)

    use def_vitals; use grid_bounds; use trig_vals;     use tracked_parms; 
    use read_parms; use trkrparms;   use genesis_diags; use verbose_output

    implicit none

    type (trackstuff) :: trkrinfo
    
    integer           :: ist, ifh, imax, jmax, maxstorm, igsvret, npts, bskip, icut
    integer           :: ilonfix, jlatfix, ibeg, jbeg, iend, jend, igiret, icutmax
    integer           :: icount, ibret, imrhf, ichrret, icmlret, ip, igrhret
    real, allocatable :: mean_rh(:,:)
    real              :: re, ri, xsmoothval, xcenlon, xcenlat, dx, dy, reold, riold
    real              :: rh_1000_925_smooth, rh_800_600_smooth
    character(len=1)  :: already_computed_domain_wide_rh
    logical(1)        :: valid_pt(imax,jmax), readgenflag(nreadgenparms)

    if (allocated(mean_rh)) deallocate (mean_rh)
    allocate (mean_rh(imax,jmax), stat = imrhf)
    if (imrhf /= 0) then
      print *, ' '
      print *, '!!! ERROR in get_rh_at_center allocating mean_rh'
      print *, '!!! array, imrhf = ', imrhf
      stop 93
      return
    endif

    ! call compute_rh_from_q to get the RH for each of the vertical layers
    if (verb >= 1) then
      print *, 'rq1, need_to_compute_rh_from_q = ',       need_to_compute_rh_from_q
      print *, '     already_computed_domain_wide_rh = ', already_computed_domain_wide_rh
    endif

    if (need_to_compute_rh_from_q == 'y' .and. already_computed_domain_wide_rh == 'n') then
      do ip = 2, 8
        ! start at 2 because the first RH variable is the 2nd variable in the list
        call compute_rh_from_q (ist, ifh, imax, jmax, dx, dy, ip, valid_pt, maxstorm, trkrinfo, readgenflag, ichrret)
      enddo
      already_computed_domain_wide_rh = 'y'
    endif

    ! call calc_multi_layer_mean for 1000-925 to get the mean RH in that layer
    mean_rh = 0.0
    icmlret = 0
    call calc_multi_layer_mean (xcenlon, xcenlat, ist, ifh, imax, jmax, 'rh', '1000-925', dx, dy, &
         & valid_pt, maxstorm, trkrinfo, mean_rh, icmlret)

    if (icmlret == 0) then
      igsvret = 0
      call get_smooth_value_at_pt (xcenlon, xcenlat, ist, ifh, imax, jmax, mean_rh(1,1), 'mean_rh1', &
           & dx, dy, valid_pt, maxstorm, re, ri, trkrinfo, xsmoothval, igsvret)
      if (igsvret == 0) then
        rh_1000_925_smooth = xsmoothval
      else
        rh_1000_925_smooth = -9999.0
      endif
    else
      rh_1000_925_smooth = -9999.0
    endif

    ! call calc_multi_layer_mean for 800-600 to get the mean RH in that layer
    mean_rh = 0.0
    icmlret = 0
    call calc_multi_layer_mean (xcenlon, xcenlat, ist, ifh, imax, jmax, 'rh', '800-600', dx, dy, &
         & valid_pt, maxstorm, trkrinfo, mean_rh, icmlret)

    if (icmlret == 0) then
      igsvret = 0
      call get_smooth_value_at_pt (xcenlon, xcenlat, ist, ifh, imax, jmax, mean_rh(1,1), 'mean_rh8', &
           & dx, dy, valid_pt, maxstorm, re, ri, trkrinfo, xsmoothval, igsvret)
      if (igsvret == 0) then
        rh_800_600_smooth = xsmoothval
      else
        rh_800_600_smooth = -9999.0
      endif
    else
      rh_800_600_smooth = -9999.0
    endif

    return

  end subroutine get_rh_at_center

  !****************************************************************************
  !*
  !*  ABSTRACT: This routine computes relative humidity across a full
  !*      model domain, using T and q.  This will only be called, obviously,
  !*      if RH was not available to be read in for this model.  For
  !*      computing saturation vapor pressure (qs), I'm using Tetens
  !*      formula, because it includes the variation of latent heat with
  !*      temperature and because it is what HWRF uses.  The form of
  !*      Tetens formula I'm using is from the 2nd edition of the Ronald
  !*      Stull book, Meterology for Scientists and Engineers, p. 98.
  !*
  !*  INPUT:
  !*      ist         :: Storm number currently being processed
  !*      ifh         :: Forecast hour currently being processed
  !*      imax        :: Max number of pts in x-direction for this grid
  !*      jmax        :: Max number of pts in y-direction for this grid
  !*      dx          :: grid-spacing of the model in the i-direction
  !*      dy          :: grid-spacing of the model in the j-direction
  !*      ip          :: integer index for the vertical level for RH
  !*      valid_pt    :: Logical; bitmap indicating if valid data at that pt.
  !*      maxstorm    :: Max # of storms that can be handled in this run
  !*      trkrinfo    :: derived type detailing user-specified grid info
  !*      readgenflag :: logical array, indicates if a genesis parm was read in
  !*
  !*  OUTPUT:
  !*      ichrret     :: integer return code from this routine
  !*
  !****************************************************************************
  subroutine compute_rh_from_q (ist, ifh, imax, jmax, dx, dy, ip, valid_pt, maxstorm, &
                               & trkrinfo, readgenflag, ichrret)

    use def_vitals; use grid_bounds; use trig_vals; use tracked_parms; use read_parms; use trkrparms

    implicit none

    type (trackstuff) :: trkrinfo
    real, parameter   :: rd_over_rv = 0.622
    real, parameter   :: l_over_rv_water = 5423.0
    real, parameter   :: l_over_rv_ice = 6139.0
    real, parameter   :: one_over_tnot = 0.003663  ! (1/273)
    real, parameter   :: eo = 0.611
    real, parameter   :: b = 17.2694
    real, parameter   :: t1 = 273.16
    real, parameter   :: t2 = 35.86
    integer           :: ist, ifh, imax, jmax, maxstorm, ichrret, ip, qix, tix, i, j
    integer           :: z, x999ct, rhgt100ct
    real              :: dx, dy, penv, es, qs, xminrh, xmaxrh
    logical(1)        :: valid_pt(imax,jmax), readgenflag(nreadgenparms)

    select case (ip)
      case (2); z = 1; qix = 9;  tix = 16; penv = 100.0;
      case (3); z = 2; qix = 10; tix = 17; penv = 92.5;
      case (4); z = 3; qix = 11; tix = 18; penv = 80.0;
      case (5); z = 4; qix = 12; tix = 19; penv = 75.0;
      case (6); z = 5; qix = 13; tix = 20; penv = 70.0;
      case (7); z = 6; qix = 14; tix = 21; penv = 65.0;
      case (8); z = 7; qix = 15; tix = 22; penv = 60.0;
      case default

      print *, ' '
      print *, 'ERROR in subroutine  compute_rh_from_q.  The index'
      print *, '  ip that indicates the vertical level needs to be'
      print *, '  in the range of 2-8 is out of range. Here, ip = ', ip
      stop 95
    end select

    print *, ' '
    print *, 'top of compute_rh_from_q, z = ', z
    print *, '  qix = ', qix, '  readgenflag(qix) = ', readgenflag(qix)
    print *, '  tix = ', tix, '  readgenflag(tix) = ', readgenflag(tix)

    if (readgenflag(qix) .and. readgenflag(tix)) then
      rhgt100ct = 0

      do j = 1, jmax  ! jloop
        do i = 1, imax  ! iloop

          if (valid_pt(i,j)) then
            ! Teten's formula:
            es = eo * exp((b * (temperature(i, j, z) - t1)) / (temperature(i, j, z) - t2))
            qs = (rd_over_rv * es) / penv
            rh(i, j, z) = (spfh(i, j, z) / qs) * 100.0
            if (rh(i,j,z) > 100.0) then
              rhgt100ct   = rhgt100ct + 1
              rh(i, j, z) = 100.0
            endif
          endif

        enddo ! iloop
      enddo  ! jloop

      xmaxrh = -999999.0
      xminrh =  999999.0
      x999ct = 0

      do j = 1, jmax ! jloop2
        do i = 1, imax ! iloop2

          if (rh(i,j,z) < xminrh) then
            xminrh = rh(i, j, z)
          endif

          if (rh(i,j,z) > xmaxrh) then
            xmaxrh = rh(i, j, z)
          endif

          if (rh(i,j,z) < 0.0) then
            x999ct = x999ct + 1
          endif

        enddo ! iloop2
      enddo ! jloop2

      print *, ' '
      print *, 'xxrhstat: xminval = ', xminrh, ' xmaxval = ',    xmaxrh
      print *, 'x999ct = ',            x999ct, ' rhgt100ct = ', rhgt100ct
    endif

    return

  end subroutine compute_rh_from_q

  !****************************************************************************
  !*
  !*  ABSTRACT: This routine computes a multi-layer mean of an input variable.
  !*
  !*  INPUT:
  !*      xcenlon   :: real value of center position at which to compute average
  !*      xcenlat   :: real value of center position at which to compute average
  !*      ist       :: Storm number currently being processed
  !*      ifh       :: Forecast hour currently being processed
  !*      imax      :: Max number of pts in x-direction for this grid
  !*      jmax      :: Max number of pts in y-direction for this grid
  !*      cvar      :: character string that contains variable being searched
  !*      clevstr   :: character string that indicates vertical levels being
  !*                   included in the vertical layer mean
  !*      dx        :: grid-spacing of the model in the i-direction
  !*      dy        :: grid-spacing of the model in the j-direction
  !*      valid_pt  :: Logical; bitmap indicating if valid data at that pt.
  !*      maxstorm  :: Max # of storms that can be handled in this run
  !*      trkrinfo  :: derived type detailing user-specified grid info
  !*
  !*  OUTPUT:
  !*      xmean_arr :: real array containing mean field
  !*      icmlret   :: integer return code from this routine
  !*
  !****************************************************************************
  subroutine calc_multi_layer_mean (xcenlon, xcenlat, ist, ifh, imax, jmax, cvar, clevstr, dx, dy, &
                                   & valid_pt, maxstorm, trkrinfo, xmean_arr, icmlret)

    use def_vitals; use grid_bounds; use trig_vals; use tracked_parms; use trkrparms

    implicit none

    type (trackstuff)    :: trkrinfo
    
    integer, allocatable :: point_ct(:,:)
    integer              :: ist, ifh, imax, jmax, maxstorm, igsvret, npts, bskip, icut
    integer              :: ilonfix, jlatfix, ibeg, jbeg, iend, jend, igiret, icutmax
    integer              :: icount, ibret, z, zstart, zend, ipc, icmlret, i, j
    real                 :: xmean_arr(imax,jmax)
    real                 :: re, ri, xsmoothval, xcenlon, xcenlat, dx, dy, reold, riold
    real                 :: xmaxrh, xminrh
    logical(1)           :: valid_pt(imax,jmax)
    character(len=1)     :: in_grid
    character(len=*)     :: clevstr, cvar

    if (allocated(point_ct)) deallocate(point_ct)
    allocate (point_ct(imax, jmax), stat = ipc)
    if (ipc /= 0) then
      print *, ' '
      print *, '!!! ERROR in calc_multi_layer_mean allocating'
      print *, '!!! point_ct array, ipc = ', ipc
      print *, '!!! STOPPING EXECUTION'
      STOP 91
    endif

    if (cvar == 'rh' .and. clevstr == '1000-925') then
      zstart = 1
      zend   = 2
    else if (cvar == 'rh' .and. clevstr == '800-600') then
      zstart = 3
      zend   = 7
    endif

    point_ct = 0

    do z = zstart, zend ! zloop
      do j = 1, jmax ! jloop
        do i = 1, imax ! iloop

          if (valid_pt(i,j) .and. rh(i,j,z) > -998.0) then
            xmean_arr(i, j) = xmean_arr(i, j) + rh(i, j, z)
            point_ct(i, j)  = point_ct(i, j) + 1
          endif

        enddo ! iloop
      enddo ! jloop
    enddo ! zloop

    xminrh = 999999.0
    xmaxrh = -999999.0

    do j = 1, jmax ! jloop2
      do i = 1, imax ! iloop2

        if (point_ct(i,j) > 0) then
          xmean_arr(i, j) = xmean_arr(i, j) / real(point_ct(i, j))
          if (xmean_arr(i,j) > xmaxrh) then
            xmaxrh = xmean_arr(i, j)
          endif
          if (xmean_arr(i,j) < xminrh) then
            xminrh = xmean_arr(i, j)
          endif
        else
          xmean_arr(i, j) = -9999.0
        endif

      enddo ! iloop2
    enddo ! jloop2

    print *, ' '
    print *, 'xxmeanstat: lev = ', clevstr, ' xmaxrh = ', xmaxrh, ' xminrh = ', xminrh

    deallocate (point_ct)

    return

  end subroutine calc_multi_layer_mean

  !****************************************************************************
  !*
  !*  ABSTRACT: This routine calculates the  thicknesses for three
  !*      different layers: 200-500, 500-850 and 200-850 mb.
  !*
  !*  The array indices for the 3 different thickness layers are
  !*      as follows:
  !*      1: 500-850
  !*      2: 200-500
  !*      3: 200-850
  !*
  !*  The array indices for the levels for the 4 different GP height
  !*      arrays (as assigned in subroutine  getdata) are as follows:
  !*      1: 850 mb
  !*      2: 700 mb
  !*      3: 500 mb
  !*      4: 200 mb
  !*
  !****************************************************************************
  subroutine thickness_calc (imax, jmax, vp)

    use tracked_parms; use verbose_output

    implicit none

    integer    :: i, j, layer, upper, lower, imax, jmax
    logical(1) :: vp(imax,jmax)

    do layer = 1, 3
      select case (layer)
        case (1); upper = 3; lower = 1;
        case (2); upper = 4; lower = 3;
        case (3); upper = 4; lower = 1;
      end select

      do j = 1, jmax
        do i = 1, imax
          if (vp(i,j)) then
            thick(i, j, layer) = hgt(i, j, upper) - hgt(i, j, lower)
          else
            thick(i, j, layer) = -999.0
          endif
        enddo
      enddo
    enddo

    return

  end subroutine thickness_calc

  !****************************************************************************
  !*
  !*  ABSTRACT: This subroutine scans an array and picks out areas of
  !*      max or min, then loads those center positions into the first-
  !*      guess lat & lon arrays to be used by subroutine  tracker for
  !*      locating the very specific low center positions.
  !*
  !*  INPUT:
  !*      imax         :: Number of gridpoints in i direction in input grid
  !*      jmax         :: Number of gridpoints in j direction in input grid
  !*      dx           :: Grid spacing in i-direction for the input grid
  !*      dy           :: Grid spacing in j-direction for the input grid
  !*      cparm        :: Char string indicating what parm is being passed in
  !*      fxy          :: Real array of data values
  !*      finf         :: Logical. Field of influence.  Dimension same as fxy
  !*      cmaxmin      :: Char string to indicate if search is for a max or a min
  !*      trkrinfo     :: Derived type that holds/describes various tracker parms,
  !*                      including the contour interval to be used
  !*      ifh          :: Index for the forecast hour
  !*      valid_pt     :: Logical bitmap masking non-valid grid points.  This is a
  !*                      concern for the regional models, which are interpolated
  !*                      from Lam-Conf or NPS grids onto lat/lon grids, leaving
  !*                      grid points around the edges which have no valid data.
  !*      maxstorm     :: max # of storms that can be handled in this run
  !*      gm_wrap_flag :: character flag set in getgridinfo that determines
  !*                      which GM-wrapping setting to use.
  !*
  !*  INPUT/OUTPUT:
  !*      masked_out   :: Logical. T = data point is already accounted for, under
  !*                      the influence of another nearby max or min center,
  !*                      F = data point is available to be scanned by this
  !*                      subroutine for max or min centers.
  !*      stormct      :: Integer: keeps and increments a running tab of the number
  !*                      of storms that have been tracked at any time across all
  !*                      forecast hours
  !*      contour_info :: Type cint_stuff from module contours.  Contains
  !*                      contour information
  !*
  !*  OUTPUT:
  !*      maxmini      :: Integer array containing i-indeces of max/min locations
  !*      maxminj      :: Integer array containing j-indeces of max/min locations
  !*      ifgcret      :: return code from this subroutine
  !*
  !*  OTHER:
  !*      storm        :: Contains the tcvitals for the storms (module def_vitals)
  !*
  !****************************************************************************
  subroutine first_ges_center (imax, jmax, dx, dy, cparm, fxy, cmaxmin, trkrinfo, ifh, valid_pt, maxstorm, &
                              & masked_out, stormct, contour_info, maxmini, maxminj, gm_wrap_flag, ifgcret)

    use trkrparms; use grid_bounds;   use set_max_parms; use def_vitals
    use contours;  use tracked_parms; use verbose_output

    implicit none

    type (trackstuff) :: trkrinfo
    type (cint_stuff) :: contour_info

    integer          :: i, j, n, isstart, ifamret, ibeg, jbeg, iend, jend
    integer          :: ifh, maxstorm, imax, jmax, itemp, ifgcret
    integer          :: stormct,oldstormct,mm
    logical(1)       :: valid_pt(imax,jmax), masked_out(imax,jmax)
    character(len=*) :: cparm, cmaxmin
    character(len=*) :: gm_wrap_flag
    integer          :: maxmini(maxstorm), maxminj(maxstorm)
    integer(kind=8)  :: ssct1, yyct1, yyct2, zzct1, zzct2, zzct3
    integer(kind=8)  :: ict, iinvct
    real             :: fxy(imax,jmax)
    real             :: dmax, dmin, dx, dy, dbuffer, tmp
    real(kind=8)     :: xsum, xavg, stdx

    if (verb .ge. 3) then
      print *, ' '
      print *, '*-------------------------------------------------*'
      print *, '* At top of first_ges_center                      *'
      write (6,102) ifhours(ifh), ifclockmins(ifh)
102   format (1x, '* Searching for new lows at hour ', i4, ':', i2.2)
      print *, '*-------------------------------------------------*'
    endif

    if (trkrinfo%northbd < -998.0 .or. trkrinfo%southbd < -998.0 .or. trkrinfo%westbd < -998.0  &
       .or. trkrinfo%eastbd < -998.0) then
      ! user did not specify a subgrid, so scan the whole domain
      ibeg = 1
      iend = imax
      jbeg = 1
      jend = jmax
      print *, 'FGC  IF A'
    else
      if (trkrinfo%westbd > 360.0 .or. trkrinfo%northbd > 90.0 .or.             &
          trkrinfo%northbd <-90.0 .or. trkrinfo%southbd > 90.0 .or.             &
          trkrinfo%southbd <-90.0 .or. trkrinfo%westbd  >= trkrinfo%eastbd .or. &
          trkrinfo%southbd >= trkrinfo%northbd) then
        
        print *, 'FGC  ELSE IF B'
        if (trkrinfo%westbd  > trkrinfo%eastbd) then
          print *, 'FGC  ELSE IF IF C'
          if (trkrinfo%westbd < 360.0 .and. trkrinfo%eastbd >= 0.0)then
            print *, 'FGC  ELSE IF IF IF D'

            if (verb .ge. 3) then
              print *, ' '
              print *, '++ NOTE: The user supplied grid lon boundaries'
              print *, '++       span across the Greenwich meridian.'
              print *, '++    '
              print *, '++        Western boundary: ',  trkrinfo%westbd
              print *, '++        Eastern boundary: ',  trkrinfo%eastbd
              print *, '++        Northern boundary: ', trkrinfo%northbd
              print *, '++        Southern boundary: ', trkrinfo%southbd
              print *, ' '
            endif

            jbeg = int(((glatmax + dy - trkrinfo%northbd) / dy) + 0.5)
            jend = int(((glatmax + dy - trkrinfo%southbd) / dy) + 0.5)
            ibeg = int(((trkrinfo%westbd - glonmin + dx)  / dx) + 0.5)
            iend = int(((trkrinfo%eastbd - glonmin + dx)  / dx) + 0.5) + imax

            print *, 'FGC  ELSE IF IF IF AFTER IBEG E'
            goto 377
          endif
        endif

        if (verb .ge. 1) then
          print *, ' '
          print *, '!!! ERROR: Error in first_ges_center.  There is a'
          print *, '!!!        problem with the user-supplied grid '
          print *, '!!!        boundaries.  Please check them and '
          print *, '!!!        resubmit the program.'
          print *, '!!!'
          print *, '!!!        Western boundary: ',  trkrinfo%westbd
          print *, '!!!        Eastern boundary: ',  trkrinfo%eastbd
          print *, '!!!        Northern boundary: ', trkrinfo%northbd
          print *, '!!!        Southern boundary: ', trkrinfo%southbd
          print *, ' '
        endif

        ifgcret = 91
        return
 377    continue

      else
        ! calculate the beginning and ending i and j points
        print *, 'FGC  REGULAR ELSE AA'
        jbeg = int(((glatmax + dy - trkrinfo%northbd) / dy) + 0.5)
        jend = int(((glatmax + dy - trkrinfo%southbd) / dy) + 0.5)
        ibeg = int(((trkrinfo%westbd - glonmin + dx)  / dx) + 0.5)
        iend = int(((trkrinfo%eastbd - glonmin + dx)  / dx) + 0.5)
      endif
    endif

    print *, ' '
    print *, 'fgc first_ges_center, ibeg = ', ibeg, '  iend = ',    iend
    print *, 'fgc first_ges_center, jbeg = ', jbeg, '  jend = ',    jend
    print *, 'fgc glatmax          = ', glatmax,              '  glonmin = ', glonmin
    print *, 'fgc dx = ', dx, ' dy = ', dy
    print *, 'fgc trkrinfo%northbd = ', trkrinfo%northbd
    print *, 'fgc trkrinfo%southbd = ', trkrinfo%southbd
    print *, 'fgc trkrinfo%westbd  = ', trkrinfo%westbd
    print *, 'fgc trkrinfo%eastbd  = ', trkrinfo%eastbd

    if (trkrinfo%contint <= 0) then
      if (verb .ge. 1) then
        print *, ' '
        print *, '!!! ERROR: Error in first_ges_center.  For a midlat'
        print *, '!!!        or tcgen run of the  tracker, the contour'
        print *, '!!!        interval supplied by the user is not '
        print *, '!!!        greater than 0.'
        print *, '!!! '
        print *, '!!! User-supplied contint = ', trkrinfo%contint
        print *, ' '
      endif

      ifgcret = 91
      return
    endif

    ! get the mean value in the domain
    dmin   =  9.99E08
    dmax   = -9.99E08
    ict    = 0
    xsum   = 0.0
    iinvct = 0

    do j = jbeg, jend
      do i = ibeg, iend
        if (i > imax) then
          itemp = i - imax   ! if wrapping past GM
        else
          itemp = i
        endif
        if (valid_pt(itemp,j)) then
          xsum = xsum + fxy(itemp, j)
          ict = ict + 1
          if (fxy(itemp,j) < dmin) dmin = fxy(itemp,j)
          if (fxy(itemp,j) > dmax) dmax = fxy(itemp,j)
          if (fxy(itemp,j) > 1040.0) then
            print *, 'PRESSERR: itemp = ', itemp, ' j = ', j, ' fxy(itemp,j) = ', fxy(itemp,j)
          endif
        else
          iinvct = iinvct + 1
        endif
      enddo
    enddo

    if (ict > 0) then
      xavg = xsum / real(ict)
    else
      if (verb .ge. 1) then
        print *, ' '
        print *, '!!! ERROR computing average value;  ict NOT > 0 in'
        print *, '!!! first_ges_center while looking for new storms.'
        print *, '!!! STOPPING....'
      endif
      xavg = -999.0
      stop 95
    endif

    print *, 'ict from mean (xavg) calculation  = ',  ict
    print *, 'xsum from mean (xavg) calculation = ', xsum
    print *, 'xavg from mean (xavg) calculation = ', xavg

    ! get the standard deviation in the domain
    stdx = 0.0
    ict  = 0

    do j = jbeg, jend
      do i = ibeg, iend
        if (i > imax) then
          itemp = i - imax   ! if wrapping past GM
        else
          itemp = i
        endif
        if (valid_pt(itemp,j)) then
          stdx = stdx + (fxy(itemp, j) - xavg)**2
          ict = ict + 1
        endif
      enddo
    enddo

    if (ict > 0) then
      stdx = sqrt(stdx / real(ict))
      if (stdx == 0.0) then
        stdx = 1.0
      endif
    else
      if (verb .ge. 1) then
        print *, ' '
        print *, '!!! ERROR computing standard dev.;  ict NOT > 0 in'
        print *, '!!! first_ges_center while looking for new storms.'
        print *, '!!! STOPPING....'
      endif
      stop 95
    endif

    if (verb .ge. 3) then
      print *, ' '
      print *, '*--------------------------------------------*'
      print *, 'In first_ges_center,      dmin = ', dmin, ' dmax = ', dmax
      print *, 'Mean value =              xavg = ', xavg, '  ict = ', ict
      print *, '       ict = ', ict, '  iinvct = ', iinvct
      print *, 'Standard deviation =      stdx = ', stdx
    endif

    print *, 'ict from std deviation (stdx) calculation = ', ict

    dbuffer = (dmax - dmin) / 2.0
    dmax    = dmax + dbuffer
    dmin    = dmin - dbuffer

    if (verb .ge. 3) then
      print *, 'after adjustment, dmin = ', dmin, ' dmax = ', dmax
    endif

    tmp = trkrinfo%contint
    contour_info%xmaxcont = dmax - mod(dmax, tmp)
    contour_info%xmincont = dmin - mod(dmin, tmp)

    if (verb .ge. 3) then
      print *, 'A1 contour_info%xmaxcont = ', contour_info%xmaxcont
      print *, 'A1 contour_info%xmincont = ', contour_info%xmincont
    endif

    if (contour_info%xmincont > contour_info%xmaxcont) then
      contour_info%xmincont = contour_info%xmaxcont
    endif

    if (verb .ge. 3) then
      print *, 'A2 contour_info%xmaxcont = ', contour_info%xmaxcont
      print *, 'A2 contour_info%xmincont = ', contour_info%xmincont
      print *, '                maxconts = ', maxconts
    endif

    contour_info%numcont = 0
    do n = 1, maxconts
      contour_info%numcont     = contour_info%numcont + 1
      contour_info%contvals(n) = contour_info%xmincont + real(n - 1) * trkrinfo%contint
      if (contour_info%contvals(n) >= dmax) exit
    enddo

    ssct1 = 0
    yyct1 = 0
    yyct2 = 0
    zzct1 = 0
    zzct2 = 0
    zzct3 = 0

    oldstormct = stormct
    call find_all_maxmins (imax, jmax, ibeg, iend, jbeg, jend, fxy, valid_pt, masked_out, contour_info, dx, dy  &
         & trkrinfo, cmaxmin, maxstorm, stormct, maxmini, maxminj, ifh, xavg, stdx, ssct1, yyct1, yyct2, zzct1, &
         & zzct2, zzct3, gm_wrap_flag, ifamret)

    print *, ' '
    print *, 'Summary counter stats for find_all_maxmins at ifh = ', ifh
    print *, '   ssct1 = ', ssct1
    print *, '   yyct1 = ', yyct1
    print *, '   yyct2 = ', yyct2
    print *, '   zzct1 = ', zzct1
    print *,'    zzct2 = ', zzct2
    print *, '   zzct3 = ', zzct3
    print *, ' stormct = ', stormct

    if (stormct > 0) then
      continue
    else
      if (verb .ge. 3) then
        print *, ' '
        print *, ' '
        print *, '!!! ************************************************'
        print *, '!!! '
        print *, '!!! NOTE: In first_ges_center, the value of stormct'
        print *, '!!! returned from find_all_maxmins is not greater'
        print *, '!!! than 0.  This means there are no new centers'
        print *, '!!! to track, which is not likely.  Perhaps you are'
        print *, '!!! searching over too small of an area??'
        print *, '!!! '
        print *, '!!! ************************************************'
        print *, ' '
      endif
    endif

    print *, 'ifh = ', ifh, ' oldstormct = ', oldstormct
    print *, '                stormct    = ', stormct

    do mm = 1, 300
      print *, 'mm = ', mm, ' maxmini(mm) = ', maxmini(mm), ' maxminj(mm) = ', maxminj(mm)
    enddo

    if (stormct > oldstormct .and. stormct > 0) then
      isstart = oldstormct + 1

      if (verb .ge. 3) then
        write (6,*) ' '
        write (6,*) 'New search: '
        write (6,*) 'Possible new max/min locations at ifh = ', ifh
        write (6,*) '--------------------------------------------'
      endif

      do n = isstart, stormct
        if (trkrinfo%type == 'midlat') then
          storm(n)%tcv_center = 'MIDL'
        else if (trkrinfo%type == 'tcgen') then
          storm(n)%tcv_center = 'TCG '
        endif
        slonfg(n, ifh) = glonmin + (maxmini(n) - 1) * dx
        slatfg(n, ifh) = glatmax - (maxminj(n) - 1) * dy
        storm(n)%tcv_stspd = -99
        storm(n)%tcv_stdir = -99
        write (storm(n)%tcv_storm_id,'(i4.4)') n
        write (storm(n)%tcv_storm_name,'(i4.4)') n
        stormswitch(n) = 1
        if (cparm == 'mslp') then

          if (verb .ge. 3) then
            if (slp(maxmini(n),maxminj(n)) > 50000.0) then
              ! pressure units are in Pa
              write (6,71) maxmini(n), maxminj(n), slonfg(n,ifh), 360.0-slonfg(n,ifh), slatfg(n,ifh), &
                           slp(maxmini(n), maxminj(n)) / 100.0
            else
              ! pressure units are in mb
              write (6,71) maxmini(n), maxminj(n), slonfg(n,ifh), 360.0-slonfg(n,ifh), slatfg(n,ifh), &
                           slp(maxmini(n), maxminj(n))
            endif
          endif
        endif
      enddo
      
    else
      if (verb .ge. 3) then
        print *, ' '
        print *, ' New search: '
        print *, '!!! NOTE: No new storms found in find_all_maxmins'
        print *, '!!! at ifh = ',    ifh, '  stormct = ', stormct
        print *, '!!! oldstormct= ', oldstormct
        print *, ' '
      endif
    endif

71  format (1x, 'i = ', i4, '  j = ', i4, '   lon: ', f7.2, 'E  (', f6.2, 'W)', 2x, ' lat: ', &
            f6.2, '    mslp: ', f8.3, ' mb')

    return

  end subroutine first_ges_center

  !****************************************************************************
  !*
  !*  ABSTRACT: This subroutine will search an area delineated by
  !*      input i and j indeces in order to find all local maxes or mins
  !*      in that area.  The (i,j) locations of the maxes/mins are returned
  !*      in the maxmini and maxminj arrays.  The input 3-character string
  !*      cmaxmin will tell the subroutine to look for a "max" or a "min".
  !*
  !*  INPUT:
  !*      imax         :: Number of gridpoints in i direction in input grid
  !*      jmax         :: Number of gridpoints in j direction in input grid
  !*      ibeg         :: i-index for upper left location of grid to search
  !*      iend         :: i-index for lower right location of grid to search
  !*      jbeg         :: j-index for upper left location of grid to search
  !*      jend         :: j-index for lower right location of grid to search
  !*      fxy          :: Real array of data values
  !*      valid_pt     :: Logical bitmap masking non-valid grid points.  This is a
  !*                      concern for the regional models, which are interpolated
  !*                      from Lam-Conf or NPS grids onto lat/lon grids, leaving
  !*                      grid points around the edges which have no valid data.
  !*      masked_out   :: Logical. T = data point is already accounted for, under
  !*                      the influence of another nearby max or min center,
  !*                      F = data point is available to be scanned by this
  !*                      subroutine for max or min centers.
  !*      contour_info :: Type cint_stuff from module contours containing the
  !*                      the following 4 variables:
  !*                      1. xmincont Real value for min contour level in the fxy data array
  !*                      2. xmaxcont Real value for max contour level in the fxy data array
  !*                      3. contvals Real array holding values of cont levels at this time
  !*                      4. numcont  Number of contour intervals found at this time
  !*      dx           :: Grid spacing in x-direction
  !*      dy           :: Grid spacing in y-direction
  !*      trkrinfo     :: derived type containing various user-input tracker parms
  !*      cmaxmin      :: String that declares if "min" or "max" is being searched
  !*      maxstorm     :: max # of storms that can be handled in this run
  !*      ifh          :: Integer index for forecast hour array
  !*      xavg         :: The mean value of the variable (likely MSLP) that is
  !*                      being searched.  Value computed on the domain specified
  !*                      by ibeg,iend,jbeg,jend.
  !*      stdv         :: Standard deviation of the variable (likely MSLP) that is
  !*                      being searched.  Value computed on the domain specified
  !*                      by ibeg,iend,jbeg,jend.
  !*      gm_wrap_flag :: character flag set in getgridinfo that determines
  !*                      which GM-wrapping setting to use.
  !*
  !*  INPUT/OUTPUT:
  !*      stormct      :: Integer: keeps and increments a running tab of the number
  !*                      of storms that have been tracked at any time across all
  !*                      forecast hours
  !*
  !*  OUTPUT:
  !*      maxmini      :: integer array containing i-indeces of the max/min points
  !*      maxminj      :: integer array containing j-indeces of the max/min points
  !*      ifamret      :: return code from this subroutine
  !*
  !****************************************************************************
  subroutine find_all_maxmins (imax, jmax, ibeg, iend, jbeg, jend, fxy, valid_pt, masked_out, contour_info,      &
                              & dx, dy, trkrinfo, cmaxmin, maxstorm, stormct, maxmini, maxminj, ifh, xavg, stdv, &
                              & ssct1, yyct1, yyct2, zzct1, zzct2, zzct3, gm_wrap_flag, ifamret)

    use trkrparms;   use set_max_parms; use contours;      use verbose_output; use radii
    use grid_bounds; use tracked_parms; use genesis_diags; use trig_vals;      use atcf

    implicit none

    type (trackstuff) :: trkrinfo
    type (cint_stuff) :: contour_info
    
    integer                 :: date_time(8)
    integer                 :: stormct, i, j, ibeg, iend, jbeg, jend, ix, jx, ixp1, ixm1
    integer                 :: igiret, bskip, ibeg_sm, iend_sm, jbeg_sm, jend_sm
    integer                 :: ip, jp, maxstorm, jxp1, jxm1, ifamret, isret, iaret, iclmret
    integer                 :: isoiret, icccret, igicwret, imax, jmax, ifh, totpts, kct
    integer                 :: eligible_pts, isia, ipa, candidate_ct, ist, ict, iia, ija, imsa
    integer                 :: icmrgret, cand_not_valid_ct, cand_masked_out_ct, ivsa
    integer                 :: cand_cc_good_ct, cand_cc_bad_ct, iccwcret, icvpret, isla
    integer                 :: ilonfix, jlatfix, icount, npts, nhalf, igsvret, ibret, isaa
    integer                 :: compute_ct, num_smooth_iter, k, maxip, maxjp, cmrg_fail_ct
    integer                 :: int_vtq_ne, int_vtq_se, int_vtq_sw, int_vtq_nw
    integer(kind=8)         :: ssct1, yyct1, yyct2, zzct1, zzct2, zzct3
    character(len=10)       :: big_ben(3)
    character(len=1)        :: ccflag, get_last_isobar_flag, point_is_over_water
    character(len=1)        :: pass_checks, low_level_wind_circ_flag, try_low_level_circ
    character(len=3)        :: maxmin, cvar
    character(len=*)        :: cmaxmin
    character(len=*)        :: gm_wrap_flag
    logical(1)              :: still_finding_valid_maxmins, rough_gradient_check_okay
    logical(1)              :: valid_pt(imax,jmax), masked_out(imax,jmax)
    logical(1)              :: pt_eligible(imax,jmax)
    logical(1), allocatable :: slp_valid_pt(:,:), valid_smoothe(:,:)
    integer                 :: maxmini(maxstorm), maxminj(maxstorm)
    integer, allocatable    :: sortindex(:), ipos(:), jpos(:)
    integer, parameter      :: dp = selected_real_kind(12, 60)
    real(dp), allocatable   :: prstemp(:)
    real, allocatable       :: mslp_smoothe(:,:), slp_array(:,:)
    real, intent(in)        :: fxy(imax,jmax)
    real                    :: realmask(imax,jmax)
    real                    :: vtquadmax(4)
    real                    :: search_cutoff, dmin, dmax, sphere_cutoff
    real                    :: plastbar, rlastbar, fract_land, dx, dy
    real                    :: xmlat, xmlon, ylat, xlon, xsmoothval
    real                    :: wgt1, wgt3, wgt5, wgt7, wgt9, sdiff, maxmslpsmooth
    real(kind=8)            :: xavg, stdv

    still_finding_valid_maxmins = .true.

    if (allocated(sortindex))     deallocate (sortindex,    stat = isia)
    if (allocated(prstemp))       deallocate (prstemp,      stat = ipa)
    if (allocated(ipos))          deallocate (ipos,         stat = iia)
    if (allocated(jpos))          deallocate (jpos,         stat = ija)
    if (allocated(slp_array))     deallocate (slp_array,    stat = isaa)
    if (allocated(slp_valid_pt))  deallocate (slp_valid_pt, stat = isla)

    if (isia /= 0 .or. ipa /= 0 .or. iia /= 0 .or. ija /= 0 .or. isaa /= 0 .or. isla /= 0) then
      print *, ' '
      print *, '!!! ERROR in find_all_maxmins deallocating arrays'
      print *, '!!! at beginning of subroutine.'
      print *, '!!! isia = ',  isia,' ipa = ', ipa, ' isla = ', isla
      print *, '!!! iia  =  ', iia,'  ija = ', ija, ' isaa = ', isaa
      print *, '!!! EXITING at FAM-A....'
      stop 98
    endif

    allocate (prstemp(maxstorm),        stat = isia)
    allocate (sortindex(maxstorm),      stat = ipa)
    allocate (ipos(maxstorm),           stat = iia)
    allocate (jpos(maxstorm),           stat = ija)
    allocate (slp_array(imax, jmax),    stat = isaa)
    allocate (slp_valid_pt(imax, jmax), stat = isla)

    if (isia /= 0 .or. ipa /= 0 .or. iia /= 0 .or. ija /= 0 .or. isaa /= 0 .or. isla /= 0) then
      print *, ' '
      print *, '!!! ERROR in find_all_maxmins allocating arrays'
      print *, '!!! at beginning of subroutine.'
      print *, '!!! isia = ', isia, ' ipa = ', ipa, ' isla = ', isla
      print *, '!!! iia =  ', iia, '  ija = ', ija, ' isaa = ', isaa
      print *, '!!! EXITING at FAM-B....'
      stop 98
    endif

    cand_cc_good_ct = 0
    prstemp = 999999.0

    print *, 'ctm beg of find_all_maxmins, maxstorm = ', maxstorm
    print *, 'ctm beg of find_all_maxmins,     ibeg = ', ibeg, ' iend = ', iend
    print *, 'ctm beg of find_all_maxmins,     jbeg = ', jbeg, ' jend = ', jend

    if (verb .ge. 1) then
      print *, ' '
      print *, '+++ In find_all_maxmins, the mean and standard'
      print *, '+++ deviation info for the searched variable'
      print *, '+++ (typically MSLP) follow: '
      print *, '    Mean value         = xavg = ', xavg
      print *, '    Standard deviation = stdv = ', stdv
      print *, ' '
    endif

    if (cmaxmin == 'min') then
      search_cutoff = xavg + stdv
    else
      search_cutoff = xavg - stdv
    endif

    if (verb .ge. 3) then
      print *, ' '
      print *, 'In find_all_maxmins, search_cutoff = ', search_cutoff
      print *, ' '
    endif

    pt_eligible  = .false.
    totpts       = 0
    eligible_pts = 0

    do j = jbeg, jend  ! jloop_e
      do i = ibeg, iend  ! iloop_e
        ip = i
        jp = j

        if (ip > imax) then
          if (trkrinfo%gridtype == 'global') then
            ip = i - imax   ! if wrapping past GM
          else
            if (verb .ge. 3) then
              print *, ' '
              print *, '!!! WARNING: In find_all_maxmins, the '
              print *, '!!!   user-requested eastern search boundary'
              print *, '!!!   is beyond the eastern bounds of '
              print *, '!!!   this regional grid.  The search'
              print *, '!!!   will not extend to the user-requested'
              print *, '!!!   grid boundary.'
              print *, '!!!         '
              print *, '!!!   imax of regional grid    = ', imax
              print *, '!!!   User-requested eastern i = ', ip
              print *, ' '
            endif

            exit  ! iloop_e
          endif
        endif

        totpts = totpts + 1

        if (cmaxmin == 'min') then
          if (fxy(ip,jp) <= search_cutoff) then
            ssct1               = ssct1 + 1
            pt_eligible(ip, jp) = .true.
            eligible_pts        = eligible_pts + 1
          endif
        else
          if (fxy(ip,jp) >= search_cutoff) then
            ssct1               = ssct1 + 1
            pt_eligible(ip, jp) = .true.
            eligible_pts        = eligible_pts + 1
          endif
        endif

      enddo  ! iloop_e
    enddo  ! jloop_e

    if (verb .ge. 3) then
      print *, ' '
      print *, 'In find_all_maxmins, total pts = totpts       = ', totpts
      print *, '       searchable points       = eligible_pts = ', eligible_pts
    endif

    if (smoothe_mslp_for_gen_scan == 'y') then
      call date_and_time (big_ben(1), big_ben(2), big_ben(3), date_time)
      write (6,51) date_time(5), date_time(6), date_time(7)
 51   format (1x, 'TIMING: Beginning of smoothing in find_all_maxmins at: ', i2.2, ':', i2.2, ':', i2.2)

      maxmin = 'min'

      if (allocated(mslp_smoothe))  deallocate (mslp_smoothe,  stat = imsa)
      if (allocated(valid_smoothe)) deallocate (valid_smoothe, stat = ivsa)

      if (imsa /= 0 .or. ivsa /= 0) then
        print *, ' '
        print *, '!!! ERROR in find_all_maxmins deallocating'
        print *, '!!! mslp_smoothe array or valid_smoothe'
        print *, '!!! imsa = ', imsa, ' ivsa = ', ivsa
        print *, '!!! EXITING at SM-A....'
        stop 98
      endif

      allocate (mslp_smoothe(imax, jmax),  stat = imsa)
      allocate (valid_smoothe(imax, jmax), stat = ivsa)

      if (imsa /= 0 .or. ivsa /= 0) then
        print *, ' '
        print *, '!!! ERROR in find_all_maxmins allocating'
        print *, '!!! mslp_smoothe or valid_smoothe arrays.'
        print *, '!!! imsa = ', imsa, ' ivsa = ', ivsa
        print *, '!!! EXITING at SM-B....'
        stop 98
      endif

      mslp_smoothe  = fxy
      valid_smoothe = .false.

      npts   = ceiling(ri_genscan / (dtk * (dx+dy) / 2.0))
      nhalf  = 0
      cvar   = 'slp'
      icount = 0
      bskip  = 1

      wgt1 = 0.006098
      wgt3 = 0.018293
      wgt5 = 0.030488
      wgt7 = 0.042683
      wgt9 = 0.054878

      jbeg_sm = jbeg + 4
      jend_sm = jend - 4
      ibeg_sm = ibeg + 4
      iend_sm = iend - 4

      compute_ct = 0
      kct        = 0

      print *, ' '
      print *, 'before smooth_loop,    jbeg = ', jbeg, ' jend = ', jend
      print *, 'before smooth_loop,    ibeg = ', ibeg, ' iend = ', iend
      print *, 'before smooth_loop, jbeg_sm = ', jbeg_sm
      print *, 'before smooth_loop, jend_sm = ', jend_sm
      print *, 'before smooth_loop, ibeg_sm = ', ibeg_sm
      print *, 'before smooth_loop, iend_sm = ', iend_sm

      num_smooth_iter = 3

      do k = 1, num_smooth_iter ! smooth_loop
        maxmslpsmooth = -9999.0
        do j = jbeg, jend ! jloop_s
          do i = ibeg, iend ! iloop_s

            if (j < jbeg_sm .or. j > jend_sm) then
              pt_eligible(i, j)   = .false.
              valid_smoothe(i, j) = .false.
              exit !iloop_s; exit iloop to get to the next j
            endif

            if (i < ibeg_sm .or. i > iend_sm) then
              pt_eligible(i, j)   = .false.
              valid_smoothe(i, j) = .false.
              cycle ! iloop_s
            endif

            ip = i
            jp = j

            if (ip > imax) then
              if (trkrinfo%gridtype == 'global') then
                ip = i - imax   ! if wrapping past GM
              else
                if (verb .ge. 3) then
                  print *, ' '
                  print *, '!!! WARNING: In find_all_maxmins, the '
                  print *, '!!!   user-requested eastern search bound'
                  print *, '!!!   is beyond the eastern bounds of '
                  print *, '!!!   this regional grid.  The search will'
                  print *, '!!!   not extend to the user-requested'
                  print *, '!!!   grid boundary.'
                  print *, '!!!         '
                  print *, '!!!   imax of regional grid    = ', imax
                  print *, '!!!   User-requested eastern i = ', ip
                  print *, ' '
                endif
                exit  ! iloop_s
              endif
            endif

            kct = kct + 1

            if (valid_pt(ip-4,jp-4) .and. valid_pt(ip,jp-4)   .and. valid_pt(ip+4,jp-4) .and. valid_pt(ip-3,jp-3) .and. &
                valid_pt(ip,jp-3)   .and. valid_pt(ip+3,jp-3) .and. valid_pt(ip-2,jp-2) .and. valid_pt(ip,jp-2)   .and. &
                valid_pt(ip+2,jp-2) .and. valid_pt(ip-1,jp-1) .and. valid_pt(ip,jp-1)   .and. valid_pt(ip+1,jp-1) .and. &
                valid_pt(ip-4,jp)   .and. valid_pt(ip-3,jp)   .and. valid_pt(ip-2,jp)   .and. valid_pt(ip-1,jp)   .and. &
                valid_pt(ip,jp)     .and. valid_pt(ip+1,jp)   .and. valid_pt(ip+2,jp)   .and. valid_pt(ip+3,jp)   .and. &
                valid_pt(ip+4,jp)   .and. valid_pt(ip-1,jp+1) .and. valid_pt(ip,jp+1)   .and. valid_pt(ip+1,jp+1) .and. &
                valid_pt(ip-2,jp+2) .and. valid_pt(ip,jp+2)   .and. valid_pt(ip+2,jp+2) .and. valid_pt(ip-3,jp+3) .and. &
                valid_pt(ip,jp+3)   .and. valid_pt(ip+3,jp+3) .and. valid_pt(ip-4,jp+4) .and. valid_pt(ip,jp+4)   .and. &
                valid_pt(ip+4,jp+4)) then
                continue
            else
              cycle ! iloop_s
            endif

            compute_ct = compute_ct + 1

            if (k == 1) then
              mslp_smoothe(ip, jp) = (wgt1 * fxy(ip-4, jp-4)) + (wgt1 * fxy(ip, jp-4))     + (wgt1 * fxy(ip+4, jp-4)) &
                                   + (wgt3 * fxy(ip-3, jp-3)) + (wgt3 * fxy(ip, jp-3))     + (wgt3 * fxy(ip+3, jp-3)) &
                                   + (wgt5 * fxy(ip-2, jp-2)) + (wgt5 * fxy(ip, jp-2))     + (wgt5 * fxy(ip+2, jp-2)) &
                                   + (wgt7 * fxy(ip-1, jp-1)) + (wgt7 * fxy(ip, jp-1))     + (wgt7 * fxy(ip+1, jp-1)) &
                                   + (wgt1 * fxy(ip-4, jp))   + (wgt3 * fxy(ip-3, jp))     + (wgt5 * fxy(ip-2, jp))   &
                                   + (wgt7 * fxy(ip-1, jp))   + (wgt9 * fxy(ip, jp) * 4.0) + (wgt7 * fxy(ip+1, jp))   &
                                   + (wgt5 * fxy(ip+2, jp))   + (wgt3 * fxy(ip+3, jp))     + (wgt1 * fxy(ip+4, jp))   &
                                   + (wgt7 * fxy(ip-1, jp+1)) + (wgt7 * fxy(ip, jp+1))     + (wgt7 * fxy(ip+1, jp+1)) &
                                   + (wgt5 * fxy(ip-2, jp+2)) + (wgt5 * fxy(ip, jp+2))     + (wgt5 * fxy(ip+2, jp+2)) &
                                   + (wgt3 * fxy(ip-3, jp+3)) + (wgt3 * fxy(ip, jp+3))     + (wgt3 * fxy(ip+3, jp+3)) &
                                   + (wgt1 * fxy(ip-4, jp+4)) + (wgt1 * fxy(ip, jp+4))     + (wgt1 * fxy(ip+4, jp+4))
            else
              mslp_smoothe(ip, jp) = (wgt1 * mslp_smoothe(ip-4, jp-4))   + (wgt1 * mslp_smoothe(ip, jp-4))   &
                                   + (wgt1 * mslp_smoothe(ip+4, jp-4))   + (wgt3 * mslp_smoothe(ip-3, jp-3)) &
                                   + (wgt3 * mslp_smoothe(ip, jp-3))     + (wgt3 * mslp_smoothe(ip+3, jp-3)) &
                                   + (wgt5 * mslp_smoothe(ip-2, jp-2))   + (wgt5 * mslp_smoothe(ip, jp-2))   &
                                   + (wgt5 * mslp_smoothe(ip+2, jp-2))   + (wgt7 * mslp_smoothe(ip-1, jp-1)) &
                                   + (wgt7 * mslp_smoothe(ip, jp-1))     + (wgt7 * mslp_smoothe(ip+1, jp-1)) &
                                   + (wgt1 * mslp_smoothe(ip-4, jp))     + (wgt3 * mslp_smoothe(ip-3, jp))   &
                                   + (wgt5 * mslp_smoothe(ip-2, jp))     + (wgt7 * mslp_smoothe(ip-1, jp))   &
                                   + (wgt9 * mslp_smoothe(ip, jp) * 4.0) + (wgt7 * mslp_smoothe(ip+1, jp))   &
                                   + (wgt5 * mslp_smoothe(ip+2, jp))     + (wgt3 * mslp_smoothe(ip+3, jp))   &
                                   + (wgt1 * mslp_smoothe(ip+4, jp))     + (wgt7 * mslp_smoothe(ip-1, jp+1)) &
                                   + (wgt7 * mslp_smoothe(ip, jp+1))     + (wgt7 * mslp_smoothe(ip+1, jp+1)) &
                                   + (wgt5 * mslp_smoothe(ip-2, jp+2))   + (wgt5 * mslp_smoothe(ip, jp+2))   &
                                   + (wgt5 * mslp_smoothe(ip+2, jp+2))   + (wgt3 * mslp_smoothe(ip-3, jp+3)) &
                                   + (wgt3 * mslp_smoothe(ip, jp+3))     + (wgt3 * mslp_smoothe(ip+3, jp+3)) &
                                   + (wgt1 * mslp_smoothe(ip-4, jp+4))   + (wgt1 * mslp_smoothe(ip, jp+4))   &
                                   + (wgt1 * mslp_smoothe(ip+4, jp+4))
            endif
            valid_smoothe(ip, jp) = .true.
          enddo ! iloop_s
        enddo ! jloop_s
      enddo ! smooth_loop

 49   format (1x, 'smth_check, jp = ', i5, '  ip = ', i5, ' orig value = ', f9.2, '   smoothed value = ', &
              f9.2, '   smth-orig = ', f6.2)
      call date_and_time (big_ben(1), big_ben(2), big_ben(3), date_time)
      write (6,53) date_time(5), date_time(6), date_time(7)
 53   format (1x, 'TIMING: Ending of smoothing in find_all_maxmins at: ', i2.2, ':', i2.2, ':', i2.2)
      print *, ' '
      print *, 'End of smoothing loop, kct = ', kct, '  compute_ct = ', compute_ct
    endif

    if (smoothe_mslp_for_gen_scan == 'y') then
      ! copy the smoothed MSLP data into the slp_array to smooth data
      slp_array    = mslp_smoothe
      slp_valid_pt = valid_smoothe
      slp          = mslp_smoothe
      valid_pt     = slp_valid_pt
      
      if (verb >= 1) then
        print *, ' '
        print *, '***************************************************'
        print *, ' GENESIS ATTENTION / WARNING #1: In subroutine'
        print *, ' find_all_maxmins, we have updated the main slp '
        print *, ' array with a smoothed version for genesis'
        print *, ' detection.  The tracking of known storms for this'
        print *, ' lead time has already been done, so this will not'
        print *, ' have any impact on that.  However, any further'
        print *, ' detailed tracking of any new disturbances --'
        print *, ' AT THIS LEAD TIME -- will be done with the'
        print *, ' smoothed mslp field.'
        print *, ' '
        print *, ' GENESIS ATTENTION / WARNING #2: In addition to'
        print *, ' updating the slp array, we are also updating the '
        print *, ' main valid_pt array with the version that was '
        print *, ' modified for use with the smoothed mslp array,'
        print *, ' where a halo of points around the perimeter of'
        print *, ' the search area have been labeled as not valid,'
        print *, ' since we could not do the smoothing close to the'
        print *, ' edge of the domain.'
        print *, '***************************************************'
      endif

    else
      ! use the original, unsmoothed MSLP data
      slp_array    = fxy
      slp_valid_pt = valid_pt
    endif

    candidate_ct = 0
    cmrg_fail_ct = 0

    do j = jbeg, jend ! jloop_g
      do i = ibeg, iend ! iloop_g
        ip = i
        jp = j

        if (ip > imax) then
          if (trkrinfo%gridtype == 'global') then
            ip = i - imax   ! if wrapping past GM
          else
            if (verb .ge. 3) then
              print *, ' '
              print *, '!!! WARNING: In find_all_maxmins, the '
              print *, '!!!   user-requested eastern search boundary'
              print *, '!!!   is beyond the eastern bounds of '
              print *, '!!!   this regional grid.  The search'
              print *, '!!!   will not extend to the user-requested'
              print *, '!!!   grid boundary.'
              print *, '!!!         '
              print *, '!!!   imax of regional grid    = ', imax
              print *, '!!!   User-requested eastern i = ', ip
              print *, ' '
            endif

            exit  ! iloop_g
          endif
        endif

        if (pt_eligible(ip,jp) .and..not. masked_out(ip,jp) .and. slp_valid_pt(ip,jp)) then

          ! call routine to check for MSLP gradient here
          yyct1    = yyct1 + 1
          icmrgret = 88
          call check_mslp_radial_gradient (imax, jmax, ip, jp, dx, dy, slp_array(1,1), slp_valid_pt, trkrinfo, &
               & gm_wrap_flag, icmrgret)

          if (icmrgret == 0) then
            call date_and_time (big_ben(1), big_ben(2), big_ben(3), date_time)
            write (6,31) date_time(5), date_time(6), date_time(7)
 31         format (1x, 'TIMING: b4 check_for_closed_wind_circ at ', i2.2, ':', i2.2, ':', i2.2)

            ! call routine to check for low-level circulation here
            low_level_wind_circ_flag = 'n'
            call check_for_closed_wind_circulation (imax, jmax, ip, jp, dx, dy, valid_pt, trkrinfo, ifh, &
                 & low_level_wind_circ_flag, gm_wrap_flag, vtquadmax, 'genesis', iccwcret)
            call date_and_time (big_ben(1), big_ben(2), big_ben(3), date_time)
            write (6,33) date_time(5), date_time(6) ,date_time(7)
 33         format (1x, 'TIMING: after check_for_closed_wind_circ at ', i2.2, ':', i2.2, ':', i2.2)

            if (iccwcret == 0) then
              int_vtq_ne = nint(10.0 * vtquadmax(1) * 1.9427)
              int_vtq_se = nint(10.0 * vtquadmax(2) * 1.9427)
              int_vtq_sw = nint(10.0 * vtquadmax(3) * 1.9427)
              int_vtq_nw = nint(10.0 * vtquadmax(4) * 1.9427)

              print *, ' '
              write (6,234), atcfymdh, adjustr(atcfname), ifhours(ifh), int_vtq_ne, int_vtq_se, int_vtq_sw, int_vtq_nw
  234         format (1x, 'tcvq_genesis ', i10.10, ', ', 1x,a4, ', ', 1x, i3, 4(', ', i7))

              if (low_level_wind_circ_flag == 'y') then
                candidate_ct           = candidate_ct + 1
                prstemp(candidate_ct)  = slp_array(ip,jp)
                ipos(candidate_ct)     = ip
                jpos(candidate_ct)     = jp
                if (verb >= 3) then
                  print *, ' '
                  print *, ' +++ Successful check of both MSLP radial gradient and LL wind circ, ip = ', ip, ' jp = ', jp
                  print *, ' '
                endif
              else
                if (verb >= 3) then
                  print *, ' '
                  print *, ' !!! MSLP radial gradient passed but LL wind circ check FAILED. ip = ', ip, ' jp = ', jp
                  print *, ' '
                endif
                cycle ! iloop_g
              endif
              
            else
              if (verb >= 3) then
                print *, ' '
                print *, ' !!! Failed check 2 of LL wind circ, ip = ', ip, ' jp = ', jp
                print *, ' '
              endif
              cycle ! iloop_g
            endif

          else
            cycle ! iloop_g
          endif
        endif
      enddo ! iloop_g
    enddo ! jloop_g

    sortindex = 0
    call qsort (prstemp, sortindex, maxstorm)

    if (verb .ge. 3) then
      print *, ' '
      print *, '+++ In find_all_maxmins, finding new storms, this is'
      print *, '+++ after the sorting of the pressure storm list.'
      print *, '+++ Pressure-sorted storm list:'
      print *, ' '

      do ist = 1, maxstorm
        if (prstemp(sortindex(ist)) < 999998.0) then
          xmlat = glatmax - (real(jpos(sortindex(ist)) - 1)) * dy
          xmlon = glonmin + (real(ipos(sortindex(ist)) - 1)) * dx
          if (prstemp(sortindex(ist)) < 1500.0) then    ! pressure values are in mb
            write (6,82) ist, sortindex(ist), prstemp(sortindex(ist)), ipos(sortindex(ist)), jpos(sortindex(ist)), &
                         360.0-xmlon, xmlon, xmlat
          else    ! pressure values are in Pa
            write (6,82) ist,sortindex(ist), prstemp(sortindex(ist))/100.0, ipos(sortindex(ist)), jpos(sortindex(ist)), &
                         360.0-xmlon, xmlon, xmlat
          endif
        endif
      enddo

 82   format (1x, 'ist = ', i6, ' sortindex(ist) = ', i6, ' prstemp = ', f8.3, ' i = ', i5, ' j = ', &
              i5, '  Lon = ', f7.2, 'W   (', f7.2, 'E),  Lat = ', f7.2)
    endif

    dmin =  9.99E10
    dmax = -9.99E10

    do ict = 1, candidate_ct  ! candidate_loop
      ip = ipos(sortindex(ict))
      jp = jpos(sortindex(ict))

      if (ip > imax) then
        if (trkrinfo%gridtype == 'global') then
          ip = ip - imax   ! if wrapping past GM
        else
          if (verb .ge. 3) then
            print *, ' '
            print *, '!!! WARNING: In find_all_maxmins, the '
            print *, '!!!   user-requested eastern search boundary'
            print *, '!!!   is beyond the eastern bounds of '
            print *, '!!!   this regional grid.  The search'
            print *, '!!!   will not extend to the user-requested'
            print *, '!!!   grid boundary.'
            print *, '!!!         '
            print *, '!!!   imax of regional grid    = ', imax
            print *, '!!!   User-requested eastern i = ', ip
            print *, '!!!   User-requested         j = ', jp
            print *, '!!!   In candidate_loop,   ict = ', ict
            print *, ' '
          endif

          cycle  ! candidate_loop
        endif
      endif

      if (slp_valid_pt(ip,jp) .and..not. masked_out(ip,jp)) then
        ix = ip
        jx = jp
        if (cmaxmin == 'min') then
          if (slp_array(ip,jp) < dmin) then
            dmin = slp_array(ip, jp)
          endif
        else
          if (slp_array(ip,jp) > dmax) then
            dmax = slp_array(ip, jp)
          endif
        endif
      else
        if (.not. slp_valid_pt(ip,jp)) then
          cand_not_valid_ct = cand_not_valid_ct + 1
        endif
        if (masked_out(ip,jp)) then
          cand_masked_out_ct = cand_masked_out_ct + 1
        endif
        cycle ! candidate_loop
      endif

      if (verb .ge. 3) then
        xmlat = glatmax - (jp - 1.0) * dy
        xmlon = glonmin + (ip - 1.0) * dx
        write (6,86)
86      format (//, 1x, 61x, 'Lon(E)', 5x, 'Lon(W)', 5x, 'Lat')
        write (6,87) ix, jx, xmlon, 360.0-xmlon, xmlat
87      format (1x, 'Checking for a possible max/min at ix = ', i6, ' jx = ', i6, 3x, f8.2, 3x, f8.2, 3x, f8.2)
      endif

      get_last_isobar_flag = 'n'
      ccflag = 'n'
      yyct2  = yyct2 + 1
      call check_closed_contour (imax, jmax, ix, jx, slp_array, slp_valid_pt, masked_out, ccflag, cmaxmin, trkrinfo, &
           & 1, contour_info, get_last_isobar_flag, plastbar, rlastbar, zzct1, zzct2, zzct3, icccret)
      pass_checks = 'n'

      if (ccflag == 'y') then
        if (stormct < maxstorm) then
          cand_cc_good_ct = cand_cc_good_ct + 1
          point_is_over_water = 'u'

          if (trkrinfo%use_land_mask == 'y' .and. trkrinfo%type == 'tcgen') then
            call check_land_mask (imax, jmax, ix, jx, fract_land, slp_valid_pt, dx, dy, point_is_over_water, ifh, &
                 & gm_wrap_flag, iclmret)
            if (iclmret /= 0) then
              print *, ' '
              print *, '!!! ERROR from check_land_mask for ix = ', ix, ' jx = ', jx
              print *, '!!! STOPPING PROGRAM'
              stop 95
            endif

            if (point_is_over_water /= 'n') then
              pass_checks = 'y'
              stormct = stormct + 1
              maxmini(stormct) = ix
              maxminj(stormct) = jx
            endif

          else
            pass_checks = 'y'
            stormct = stormct + 1
            maxmini(stormct) = ix
            maxminj(stormct) = jx
          endif

          if (pass_checks == 'y' .and. verb .ge. 3) then
            xmlat = glatmax - ((jx - 1.0) * dy)
            xmlon = glonmin + ((ix - 1.0) * dx)
            write (6,92) stormct, ix, jx, 360.0-xmlon, xmlon, xmlat
 92         format (1x, 'ccflag = y, new stormct = ', i6, ' ix = ', i5, ' jx = ', i5, '  Lon = ', &
                    f7.2, 'W   (', f7.2, 'E),  Lat = ', f7.2)
          endif

        else
          if (verb .ge. 3) then
            print *, '---max stormct reached, stormct = ', stormct
          endif
        endif
      
      else
        cand_cc_bad_ct = cand_cc_bad_ct + 1
        if (verb .ge. 3) then
          print *, '!!! contour check negative, ccflag = ', ccflag
        endif
      endif

      if (verb .ge. 3) then
        print *, ' '
        print *, '*-----------------------------------------------*'
        print *, '* After check_closed_contour...                 *'
        print *, '*-----------------------------------------------*'
        print *, ' '
      endif

      igicwret = 0
      call get_ijplus1_check_wrap (imax, jmax, ix, jx, ixp1, jxp1, ixm1, jxm1, trkrinfo, igicwret)

      if (igicwret == 0) then
        masked_out(ix, jx)     = .true.
        masked_out(ix, jxp1)   = .true.
        masked_out(ixp1, jxp1) = .true.
        masked_out(ixp1, jx)   = .true.
        masked_out(ixp1, jxm1) = .true.
        masked_out(ix, jxm1)   = .true.
        masked_out(ixm1, jxm1) = .true.
        masked_out(ixm1, jx)   = .true.
        masked_out(ixm1, jxp1) = .true.
      else
        if (verb .ge. 3) then
          print *, ' '
          print *, '!!! NOTE: In find_all_maxmins, after the call to'
          print *, '!!!     check_closed_contour, the call to '
          print *, '!!!     get_ijplus1_check_wrap returned a nonzero'
          print *, '!!!     return code.  This point is too close to'
          print *, '!!!     the grid boundary, and so we will NOT be'
          print *, '!!!     setting surrounding points to'
          print *, '!!!     masked_out=true, we will only set the flag'
          print *, '!!!     to true for the (ix,jx) we are at.'
          print *, '!!! '
          print *, '!!!  ix = ', ix, ' jx = ', jx, '  slp_array = ', slp_array(ix,jx)
          print *, '!!! '
          print *, ' '
        endif
        masked_out(ix, jx) = .true.
      endif
    enddo  ! candidate_loop

    if (verb >= 3) then
      print *, ' '
      print *, 'At end of candidate loop in find_all_maxmins: '
      print *, '        candidate_ct = ', candidate_ct
      print *, '   cand_not_valid_ct = ', cand_not_valid_ct
      print *, '  cand_masked_out_ct = ', cand_masked_out_ct
      print *, '     cand_cc_good_ct = ', cand_cc_good_ct
      print *, '      cand_cc_bad_ct = ', cand_cc_bad_ct
      print *, '        cmrg_fail_ct = ', cmrg_fail_ct
      print *, '  (During candidate_loop, some points surrounding'
      print *, '   others may have been masked out, so the sum of'
      print *, '   4 cand_ counts may not match up to the total num'
      print *, '   of candidate pts shown in candidate_ct.)'
    endif

    deallocate (sortindex)
    deallocate (prstemp)
    deallocate (ipos)
    deallocate (jpos)
    deallocate (slp_array)
    deallocate (slp_valid_pt)

    if (allocated(mslp_smoothe))  deallocate (mslp_smoothe)
    if (allocated(valid_smoothe)) deallocate (valid_smoothe)

    return

  end subroutine find_all_maxmins

  !****************************************************************************
  !*
  !*  ABSTRACT: This subroutine performs a computation that looks out
  !*      along 8 radials to determine if there is a radial gradient of MSLP
  !*      that is at least as strong as that specified by the user.  For
  !*      example, if the user enters a MSLP contour interval of 1 mb, then
  !*      we will start at the candidate position, and in each of the 8
  !*      radial directions, we will check the interpolated MSLP at discrete
  !*      distances out to 300 km.  If at any discrete radius along the way
  !*      outward, that 1-mb increase in MSLP is achieved, then set the flag
  !*      to Y for that radial and stop any further checking along that
  !*      radial, and move to the next radial.  Iterate through all 8
  !*      radials, as long as there is continued success, meaning that if
  !*      while going through this process, if one of the radials fails the
  !*      test, then this candidate point is discarded altogether, and then
  !*      move onto the next candidate point.  As part of this testing along
  !*      a radial, consider allowing perhaps a slight drop along a radial
  !*      (maybe something like 0.05 mb?) to account for noise, but if it's
  !*      any more than that, then fail the radial and discard the candidate
  !*      point.  NOTE: In the first testing of this routine in early 2023,
  !*      it was found that for hi-res T-SHiELD data, using a value of
  !*      xmslp_noise > 0 allowed too many noise disturbances through, so
  !*      I have set it to zero.
  !*
  !*  INPUT:
  !*      imax         :: Num pts in i-direction on grid
  !*      jmax         :: Num pts in j-direction on grid
  !*      ip           :: i index for location of local max or min
  !*      jp           :: j index for location of local max or min
  !*      dx           :: x-increment on the grid
  !*      dy           :: y-increment on the grid
  !*      fxy          :: input data array
  !*      valid_pt     :: Logical; bitmap indicating if valid data at that pt
  !*      masked_outc  :: Logical. T = data point is already accounted for,
  !*                      under the influence of another nearby max or min
  !*                      center; F = data point is available to be scanned by
  !*                      this subroutine for max or min centers.
  !*      ctlon        :: Fix longitude for the input parameter to this routine
  !*      ctlon        :: Fix latitude for the input parameter to this routine
  !*      cmodel_type  :: character, 'global' or 'regional'
  !*      ifh          :: integer index for forecast hour array
  !*      gm_wrap_flag :: character flag set in getgridinfo that determines
  !*                      what GM-wrapping setting to use.
  !*
  !****************************************************************************
  subroutine check_mslp_radial_gradient (imax, jmax, ip, jp, dx, dy, fxy, valid_pt, trkrinfo, gm_wrap_flag, icmrgret)

    use set_max_parms; use trkrparms; use grid_bounds; use verbose_output; use level_parms

    implicit none

    type (trackstuff)  :: trkrinfo

    character(len=1)   :: one_radial_mslp_depth_flag
    character(len=1)   :: continuous_gradient_flag
    character(len=*)   :: gm_wrap_flag
    integer, parameter :: distmax = 11, num_azim = 8
    integer            :: imax, jmax, ip, jp, idist, ilevint, bimct, iazim, ifh99, iquadct
    integer            :: iazim_good_depth_ct, ibiret1, icmrgret, i, j
    integer            :: iazim_full_dist_ct
    real, intent(in)   :: fxy(imax,jmax)
    real               :: max_radial_grad_dist(num_azim)
    real               :: rdist(distmax)
    real               :: dx, dy, bear, xmlat, xmlon, targlat, targlon, xintrp_mslp
    real               :: xcent_mslpval, xmslp_thresh, xmslp_noise
    real               :: xnext_radially_inward_mslpval
    logical(1)         :: valid_pt(imax,jmax)

    data rdist /10.0, 15.0, 20.0, 25.0, 30.0, 35.0, 40.0, 50.0, 60.0, 75.0, 100.0/

    ilevint = 1020
    bimct   = 0
    ifh99   = 99
    xcent_mslpval = fxy(ip, jp)

    if (fxy(ip,jp) > 50000.0) then
      if (trkrinfo%contint < 20.0) then
        ! convert mb to Pa
        xmslp_thresh = trkrinfo%contint * 100.0
      else
        ! no conversion needed
        xmslp_thresh = trkrinfo%contint
      endif
      xmslp_noise = 0.0

    else
      if (trkrinfo%contint < 20.0) then
        ! no conversion needed
        xmslp_thresh = trkrinfo%contint
      else
        xmslp_thresh = trkrinfo%contint / 100.0
      endif
      xmslp_noise = 0.0
    endif

    xmlat = glatmax - (jp - 1.0) * dy !CAITLYN - repeated code?
    xmlon = glonmin + (ip - 1.0) * dx
    iazim_good_depth_ct = 0

    do iazim = 1, num_azim  ! azimloop1
      bear =  (real(iazim - 1) * 45.0) + 22.5
      one_radial_mslp_depth_flag = 'n'
      continuous_gradient_flag   = 'n'
      xnext_radially_inward_mslpval = xcent_mslpval

      do idist = 1, distmax  ! distloop1
        call distbear (xmlat, xmlon, rdist(idist), bear, targlat, targlon, gm_wrap_flag)

        if (gm_wrap_flag == 'maxplus360') then
          if ((xmlon > 330.0 .and. xmlon <= 360.0) .and. targlon < 25.0) then
            targlon = targlon + 360.0
          endif
          if (xmlon > 360.0 .and. (targlon >= 0.0 .and. targlon < 180.0)) then
            targlon = targlon + 360.0
          endif
        endif

        call bilin_int_uneven (targlat, targlon, dx, dy, imax, jmax, trkrinfo, ilevint, 'p', xintrp_mslp, &
             & valid_pt, bimct, ifh99, ibiret1)

        if (ibiret1 == 0) then
          if (xintrp_mslp < (xcent_mslpval - xmslp_noise)) then
            if (rdist(idist) <= 25.0) then
              icmrgret = 95
              return
            endif
          endif

          if (one_radial_mslp_depth_flag == 'n') then
            if (xintrp_mslp >= (xcent_mslpval + xmslp_thresh)) then
              one_radial_mslp_depth_flag = 'y'
            endif
          endif

          if ((xintrp_mslp + xmslp_noise) < xnext_radially_inward_mslpval) then
            continuous_gradient_flag = 'n'

            if (rdist(idist) <= 25.0) then
              icmrgret = 96
              return
            else
              if (idist > 1) then
                max_radial_grad_dist(iazim) = rdist(idist - 1)
                exit  ! distloop1
              else
                max_radial_grad_dist(iazim) = 0.0
                exit  ! distloop1
              endif
            endif
          else
            xnext_radially_inward_mslpval = xintrp_mslp
            continuous_gradient_flag      = 'y'
          endif
        endif
      enddo  ! distloop1

      if (one_radial_mslp_depth_flag == 'y') then
        iazim_good_depth_ct = iazim_good_depth_ct + 1
        if (continuous_gradient_flag == 'y' ) then
          max_radial_grad_dist(iazim) = rdist(distmax)
        endif
      else
        icmrgret = 95
        return
      endif
    enddo  ! azimloop1

    if (iazim_good_depth_ct == num_azim) then
      write (6,97) jp, xmlat, ip, xmlon, 360.0-xmlon
97    format (//, 1x, '  --> GOOD check_mslp depth at every radial, jp = ', i5, ' xmlat = ', f7.2, ' ip = ', &
                  i5, ' xmlon = ', f7.2, 'E  (', f7.2, 'W)')
      continue
    else
      write (6,99) jp, xmlat, ip, xmlon, 360.0-xmlon, iazim_good_depth_ct, num_azim
   99 format (//, 1x, '  --> FAIL check_mslp depth NOT at every radial, jp = ', i5, ' xmlat = ', f7.2, ' ip = ', &
                  i5, ' xmlon = ', f7.2, 'E  (', f7.2, 'W) iazim_good_depth_ct = ', i3, ' num_azim = ', i3)
      icmrgret = 95
      return
    endif

    iazim_full_dist_ct = 0
    do iazim = 1, num_azim  ! azimloop2
      if (max_radial_grad_dist(iazim) == rdist(distmax)) then
        iazim_full_dist_ct = iazim_full_dist_ct + 1
      endif
    enddo  ! azimloop2

    if (iazim_full_dist_ct == num_azim) then
      if (verb >= 3) then
        print *, ' '
        print *, 'In check_mslp_radial_gradient, GOOD radial gradient'
        print *, '  to distmax for ALL azimuths.'
      endif
      icmrgret = 0
      return
    elseif (iazim_full_dist_ct >= 3 .and. iazim_full_dist_ct < 8) then
      if (verb >= 3) then
        print *, ' '
        print *, 'In check_mslp_radial_gradient, GOOD radial gradient'
        print *, '  to distmax for at least 3 azimuths. '
        print *, '  iazim_full_dist_ct = ', iazim_full_dist_ct
      endif
      icmrgret = 0
      return
    endif

    if (iazim_full_dist_ct < 2) then
      if (verb >= 3) then
        print *, ' '
        print *, '!!! In check_mslp_radial_gradient, not enough'
        print *, '!!! azimuths reached the full distmax.  FAILING'
        print *, '!!! this gridpoint.  iazim_full_dist_ct = ', iazim_full_dist_ct
      endif
      icmrgret = 95
      return
    endif

    iquadct = 0
    if (max_radial_grad_dist(1) == rdist(distmax) .or. max_radial_grad_dist(2) == rdist(distmax)) then
      iquadct = iquadct + 1
    endif
    if (max_radial_grad_dist(3) == rdist(distmax) .or. max_radial_grad_dist(4) == rdist(distmax)) then
      iquadct = iquadct + 1
    endif
    if (max_radial_grad_dist(5) == rdist(distmax) .or. max_radial_grad_dist(6) == rdist(distmax)) then
      iquadct = iquadct + 1
    endif
    if (max_radial_grad_dist(7) == rdist(distmax) .or. max_radial_grad_dist(8) == rdist(distmax)) then
      iquadct = iquadct + 1
    endif

    if (iquadct > 1) then
      if (verb >= 3) then
        print *, ' '
        print *, '+++ In check_mslp_radial_gradient, only 2 radials'
        print *, '+++ maintained their MSLP gradient over the full'
        print *, '+++ distance, but they occurred in different'
        print *, '+++ quadrants, so this point passes.'
      endif
      icmrgret = 0
      return
    else
      if (verb >= 3) then
        print *, ' '
        print *, '!!! In check_mslp_radial_gradient, only 2 radials'
        print *, '!!! maintained their MSLP gradient over the full'
        print *, '!!! distance, but they occurred in the same'
        print *, '!!! quadrant, so this point FAILS.'
      endif
      icmrgret = 95
      return
    endif

    return

  end subroutine check_mslp_radial_gradient

  !****************************************************************************
  !*
  !*  ABSTRACT: This subroutine checks for a low-level (10-m)
  !*      cyclonic circulation, in a manner that is meant to emulate how
  !*      NHC assesses a disturbance in order to determine whether or not
  !*      TC formation has occurred.  We will do a check at three different
  !*      radii (initially 75, 125 and 175 km), and if the check passes at
  !*      any one of these, then the low-level wind circulation is
  !*      satisfied, the flag is set to y, and the subroutine returns to
  !*      the calling routine.  At each candidate radius, we do a check of
  !*      the Vt at 16 equally-spaced azimuths.  There are 4 points in each
  !*      quadrant.  We average those 4 points to get a mean Vt for that
  !*      azimuth.  Once we have a mean Vt for all 16 azimuths, go through
  !*      the azimuths, one at a time, in a clockwise fashion, and check to see
  !*      if their mean cyclonic Vt passes a threshold.  As long as 2 in a
  !*      row do not fail, the test passes (i.e., every other one can pass
  !*      and that is okay).
  !*
  !*  INPUT:
  !*      imax                :: max i dimension of model grid
  !*      jmax                :: max j dimension of model grid
  !*      ip                  :: i index for candidate location of local max or min
  !*      jp                  :: j index for candidate location of local max or min
  !*      dx                  :: grid spacing in i-direction of model grid
  !*      dy                  :: grid spacing in j-direction of model grid
  !*      valid_pt            :: logical bitmap for valid data at a grid point
  !*      trkrinfo            :: derived type detailing user-specified grid info
  !*      ifh                 :: integer index for the current lead time being processed
  !*      gm_wrap_flag        :: character flag set in getgridinfo that determines
  !*                             what GM-wrapping setting to use for this grid.
  !*      tracker_application :: character string that determines if the
  !*                             calling routine is working through a genesis
  !*                             application or a forward tracking application for an
  !*                             already-known system, whether known at the very start
  !*                             of this tracker run or known from a previous lead time
  !*                             where it might have been found for the first time in
  !*                             this forecast as part of a genesis run.  The value
  !*                             should be either "genesis" or "forward".
  !*
  !*  OUTPUT:
  !*      low_level_wind_circ_flag :: character flag that will inform the
  !*                             calling routine as to whether or not a low-level
  !*                             closed circulation was found.
  !*      vtquadmax           :: real array that contains the max mean cyclonic Vt
  !*                             averaged the various azimuths at any given distance
  !*                             in that quadrant (i.e., it could occur at 75, 125 or
  !*                             175 km... it does not matter).
  !*      iccwcret            :: return code from this subroutine
  !*
  !****************************************************************************
  subroutine check_for_closed_wind_circulation (imax, jmax, ip, jp, dx, dy, valid_pt, trkrinfo, ifh, &
                                               & low_level_wind_circ_flag, gm_wrap_flag, vtquadmax,  &
                                               & tracker_application, iccwcret)

    use grid_bounds; use tracked_parms; use trig_vals; use trkrparms; use verbose_output

    implicit none

    type (trackstuff)   :: trkrinfo

    integer, parameter  :: numdist = 3, numazim = 16, numquad = 4
    integer, intent(in) :: ip, jp
    integer             :: vt_exceed_17kts_ct(numquad,numdist)
    integer             :: vtct(numquad,numdist)
    integer             :: date_time(8)
    integer             :: imax, jmax, idist, azimuth_ct, ibiret1, ibiret2, bimct, iq, nq
    integer             :: final_quad_full_vt_ct, iccwcret, iazim, igvtret, ifh
    integer             :: final_quad_half_vt_ct, final_quad_sum_ct
    real                :: xcandlon, ycandlat
    real                :: rdist(numdist)
    real                :: vtsum(numquad,numdist), vtquadmax(numquad)
    real                :: dx, dy, bear, targlat, targlon, xintrp_u, xintrp_v, vr, vt
    real                :: hemisphere, vtavg, full_vt_thresh, half_vt_thresh
    character(len=1)    :: low_level_wind_circ_flag
    character(len=1)    :: quad_pass_flag(numquad)
    character(len=1)    :: quad_pass_half_vt_flag(numquad)
    character(len=*)    :: gm_wrap_flag
    character(len=*)    :: tracker_application
    logical(1)          :: valid_pt(imax,jmax)

    data rdist /75.0, 125.0, 175.0/  ! distances in km

    vt_exceed_17kts_ct     = 0
    quad_pass_flag         = 'n'
    quad_pass_half_vt_flag = 'n'
    vtsum                  = 0.0
    vtquadmax              = 0.0
    vtct                   = 0
    iccwcret               = 0
    igvtret                = 0

    full_vt_thresh = 7.0                   ! wind speed in m/s
    half_vt_thresh = 0.5 * full_vt_thresh  ! wind speed in m/s

    bimct = 0

    xcandlon = glonmin + (real(ip - 1) * dx)
    ycandlat = glatmax - (real(jp - 1) * dy)

    if (ycandlat >= 0.0) then
      hemisphere = 1.0
    else
      hemisphere = -1.0
    endif

    do idist = 1, numdist ! radiusloop
      azimuth_ct = 0

      do iazim = 1, numazim ! azimloop
        bear = ((real(iazim - 1)) * 22.5) + 11.25

        call distbear (ycandlat, xcandlon, rdist(idist), bear, targlat, targlon, gm_wrap_flag)

        if (gm_wrap_flag == 'maxplus360') then
          if ((xcandlon > 330.0 .and. xcandlon <= 360.0) .and. targlon < 25.0) then
            targlon = targlon + 360.0
          endif
          if (xcandlon > 360.0 .and. (targlon >= 0.0 .and. targlon < 180.0)) then
            targlon = targlon + 360.0
          endif
        endif

        call bilin_int_uneven (targlat, targlon, dx, dy, imax, jmax, trkrinfo, 1020, 'u', xintrp_u, &
             & valid_pt, bimct, -99, ibiret1)
        call bilin_int_uneven (targlat, targlon, dx, dy, imax, jmax, trkrinfo, 1020, 'v', xintrp_v, &
             & valid_pt, bimct, -99, ibiret2)

        if (ibiret1 == 0 .and. ibiret2 == 0) then
          call getvrvt (xcandlon, ycandlat, targlon, targlat, xintrp_u, xintrp_v, vr, vt, ifh, igvtret)

          if (bear >= 0.0 .and. bear < 90.0) then
            iq = 1
          elseif (bear >= 90.0 .and. bear < 180.0) then
            iq = 2
          elseif (bear >= 180.0 .and. bear < 270.0) then
            iq = 3
          elseif (bear >= 270.0 .and. bear <= 360.0) then
            iq = 4
          endif

          vtsum(iq, idist) = vtsum(iq, idist) + vt
          vtct(iq, idist)  = vtct(iq, idist) + 1

          if ((hemisphere*vt) >= 8.75) then
            ! increment counter by 1 if cyclonic Vt > 8.75 m/s (17 kts) @ this azimuth
            vt_exceed_17kts_ct(iq, idist) = vt_exceed_17kts_ct(iq, idist) + 1
          endif
        endif
      enddo ! azimloop

      do nq = 1, numquad
        if (vt_exceed_17kts_ct(nq,idist) >= 2) then
          quad_pass_flag(nq) = 'y'
        endif
      enddo

      do nq = 1, numquad
        ! we need at least 2 valid azimuths in order to get a proper mean Vt.
        if (vtct(nq,idist) >= 2) then
          vtavg = vtsum(nq, idist) / vtct(nq, idist)
          if ((hemisphere * vtavg) >= full_vt_thresh) then
            quad_pass_flag(nq) = 'y'
          elseif ((hemisphere * vtavg) >= half_vt_thresh) then
            quad_pass_half_vt_flag(nq) = 'y'
          endif
        else
          vtavg = -9999.0
        endif

        ! Now check for the max average Vt in this quadrant
        if (vtavg > -9998.0) then
          if ((hemisphere * vtavg) > (hemisphere * vtquadmax(nq))) then
            vtquadmax(nq) = vtavg
          endif
        endif
      enddo
    enddo ! radiusloop

    if (verb >= 3) then
      print *, ' '
      print *, '  *--------------------------------------------------*'
      print *, '   LL wind circulation check:'
      print *, '   Values of mean Vt wind in each quadrant.  Values'
      print *, '   come from subroutine  check_for_closed_circulation'
      print *, '   and the values shown below for each quadrant could'
      print *, '   be at any one of the 3 checked distances (75, 125,'
      print *, '   or 175 km).  The exact distance does not matter.'
      print *, '   We are simply trying to determine if there is a '
      print *, '   closed circulation to start / continue tracking.'
      print *, ' '
      write (6,71) 'NE', vtquadmax(1) * 1.9427
      write (6,71) 'SE', vtquadmax(2) * 1.9427
      write (6,71) 'SW', vtquadmax(3) * 1.9427
      write (6,71) 'NW', vtquadmax(4) * 1.9427
      print *, ' '
      print *, '  *--------------------------------------------------*'
71    format (1x, '   LL Wind Circ Vt mean quadmax value: ', a2, 2x, f8.2, ' kts')
    endif

    final_quad_full_vt_ct = 0
    final_quad_half_vt_ct = 0
    final_quad_sum_ct     = 0

    do nq = 1, numquad
      if (quad_pass_flag(nq) == 'y') then
        final_quad_full_vt_ct = final_quad_full_vt_ct + 1
      endif
    enddo

    do nq = 1, numquad
      if (quad_pass_half_vt_flag(nq) == 'y') then
        final_quad_half_vt_ct = final_quad_half_vt_ct + 1
      endif
    enddo

    final_quad_sum_ct = final_quad_full_vt_ct + final_quad_half_vt_ct

    if (final_quad_sum_ct == 4) then
      if (final_quad_full_vt_ct >= 2) then
        low_level_wind_circ_flag = 'y'
      else
        low_level_wind_circ_flag = 'n'
      endif
    else
      low_level_wind_circ_flag   = 'n'
    endif

    return

  end subroutine check_for_closed_wind_circulation

  !****************************************************************************
  !*
  !*  ABSTRACT: This subroutine masks out grid points for a storm that
  !*      is currently being tracked.  It is called after a fix has been
  !*      made at the current forecast hour.  It is only used as a backup,
  !*      that is, if the mslp data were not there and/or a fix position
  !*      for mslp could not be made, then that means that the mask would
  !*      not be able to get updated using the routine in subroutine
  !*      check_closed_contour.  But we still do need to update that mask,
  !*      so we will instead do it based on wind circulation.  We will go
  !*      out radially from the center, starting at 40 km, then every
  !*      40 km from there on out.  When the mean cyclonic Vt drops below
  !*      3 m/s, stop searching, and then mask out all grid points within
  !*      that last-searched radius.
  !*
  !*  INPUT:
  !*      imax         :: Num pts in i-direction on grid
  !*      jmax         :: Num pts in j-direction on grid
  !*      ix           :: i index for location of local max or min
  !*      jx           :: j index for location of local max or min
  !*      fxy          :: input data array
  !*      valid_pt     :: Logical; bitmap indicating if valid data at that pt
  !*      masked_outc  :: Logical. T = data point is already accounted for,
  !*                      under the influence of another nearby max or min
  !*                      center; F = data point is available to be scanned by
  !*                      this subroutine for max or min centers.
  !*      ctlon        :: Fix longitude for the input parameter to this routine
  !*      ctlon        :: Fix latitude for the input parameter to this routine
  !*      cmodel_type  :: character, 'global' or 'regional'
  !*      ifh          :: integer index for forecast hour array
  !*      gm_wrap_flag :: character flag set in getgridinfo that determines
  !*                      which GM-wrapping setting to use.
  !*
  !****************************************************************************
  subroutine mask_based_on_wind_circ (imax, jmax, dx, dy, level, valid_pt, masked_outc, trkrinfo, ctlon, ctlat, &
                                     & cmodel_type, ifh, gm_wrap_flag, imbowret)

    use set_max_parms; use trkrparms; use grid_bounds; use verbose_output; use level_parms

    implicit none

    type (trackstuff)  :: trkrinfo

    character(len=*)   :: cmodel_type
    character(len=*)   :: gm_wrap_flag
    integer, parameter :: numazim = 24
    integer            :: imax, jmax, level, imbowret, nlev, iazim, i, j
    integer            :: ibiret1, ibiret2, azimuth_ct, igvtret
    integer            :: jnfix, jsfix, iefix, iwfix, bimct, ifh
    real               :: vr(numazim), vt(numazim)
    real               :: dx, dy, ctlon, ctlat, rdist, bear, targlat, targlon
    real               :: xintrp_u, xintrp_v, grid_buffer, xmax_rdist_reached
    real               :: vt_mean, vt_azim_sum, xbear, dist, degrees
    logical(1)         :: valid_pt(imax,jmax), masked_outc(imax,jmax)
    logical(1)         :: searching_valid_pts

    imbowret = 0

    select case (level)
      case (850);  nlev = nlev850  ! check module level_parms for the values of these
      case (700);  nlev = nlev700
      case (500);  nlev = nlev500
      case (200);  nlev = nlev200
      case (1020); nlev = levsfc
    end select

    if (cmodel_type == 'regional') then
      grid_buffer = 0.30
    else
      grid_buffer = 0.0
    endif

    searching_valid_pts = .true.

    rdist = 40.0                 ! units in km
    xmax_rdist_reached = rdist   ! units in km
    bimct = 0

    do while (searching_valid_pts)  ! radial_loop
      azimuth_ct  = 0
      vt_azim_sum = 0.0
      vt = -999.0
      vr = -999.0

      do iazim = 1, numazim  ! azimloop
        bear = ((real(iazim - 1)) * 15.0) + 7.5
        call distbear (ctlat, ctlon, rdist, bear, targlat, targlon, gm_wrap_flag)

        if (gm_wrap_flag == 'maxplus360') then
          if ((ctlon > 330.0 .and. ctlon <= 360.0) .and. targlon < 25.0) then
            targlon = targlon + 360.0
          endif
          if (ctlon > 360.0 .and. (targlon >= 0.0 .and. targlon < 180.0)) then
            targlon = targlon + 360.0
          endif
        endif

        if (targlon >= glonmax) then
          if (trkrinfo%gridtype == 'global') then
            targlon = targlon - 360.0
          else
            xmax_rdist_reached = rdist
            exit  ! radial_loop
          endif
        endif

        if (targlon < glonmin) then
          if (trkrinfo%gridtype == 'global') then
            targlon = targlon + 360.0
          else
            xmax_rdist_reached = rdist
            exit  ! radial_loop
          endif
        endif

        if (targlat > glatmax .or. targlat < glatmin) then
          xmax_rdist_reached = rdist
          exit  ! radial_loop
        endif

        call bilin_int_uneven (targlat, targlon, dx, dy, imax, jmax, trkrinfo, level, 'u', xintrp_u, &
             & valid_pt, bimct, -99, ibiret1)
        call bilin_int_uneven (targlat, targlon, dx, dy, imax, jmax, trkrinfo, level, 'v', xintrp_v, &
             & valid_pt, bimct, -99, ibiret2)

        if (ibiret1 == 0 .and. ibiret2 == 0) then
          call getvrvt (ctlon, ctlat, targlon, targlat, xintrp_u, xintrp_v, vr(iazim), vt(iazim), -99, igvtret)
          azimuth_ct = azimuth_ct + 1
          vt_azim_sum = vt_azim_sum + vt(iazim)
        else
          xmax_rdist_reached = rdist
          exit  ! radial_loop
        endif
      enddo  ! azimloop

      if (azimuth_ct > 0) then
        ! compute azimuthally-averaged Vt at this distance
        vt_mean = vt_azim_sum / real(azimuth_ct)
      else
        vt_mean = -999.0
      endif

      if (verb .ge. 3) then
        print *, 'mbow: rdist = ', rdist, ' azimuth_ct = ', azimuth_ct, '  vt_azim_sum = ', vt_azim_sum, &
                 ' vt_mean = ',    vt_mean
      endif

      if (ctlat >= 0.0) then
        if (vt_mean >= 3.0) then
          rdist = rdist + 40.0
        else
          xmax_rdist_reached = rdist
          exit  ! radial_loop
        endif
      else
        if (vt_mean <= -3.0 .and. vt_mean > -998.0) then
          rdist = rdist + 40.0
        else
          xmax_rdist_reached = rdist
          exit  ! radial_loop
        endif
      endif
    enddo  ! radial_loop

    if (bimct > 0) then
      if (verb .ge. 3) then
        print *, ' '
        print *, 'Warning summary: From sub mask_based_on_wind_circ,'
        print *, 'calls to sub bilin_int_uneven resulted in'
        print *, '(blocked) attempts to access points outside the'
        print *, 'bounds of a regional grid.  Total # of access'
        print *, 'attempts for this call in radial_loop = ', bimct
        print *, ' '
      endif
    endif

    if (verb .ge. 3) then
      print *, 'mbow: After radial_loop, rdist = ', rdist, '    xmax_rdist_reached = ', xmax_rdist_reached
    endif

    if (xmax_rdist_reached > 80.0) then
      xmax_rdist_reached = xmax_rdist_reached - 40.0
    else
      xmax_rdist_reached = 80.0
    endif

    if (verb .ge. 3) then
      print *, 'mbow: After adjustment of xmax_rdist_reached, rdist = ', rdist, &
               '    xmax_rdist_reached = ', xmax_rdist_reached
    endif

    do i = 1, 4  ! bearloop

      select case (i)
        case (1); xbear =   0.0;
        case (2); xbear =  90.0;
        case (3); xbear = 180.0;
        case (4); xbear = 270.0;
      end select

      call distbear (ctlat, ctlon, xmax_rdist_reached, xbear, targlat, targlon, gm_wrap_flag)

      if (gm_wrap_flag == 'maxplus360') then
        if ((ctlon > 330.0 .and. ctlon <= 360.0) .and. targlon < 25.0) then
          targlon = targlon + 360.0
        endif
        if (ctlon > 360.0 .and. (targlon >= 0.0 .and. targlon < 180.0)) then
          targlon = targlon + 360.0
        endif
      endif

      if (verb .ge. 3) then
        print *, 'mbow: distbear for i = ', i, ' targlon = ', targlon, &
                  '  (0-360E) targlon = ', mod(targlon,360.0), ' targlat = ', targlat
      endif

      if (targlon >= glonmax) then
        if (trkrinfo%gridtype == 'global') then
          targlon = targlon - 360.0
        else
          print *, ' '
          print *, 'WARNING: In subroutine mask_based_on_wind_circ,'
          print *, 'targlon > glonmax for a regional grid, so we '
          print *, 'cannot update the mask.'
          print *, 'targlon = ', targlon, '  glonmax = ', glonmax
          print *, '  (0-360) targlon = ', mod(targlon,360.0)
          imbowret = 95
          return
        endif
      endif

      if (targlon < glonmin) then
        if (trkrinfo%gridtype == 'global') then
          targlon = targlon + 360.0
        else
          print *, ' '
          print *, 'WARNING: In subroutine mask_based_on_wind_circ,'
          print *, 'targlon < glonmin for a regional grid, so we '
          print *, 'cannot update the mask.'
          print *, 'targlon = ', targlon, '  glonmin = ', glonmin
          print *, '  (0-360) targlon = ', mod(targlon,360.0)
          imbowret = 95
          return
        endif
      endif

      if (targlat > glatmax .or. targlat < glatmin) then
          print *, ' '
          print *, 'WARNING: In subroutine mask_based_on_wind_circ,'
          print *, 'either targlat > glatmx or targlat < glatmin, so'
          print *, 'we cannot update the mask.'
          print *, 'targlat = ', targlat, '  glatmin = ', glatmin
          print *, '                         glatmin = ', glatmin
          imbowret = 95
          return
        cycle ! bearloop
      endif

      if (i == 1) then
        ! get j for northern latitude; round targlat to the closest jpoint
        if (targlat >= 0.0) then    ! N. Hemisphere
          jnfix = int((glatmax - targlat)/dy + 1.0 + 0.5)
        else                        ! S. Hemisphere
          jnfix = ceiling((glatmax - targlat) /dy + 1.0 - 0.5)
        endif

      elseif (i == 2) then
        ! get i for eastern longitude; round targlon to closest ipoint
        iefix = int((targlon - glonmin) / dx + 1.0 + 0.5)

      elseif (i == 3) then
        ! get i for southern latitude; round targlat to the closest jpoint
        if (targlat >= 0.0) then    ! N. Hemisphere
          jsfix = int((glatmax - targlat) / dy + 1.0 + 0.5)
        else                        ! S. Hemisphere
          jsfix = ceiling((glatmax - targlat) / dy + 1.0 - 0.5)
        endif

      elseif (i == 4) then
        ! get i for western longitude; round targlon to the closest ipoint
        iwfix = int((targlon - glonmin) / dx + 1.0 + 0.5)
      endif
    enddo  ! bearloop

    if (verb .ge. 3) then
      print *, 'mbow:  iwfix = ', iwfix, ' iefix = ', iefix, ' jnfix = ', jnfix, ' jsfix = ', jsfix
    endif

    do i = iwfix, iefix
      do j = jnfix, jsfix
        call calcdist (glon(i), glat(j), ctlon, ctlat, dist, degrees)
        if (dist < xmax_rdist_reached) then
          masked_outc(i, j) = .true.
        endif
      enddo
    enddo

    return

  end subroutine mask_based_on_wind_circ

  !****************************************************************************
  !*
  !*  ABSTRACT: This subroutine checks a field of data around an input
  !*      (ix,jx) data point to see if a closed contour exists around
  !*      that data point.  It can check for a closed contour on a max or a
  !*      min field, depending on the value of the input variable 'cmaxmin'.
  !*      The algorithm works by examining rings of the 8 data points
  !*      surrounding a data point that is in the contour interval.  For
  !*      example, in the diagram below, the X represents the location of
  !*      the local minimum value which was passed into this routine with
  !*      the coordinates (ix,jx), let's say it's 985 mb.  And let's assume
  !*      that the data values at points A-I are all in the 4 mb contour
  !*      interval of 985-989 mb, and that all the surrounding points have
  !*      data values >= 989.  To test for a closed contour, we first check
  !*      the ring of 8 points immediately around point X to see what their
  !*      data values are.  If a data value is found that is below the
  !*      lower limit of this contour interval (985 mb) or lower than the
  !*      local minimum value at the X point that we initially targeted
  !*      (985 mb), then we do NOT have a closed contour, and we exit this
  !*      subroutine.  But in our example, that's not the case, and we have
  !*      5 points (B,D,E,F,G) that are in the interval.  So in our next
  !*      iteration of the loop, we set up 5 rings, each one set up around
  !*      the points found in the first iteration (B,D,E,F,G), and we check
  !*      the 8 points around each of those points.  A logical array is
  !*      used so that as soon as a point is found, it is flagged as being
  !*      found.  In this way, when we look at the ring around point D, for
  !*      example, we won't pick point X again and set up another ring
  !*      around it in the next ring iteration and end up in an infinite
  !*      loop, going back and forth between point X and point D.  While
  !*      checking the 8 points in a ring, if a found data value is above
  !*      our contour interval (i.e., >= 989 mb), we just ignore the
  !*      point; we only mark points that are in our contour interval,
  !*      and again, if we find a point below our contour interval, we
  !*      exit the subroutine with a flag indicating a closed contour was
  !*      NOT found.  So in this method, we keep spreading out from the
  !*      initial local minimum and creating and checking new rings until
  !*      we either: (a) Hit the edge of the regional grid, in which case
  !*      we consider a closed contour NOT found, (b) Run into a data
  !*      point that has been marked as being under the influence of
  !*      another nearby low, in which case we consider a closed contour
  !*      NOT found, (c) Run into a point which is below (above) our
  !*      contour interval for a min (max) check, in which case we
  !*      consider a closed contour NOT found, or (d) we run out of
  !*      points to keep searching, we have no rings left to create and
  !*      check because all of the surrounding points are above (below)
  !*      our contour interval for a min (max) check, and by default we
  !*      consider this a closed contour and return to the calling
  !*      subroutine a flag indicating such.
  !*
  !*               + + + + + + + + + +
  !*               + + + + + + + + + +
  !*               + + A B + + + + + +
  !*               + + C D X E + + + +
  !*               + + + + F G + + + +
  !*               + + + + + H I + + +
  !*               + + + + + + + + + +
  !*               + + + + + + + + + +
  !*
  !*  UPDATE: This subroutine was updated to keep searching for
  !*      multiple closed contours until it can't find anymore.  The
  !*      input parameter num_requested_contours dictates how many
  !*      contours to search for.  In the case of just trying to roughly
  !*      locate new centers and establish that there is a closed
  !*      circulation, num_requested_contours will = 1, and we will exit
  !*      after finding that 1 contour.  But for a check after making a
  !*      full center fix, we set num_requested_contours = 999 so that
  !*      we can keep searching for all closed contours around the low.
  !*      In this 999 case, you will eventually get to a point where
  !*      there is no closed contour.  In that case, in the standard
  !*      output you will see a message telling you that you hit a point
  !*      that is not in the contour and that there is no closed contour,
  !*      but you will also notice that the ccflag = y, meaning there is
  !*      a closed contour (because you have found at least 1 closed
  !*      contour along the way).  The reason to keep searching for more
  !*      closed contours is that we can then return the value of the
  !*      outermost closed isobar.
  !*
  !*  INPUT:
  !*      imax                   :: Num pts in i-direction on grid
  !*      jmax                   :: Num pts in j-direction on grid
  !*      ix                     :: i index for location of local max or min
  !*      jx                     :: j index for location of local max or min
  !*      fxy                    :: input data array
  !*      valid_pt               :: Logical; bitmap indicating if valid data at that pt
  !*      masked_out             :: Logical. T = data point is already accounted for, under
  !*                                the influence of another nearby max or min center,
  !*                                F = data point is available to be scanned by this
  !*                                subroutine for max or min centers.
  !*      cmaxmin                :: character string ('max' or 'min') that tells this
  !*                                routine what we're looking for.
  !*      trkrinfo               :: derived type that holds/describes various tracker parms
  !*      contour_info           :: Type cint_stuff from module contours.  Contains
  !*                                contour information
  !*      num_requested_contours :: For the simple  first_ges_center check,
  !*                                this will be 1 (we just want to know if there's at
  !*                                least 1 closed contour).  For the verifying check after
  !*                                we've found a center, this will be 9999 (i.e., just keep
  !*                                searching for more contours)
  !*      get_last_isobar_flag   :: character ('y' or 'n') to indicate whether
  !*                                or not to report on the value of the last closed isobar
  !*                                and the radius of the last closed isobar.
  !*
  !*  OUTPUT:
  !*      closed_contour         :: character; A returned value of 'y' indicates that
  !*                                this routine was able to find a closed contour.
  !*      plastbar               :: Contains the value of the last closed isobar (unrounded)
  !*      rlastbar               :: Contains the mean radius of the last closed isobar
  !*
  !*  LOCAL:
  !*      num_pts_in_all_contours :: Counter for the number of pts inside of
  !*                                the contour we're looking at
  !*      next_ring_ct           :: Counter for the number of points that have been
  !*                                tagged to be used as center points for the next
  !*                                iteration of multiple_ring_loop.
  !*      next_contour_ct        :: Counter for the number of points that have been
  !*                                tagged to be used as center points in the first iteration
  !*                                through single_contour_scan_loop as we begin to scan
  !*                                points in the *next* contour interval.  This counter gets
  !*                                incremented when, for example, we are searching points
  !*                                around a current center point and we find one that is not
  !*                                in our current interval, but rather is in the next
  !*                                interval.  We want to remember this point and store the
  !*                                location, so we increment this counter and store the
  !*                                location in next_contour_i and next_contour_j arrays.
  !*      beyond_contour_ct      :: Counter for the number of points that have been
  !*                                tagged to be used as center points for some subsequent
  !*                                iteration of successive_contours_loop.  This is
  !*                                different from next_contour_ct, which is used to hold
  !*                                the locations of points that are definitely in the
  !*                                *next* contour interval.  Here, we have points that we
  !*                                just store in a pool of potential points to be searched
  !*                                in future iterations.  These points can come about in
  !*                                cases where there is a very intense, very compact low
  !*                                with a tight pressure gradient, such that multiple
  !*                                contour intervals could be spanned in between 2 adjacent
  !*                                gridpoints (this is especially the case if the contour
  !*                                interval you have chosen is small).  You need to be
  !*                                careful with how you handle this array.  Once you find
  !*                                that you have searchable points in next_contour_i or
  !*                                next_contour_j, do not just simply empty out this
  !*                                beyond_contour count and its i and j arrays.  The
  !*                                reason being that some of these "beyond" points may end
  !*                                up being used and searched in subsequent iterations, but
  !*                                not if we just delete them now.
  !*
  !****************************************************************************
  subroutine check_closed_contour (imax, jmax, ix, jx, fxy, valid_pt, masked_out, closed_contour, cmaxmin, trkrinfo, &
                                  & num_requested_contours, contour_info, get_last_isobar_flag, plastbar, rlastbar,  &
                                  & zzct1, zzct2, zzct3, icccret)

    use set_max_parms; use trkrparms; use contours; use grid_bounds; use verbose_output

    implicit none

    type (trackstuff)    :: trkrinfo
    type (cint_stuff)    :: contour_info

    integer              :: i, j, ir, iria, irja, irx, jrx, ix, jx, imax, jmax
    integer              :: nb, ibx, jby, nct, iflip
    integer              :: mr, ringct, ixp1, ixm1, jxp1, jxm1, nring, iter
    integer              :: icenx, jcenx, icccret, next_ring_ct, igicwret
    integer              :: num_pts_in_all_contours, next_contour_ct
    integer              :: beyond_contour_ct
    integer(kind=8)      :: zzct1, zzct2, zzct3
    integer              :: num_pts_in_one_contour
    integer              :: num_requested_contours, num_found_contours
    integer              :: nm, im, jm, inall, insingle, isc_count, rlast_distct
    character(len=1)     :: found_a_point_in_our_contour, closed_contour
    character(len=1)     :: found_a_point_below_contour
    character(len=1)     :: found_a_point_above_contour, get_last_isobar_flag
    character(len=*)     :: cmaxmin
    logical(1)           :: still_scanning
    logical(1)           :: valid_pt(imax,jmax), masked_out(imax,jmax)
    logical(1)           :: point_is_already_in_our_contour(imax,jmax)
    logical(1)           :: point_is_already_in_next_contour(imax,jmax)
    logical(1)           :: point_is_already_in_beyond_pool(imax,jmax)
    integer              :: isni, isnj, inci, incj, ibci, ibcj, ihmi, ihmj, itmi, itmj
    integer, allocatable :: search_next_i(:)
    integer, allocatable :: search_next_j(:)
    integer, allocatable :: next_contour_i(:)
    integer, allocatable :: next_contour_j(:)
    integer, allocatable :: beyond_contour_i(:)
    integer, allocatable :: beyond_contour_j(:)
    integer, allocatable :: hold_mask_i_loc(:)
    integer, allocatable :: hold_mask_j_loc(:)
    integer, allocatable :: temp_mask_i_loc(:)
    integer, allocatable :: temp_mask_j_loc(:)
    integer, allocatable :: ringposi(:),ringposj(:)
    real                 :: fxy(imax,jmax), contvals(maxconts)
    real                 :: contlo, conthi, xcentval, contlo_next, conthi_next
    real                 :: dist, degrees, rlast_distsum, plastbar, rlastbar

    if (allocated(search_next_i))    deallocate (search_next_i)
    if (allocated(search_next_j))    deallocate (search_next_j)
    if (allocated(next_contour_i))   deallocate (next_contour_i)
    if (allocated(next_contour_j))   deallocate (next_contour_j)
    if (allocated(beyond_contour_i)) deallocate (beyond_contour_i)
    if (allocated(beyond_contour_j)) deallocate (beyond_contour_j)
    if (allocated(hold_mask_i_loc))  deallocate (hold_mask_i_loc)
    if (allocated(hold_mask_j_loc))  deallocate (hold_mask_j_loc)
    if (allocated(temp_mask_i_loc))  deallocate (temp_mask_i_loc)
    if (allocated(temp_mask_j_loc))  deallocate (temp_mask_j_loc)

    allocate (search_next_i (imax * jmax),         stat = isni)
    allocate (search_next_j (imax * jmax),         stat = isnj)
    allocate (next_contour_i(imax * jmax),         stat = inci)
    allocate (next_contour_j(imax * jmax),         stat = incj)
    allocate (beyond_contour_i((imax * jmax) / 2), stat = ibci)
    allocate (beyond_contour_j((imax * jmax) / 2), stat = ibcj)
    allocate (hold_mask_i_loc(imax * jmax),        stat = ihmi)
    allocate (hold_mask_j_loc(imax * jmax),        stat = ihmj)
    allocate (temp_mask_i_loc(imax * jmax),        stat = itmi)
    allocate (temp_mask_j_loc(imax * jmax),        stat = itmj)

    if (isni /= 0 .or. isnj /= 0 .or. inci /= 0 .or. incj /= 0 .or. ibci /= 0 .or. ibcj /= 0 .or. &
        ihmi /= 0 .or. ihmj /= 0 .or. itmi /= 0 .or. itmj /= 0) then

      if (verb .ge. 1) then
        print *, ' '
        print *, '!!! ERROR in check_closed_contour allocating'
        print *, '!!! various search, hold and temp arrays.'
        print *, '!!! isni = ', isni, ' isnj = ', isnj
        print *, '!!! inci = ', inci, ' incj = ', incj
        print *, '!!! ibci = ', ibci, ' ibcj = ', ibcj
        print *, '!!! ihmi = ', ihmi, ' ihmj = ', ihmj
        print *, '!!! itmi = ', itmi, ' itmj = ', itmj
        print *, ' '
      endif
      STOP 98
    endif

    closed_contour          = 'n'
    xcentval                = fxy(ix,jx)
    num_found_contours      = 0
    next_contour_ct         = 0
    beyond_contour_ct       = 0
    num_pts_in_all_contours = 0
    hold_mask_i_loc         = 0
    hold_mask_j_loc         = 0
    beyond_contour_i        = 0
    beyond_contour_j        = 0
    point_is_already_in_our_contour  = .false.
    point_is_already_in_beyond_pool  = .false.
    icccret   = 0
    isc_count = 0
    plastbar  = -999.0
    rlastbar  = -999.0

    zzct1 = zzct1 + 1

    if (verb .ge. 3) then
      print *, ' '
      print *, '*-----------------------------------------------*'
      print *, '* Top of check_closed_contour, ix = ', ix, ' jx = ', jx
      print *, '*-----------------------------------------------*'
      print *, ' '
      print *, 'fxy(ix,jx) = ', fxy(ix,jx), ' xcentval = ', xcentval
    endif

    i = 1
    do while (i <= maxconts)
      if (cmaxmin == 'min') then
        contvals(i) = xcentval + real(i - 1) * trkrinfo%contint
        i = i + 1
      else
        iflip = maxconts - i + 1
        contvals(iflip) = xcentval - real(i - 1) * trkrinfo%contint
        i = i + 1
      endif
    enddo

    do while (num_found_contours < num_requested_contours) ! successive_contours_loop
      isc_count = isc_count + 1
      point_is_already_in_next_contour = .false.
      zzct2 = zzct2 + 1
      i = 1

      do while (i < maxconts)
        if (cmaxmin == 'min') then
          if (contvals(i) <= xcentval .and. xcentval < contvals(i+1)) then

            if (verb .ge. 3) then
              print *, 'At A, num_found_contours = ', num_found_contours
            endif

            contlo = contvals(i + num_found_contours)
            conthi = contvals(i + 1 + num_found_contours)

            if (verb .ge. 3) then
              print *, 'At A, contlo = ', contlo, ' conthi = ', conthi
            endif
            exit
          endif
          
        else
          if (contvals(i) < xcentval .and. xcentval <= contvals(i+1)) then
            contlo = contvals(i - num_found_contours)
            conthi = contvals(i - num_found_contours + 1)
            exit
          endif
        endif
        i = i + 1
      enddo

      if (verb .ge. 3) then
        print *, ' '
        print *, 'num_found_contours = ', num_found_contours
        print *, '            contlo = ', contlo, ' conthi = ', conthi
        print *, '          xcentval = ', xcentval
      endif

      temp_mask_i_loc = 0
      temp_mask_j_loc = 0

      zzct3 = zzct3 + 1

      iter  = 1
      num_pts_in_one_contour = 0
      still_scanning = .true.

      rlast_distsum = 0.0
      rlast_distct  = 0

      do while (still_scanning)  ! single_contour_scan_loop

        if (iter == 1 .and. num_found_contours == 0) then
          ringct = 1
          search_next_i(1) = ix
          search_next_j(1) = jx

        else if (iter == 1 .and. num_found_contours > 0) then
          if (next_contour_ct == 0) then
            if (verb .ge. 3) then
              print *, ' '
              print *, 'ALERT: next_contour_ct = 0 '
            endif

            if (cmaxmin == 'min') then
              contlo_next = conthi
              conthi_next = conthi + trkrinfo%contint

              do nb = 1, beyond_contour_ct  ! bey_con_min_loop
                ibx = beyond_contour_i(nb)
                jby = beyond_contour_j(nb)

                if (.not. point_is_already_in_beyond_pool(ibx,jby)) then
                  cycle   ! bey_con_min_loop
                endif

                if (fxy(ibx,jby) >= contlo_next .and. fxy(ibx,jby) <  conthi_next) then
                  next_contour_ct = next_contour_ct + 1
                  next_contour_i(next_contour_ct) = ibx
                  next_contour_j(next_contour_ct) = jby
                  point_is_already_in_beyond_pool(ibx, jby) = .false.
                endif
              enddo  ! bey_con_min_loop

            else
              contlo_next = contlo - trkrinfo%contint
              conthi_next = contlo

              do nb = 1, beyond_contour_ct  ! bey_con_max_loop
                ibx = beyond_contour_i(nb)
                jby = beyond_contour_j(nb)

                if (.not. point_is_already_in_beyond_pool(ibx,jby)) then
                  cycle  ! bey_con_max_loop
                endif

                if (fxy(ibx,jby) >  contlo_next .and. fxy(ibx,jby) <= conthi_next) then
                  next_contour_ct = next_contour_ct + 1
                  next_contour_i(next_contour_ct) = ibx
                  next_contour_j(next_contour_ct) = jby
                  point_is_already_in_beyond_pool(ibx,jby) = .false.
                endif
              enddo  ! bey_con_max_loop
            endif

            if (next_contour_ct > 0) then
              ringct = next_contour_ct

            else
              if (verb .ge. 3) then
                print *, ' '
                print *, '!!! XXX next_contour_ct not > 0 !!!'
                print *, 'next_contour_ct   = ', next_contour_ct
                print *, 'beyond_contour_ct = ', beyond_contour_ct
                print *, '           ringct = ', ringct
                print *, '     next_ring_ct = ', next_ring_ct
                print *, 'cycling to top of successive_contours_loop..'
                print *, ' '
              endif

              num_found_contours = num_found_contours + 1
              cycle ! successive_contours_loop
            endif

          else
            ringct = next_contour_ct
          endif

          do nring = 1, ringct
            search_next_i(nring) = next_contour_i(nring)
            search_next_j(nring) = next_contour_j(nring)
          enddo

          next_contour_ct = 0

        else
          ringct = next_ring_ct
        endif

        if (allocated(ringposi)) deallocate (ringposi)
        if (allocated(ringposj)) deallocate (ringposj)

        allocate (ringposi(ringct), stat = iria)
        allocate (ringposj(ringct), stat = irja)

        if (iria /= 0 .or. irja /= 0) then
          if (verb .ge. 1) then
            print *, ' '
            print *, '!!! ERROR in check_closed_contour allocating'
            print *, '!!! various ring arrays.  iria = ', iria
            print *, '!!! irja = ', irja
            print *, ' '
          endif
          STOP 98
        endif

        do nring = 1, ringct
          ringposi(nring) = search_next_i(nring)
          ringposj(nring) = search_next_j(nring)
        enddo

        next_ring_ct = 0

        do nb = 1, beyond_contour_ct  ! check_beyond_loop
          ibx = beyond_contour_i(nb)
          jby = beyond_contour_j(nb)

          if (.not. point_is_already_in_beyond_pool(ibx,jby)) then
            cycle   ! check_beyond_loop
          endif

          do nring = 1, ringct
            if (ibx == ringposi(nring) .and. jby == ringposj(nring)) then
              point_is_already_in_beyond_pool(ibx,jby) = .false.
            endif
          enddo
        enddo  ! check_beyond_loop

        do mr = 1, ringct  ! multiple_ring_loop
          icenx = ringposi(mr)
          jcenx = ringposj(mr)
          call get_ijplus1_check_wrap (imax, jmax, icenx, jcenx, ixp1, jxp1, ixm1, jxm1, trkrinfo, igicwret)

          if (igicwret /= 0) then
            if (verb .ge. 3) then
              print *, ' '
              print *, '!!! NO CLOSED CONTOUR: The call to '
              print *, '!!! get_ijplus1_check_wrap indicates the'
              print *, '!!! max/min contour extends past the edge of'
              print *, '!!! our regional grid. '
              print *, ' '
              print *, ' '
            endif

            do nm = 1, num_pts_in_all_contours
              im = hold_mask_i_loc(nm)
              jm = hold_mask_j_loc(nm)
              masked_out(im, jm) = .true.
            enddo

            deallocate (ringposi);       deallocate (ringposj)
            deallocate (search_next_i);  deallocate (search_next_j)
            deallocate (next_contour_i); deallocate (next_contour_j)
            deallocate (beyond_contour_i)
            deallocate (beyond_contour_j)
            deallocate (hold_mask_i_loc)
            deallocate (hold_mask_j_loc)
            deallocate (temp_mask_i_loc)
            deallocate (temp_mask_j_loc)
            icccret = 0
            return
          endif

          do ir = 1, 9  ! individual_ring_loop

            select case (ir)
              case (1); irx = ixm1;  jrx = jcenx;  !     2       3       4
              case (2); irx = ixm1;  jrx = jxm1;   !
              case (3); irx = icenx; jrx = jxm1;   !
              case (4); irx = ixp1;  jrx = jxm1;   !     1 (icenx,jcenx) 5
              case (5); irx = ixp1;  jrx = jcenx;  !
              case (6); irx = ixp1;  jrx = jxp1;   !
              case (7); irx = icenx; jrx = jxp1;   !     8       7       6
              case (8); irx = ixm1;  jrx = jxp1;   !
              case (9); irx = icenx; jrx = jcenx;  ! = center pt of ring
            end select

            if (.not. valid_pt(irx,jrx)) then
              if (verb .ge. 3) then
                print *, ' '
                print *, '!!! NOTE: In check_closed_contour, while '
                print *, '!!!    checking points around (icenx,jcenx) ='
                print *, '!!!    (', icenx, ',', jcenx,' ), we hit a non-'
                print *, '!!!    valid point, meaning we are near the'
                print *, '!!!    bounds of the grid, or at least the '
                print *, '!!!    bounds of the valid data for this '
                print *, '!!!    grid.  We will skip the'
                print *, '!!!    search for this center.'
                print *, '!!! '
                print *, '!!! (i,j) of non-valid pt = (', irx, ',', jrx,')'
                print *, '!!! '
              endif

              do nm = 1, num_pts_in_all_contours
                im = hold_mask_i_loc(nm)
                jm = hold_mask_j_loc(nm)
                masked_out(im, jm) = .true.
              enddo

              deallocate (ringposi);       deallocate (ringposj)
              deallocate (search_next_i);  deallocate (search_next_j)
              deallocate (next_contour_i); deallocate (next_contour_j)
              deallocate (beyond_contour_i)
              deallocate (beyond_contour_j)
              deallocate (hold_mask_i_loc)
              deallocate (hold_mask_j_loc)
              deallocate (temp_mask_i_loc)
              deallocate (temp_mask_j_loc)
              icccret = 0
              return
            endif

            if (masked_out(irx,jrx)) then
              if (verb .ge. 3) then
                print *, ' '
                print *, '!!! NOTE: In check_closed_contour, while '
                print *, '!!!    checking points around (icenx,jcenx)='
                print *, '!!!    (', icenx, ',', jcenx,'), we hit a point'
                print *, '!!!    that has been masked out, meaning it'
                print *, '!!!    belongs under the influence of '
                print *, '!!!    another nearby low, so we will skip'
                print *, '!!!    the search for this center....'
                print *, '!!!  '
                print *, '!!! Min central value      = ', xcentval
                print *, '!!! (i,j) of central value = (', ix, ',', jx,')'
                print *, '!!!  '
                print *, '!!! Masked-out value found = ', fxy(irx,jrx)
                print *, '!!! (i,j) of masked value  = (', irx, ',', jrx,')'
                print *, '!!!  '
                print *, '!!! Lower bound of contour interval = ', contlo
                print *, '!!! Upper bound of contour interval = ', conthi
                print *, '!!!    Contour interval = ', trkrinfo%contint
                print *, '!!!    '
                print *, '!!! closed_contour flag = ', closed_contour
                print *, '!!!    '
              endif

              do nm = 1, num_pts_in_all_contours
                im = hold_mask_i_loc(nm)
                jm = hold_mask_j_loc(nm)
                masked_out(im, jm) = .true.
              enddo

              deallocate (ringposi);       deallocate (ringposj)
              deallocate (search_next_i);  deallocate (search_next_j)
              deallocate (next_contour_i); deallocate (next_contour_j)
              deallocate (beyond_contour_i)
              deallocate (beyond_contour_j)
              deallocate (hold_mask_i_loc)
              deallocate (hold_mask_j_loc)
              deallocate (temp_mask_i_loc)
              deallocate (temp_mask_j_loc)
              icccret = 0
              return
            endif

            if (point_is_already_in_our_contour(irx,jrx)) then
              cycle   ! individual_ring_loop
            endif

            found_a_point_below_contour = 'n'
            found_a_point_above_contour = 'n'
            if (cmaxmin == 'min') then
              if (fxy(irx,jrx) < xcentval .or. fxy(irx,jrx) < contlo) then
                found_a_point_below_contour = 'y'
              endif
            else
              if (fxy(irx,jrx) > xcentval .or. fxy(irx,jrx) > conthi) then
                found_a_point_above_contour = 'y'
              endif
            endif

            if (found_a_point_below_contour == 'y' .or. found_a_point_above_contour == 'y') then
              if (verb .ge. 3) then
                print *, ' '
                print *, '!!! NOTE: In check_closed_contour, while '
                print *, '!!!    checking points around (icenx,jcenx) ='
                print *, '!!!    (', icenx, ',', jcenx,'), we hit a data'
                print *, '!!!    value that is less (greater) than the'
                print *, '!!!    current contour interval bound for a'
                print *, '!!!    min (max) and/or is less (greater) '
                print *, '!!!    than the minimum (maximum) central '
                print *, '!!!    value that we are centering the '
                print *, '!!!    search on.'
                print *, '!!!    '
                print *, '!!! Central value          = ', xcentval
                print *, '!!! (i,j) of central value = (', ix, ',', jx,')'
                print *, '!!!  '
                print *, '!!! Flagged value found    = ', fxy(irx,jrx)
                print *, '!!! (i,j) of flagged value = (', irx, ',', jrx,')'
                print *, '!!!   '
                print *, '!!! Lower bound of contour interval = ', contlo
                print *, '!!! Upper bound of contour interval = ', conthi
                print *, '!!! Contour interval    = ', trkrinfo%contint
                print *, '!!!    '
                print *, '!!! closed_contour flag = ', closed_contour
                print *, '!!! '
              endif

              do nm = 1, num_pts_in_all_contours
                im = hold_mask_i_loc(nm)
                jm = hold_mask_j_loc(nm)
                masked_out(im, jm) = .true.
              enddo

              deallocate (ringposi);       deallocate (ringposj)
              deallocate (search_next_i);  deallocate (search_next_j)
              deallocate (next_contour_i); deallocate (next_contour_j)
              deallocate (beyond_contour_i)
              deallocate (beyond_contour_j)
              deallocate (hold_mask_i_loc)
              deallocate (hold_mask_j_loc)
              deallocate (temp_mask_i_loc)
              deallocate (temp_mask_j_loc)
              icccret = 0
              return
            endif

            found_a_point_in_our_contour = 'n'
            if (cmaxmin == 'min') then
              if (fxy(irx,jrx) >= contlo .and. fxy(irx,jrx) < conthi) then
                found_a_point_in_our_contour = 'y'
              endif
            else
              if (fxy(irx,jrx) > contlo .and. fxy(irx,jrx) <= conthi) then
                found_a_point_in_our_contour = 'y'
              endif
            endif

            if (found_a_point_in_our_contour == 'y') then
              point_is_already_in_our_contour(irx, jrx) = .true.
              next_ring_ct = next_ring_ct + 1
              search_next_i(next_ring_ct) = irx
              search_next_j(next_ring_ct) = jrx

              num_pts_in_one_contour = num_pts_in_one_contour + 1
              temp_mask_i_loc(num_pts_in_one_contour) = irx
              temp_mask_j_loc(num_pts_in_one_contour) = jrx

              if (get_last_isobar_flag == 'y') then
                call calcdist (glon(ix), glat(jx), glon(irx), glat(jrx), dist, degrees)
                rlast_distsum = rlast_distsum + dist
                rlast_distct  = rlast_distct + 1
              endif
            endif

            if (found_a_point_in_our_contour /= 'y' .and. .not. point_is_already_in_next_contour(irx,jrx)) then
              if (cmaxmin == 'min') then
                contlo_next = conthi
                conthi_next = conthi + trkrinfo%contint
                if (fxy(irx,jrx) >= contlo_next .and. fxy(irx,jrx) < conthi_next) then
                  next_contour_ct = next_contour_ct + 1
                  next_contour_i(next_contour_ct) = irx
                  next_contour_j(next_contour_ct) = jrx
                  point_is_already_in_next_contour(irx, jrx) = .true.
                else if (fxy(irx,jrx) >= conthi_next) then
                  beyond_contour_ct = beyond_contour_ct + 1
                  beyond_contour_i(beyond_contour_ct) = irx
                  beyond_contour_j(beyond_contour_ct) = jrx
                  point_is_already_in_beyond_pool(irx, jrx) = .true.
                endif
              
              else
                contlo_next = contlo - trkrinfo%contint
                conthi_next = contlo
                if (fxy(irx,jrx) >  contlo_next .and. fxy(irx,jrx) <= conthi_next) then
                  next_contour_ct = next_contour_ct + 1
                  next_contour_i(next_contour_ct) = irx
                  next_contour_j(next_contour_ct) = jrx
                  point_is_already_in_next_contour(irx, jrx) = .true.
                else if (fxy(irx,jrx) <= contlo_next) then
                  beyond_contour_ct = beyond_contour_ct + 1
                  beyond_contour_i(beyond_contour_ct) = irx
                  beyond_contour_j(beyond_contour_ct) = jrx
                  point_is_already_in_beyond_pool(irx, jrx) = .true.
                endif
              endif
            endif
          enddo  ! individual_ring_loop
        enddo  ! multiple_ring_loop

        if (next_ring_ct > 0) then
          iter = iter + 1
        else
          icccret = 0
          still_scanning = .false.
          if (allocated(ringposi)) deallocate (ringposi)
          if (allocated(ringposj)) deallocate (ringposj)
          num_found_contours = num_found_contours + 1
          closed_contour = 'y'
          if (num_found_contours == 1) then
            if (verb .ge. 3) then
              print *, ' '
              print *, '+++ Closed contour found '
            endif
          endif
        endif
      enddo  ! single_contour_scan_loop

      do insingle = 1, num_pts_in_one_contour
        num_pts_in_all_contours = num_pts_in_all_contours + 1
        inall = num_pts_in_all_contours
        hold_mask_i_loc(inall) = temp_mask_i_loc(insingle)
        hold_mask_j_loc(inall) = temp_mask_j_loc(insingle)
      enddo

      if (get_last_isobar_flag == 'y') then
        if (cmaxmin == 'min') then
          plastbar = conthi
        else
          plastbar = contlo
        endif
        if (rlast_distct > 0) then
          rlastbar = rlast_distsum / real(rlast_distct)
          rlastbar = rlastbar * 0.539638  ! convert km to nm
        else
          rlastbar = -999.0
        endif
      endif

    enddo  ! successive_contours_loop

    if (verb .ge. 3) then
      print *, ' '
      print *, 'END SUM: num of iterations = ', isc_count
    endif

    do nm = 1, num_pts_in_all_contours
      im = hold_mask_i_loc(nm)
      jm = hold_mask_j_loc(nm)
      masked_out(im, jm) = .true.
    enddo

    if (allocated(search_next_i))    deallocate (search_next_i)
    if (allocated(search_next_j))    deallocate (search_next_j)
    if (allocated(next_contour_i))   deallocate (next_contour_i)
    if (allocated(next_contour_j))   deallocate (next_contour_j)
    if (allocated(beyond_contour_i)) deallocate (beyond_contour_i)
    if (allocated(beyond_contour_j)) deallocate (beyond_contour_j)
    if (allocated(hold_mask_i_loc))  deallocate (hold_mask_i_loc)
    if (allocated(hold_mask_j_loc))  deallocate (hold_mask_j_loc)
    if (allocated(temp_mask_i_loc))  deallocate (temp_mask_i_loc)
    if (allocated(temp_mask_j_loc))  deallocate (temp_mask_j_loc)
    if (allocated(ringposi))         deallocate (ringposi)
    if (allocated(ringposj))         deallocate (ringposj)

    return

  end subroutine check_closed_contour

  !****************************************************************************
  !*
  !*  ABSTRACT: This subroutine looks at the values for the land-sea
  !*      mask at and surrounding an input (i,j) position to determine if
  !*      less than 50% of the area surrounding the input (i,j) position
  !*      within 75 km radius is land.
  !*
  !*  INPUT:
  !*      imax                :: Num pts in i-direction on grid
  !*      jmax                :: Num pts in j-direction on grid
  !*      ix                  :: i index for location of local max or min
  !*      jx                  :: j index for location of local max or min
  !*      valid_pt            :: Logical; bitmap indicating if valid data at that pt
  !*      dx                  :: Grid spacing in x-direction
  !*      dy                  :: Grid spacing in y-direction
  !*      gm_wrap_flag        :: character flag set in getgridinfo to determine
  !*                             settings for GM-wrapping
  !*
  !*  OUTPUT:
  !*      fract_land          :: Fraction of points/area that is covered by land
  !*      point_is_over_water :: y/n: A value of 'y' is returned if <50%
  !*                             of the points/area is covered by land
  !*      iclmret             :: Return code from this routine
  !*
  !****************************************************************************
  subroutine check_land_mask (imax, jmax, ix, jx, fract_land, valid_pt, dx, dy, &
                             & point_is_over_water, ifh, gm_wrap_flag, iclmret)

    use grid_bounds; use tracked_parms; use trkrparms; use verbose_output

    implicit none

    type (trackstuff) :: trkrinfo

    integer            :: date_time(8)
    character(len=10)  :: big_ben(3)
    logical(1)         :: valid_pt(imax,jmax)
    character(len=1)   :: point_is_over_water
    character(len=*)   :: gm_wrap_flag
    integer, parameter :: numazim = 8
    integer            :: iazim, ibiret1, imax, jmax, ix, jx, iclmret, imct, bimct, ifh
    real               :: bear, targlat, targlon, xplon, yplat, rdist, xintrp_mask
    real               :: fract_land, dx, dy, xmask_sum

    iclmret = 0

    xplon = glonmin + (real(ix) - 1.0) * dx
    yplat = glatmax - (real(jx) - 1.0) * dy

    rdist = 75.0  ! always look only 75 km radius out for this particular land-sea mask application

    imct = 0

    xmask_sum = 0.0

    if (valid_pt(ix,jx)) then
      xmask_sum = xmask_sum + lsmask(ix, jx)
      imct = imct + 1
    else
      point_is_over_water = 'n'
      fract_land = 99.0
      if (verb .ge. 3) then
        print *, ' '
        print *, '+++ Land-sea mask check: !!! NO: At this input'
        print *, '+++ (ix,jx) point, there is no valid data in the'
        print *, '+++ valid_pt array, so it makes no sense to have a'
        print *, '+++ land-sea mask value here.  Set the mask value'
        print *, '+++ to N (i.e., just call it land) and return to'
        print *, '+++ the calling routine.'
        print *, '+++ '
      endif
      return
    endif

    bimct = 0

    do iazim = 1, numazim  ! azimloop CAITLYN - do some of these do loops do the same thing?
      bear = ((real(iazim - 1)) * 15.0) + 45.0
      call distbear (yplat, xplon, rdist, bear, targlat, targlon, gm_wrap_flag)

      if (gm_wrap_flag == 'maxplus360') then
        if ((xplon > 330.0 .and. xplon <= 360.0) .and. targlon < 25.0) then
          targlon = targlon + 360.0
        endif
        if (xplon > 360.0 .and.(targlon >= 0.0 .and. targlon < 180.0)) then
          targlon = targlon + 360.0
        endif
      endif

      call bilin_int_uneven (targlat, targlon, dx, dy, imax, jmax, trkrinfo, 850, 'm', xintrp_mask, &
           & valid_pt, bimct, -99, ibiret1)

      if (ibiret1 == 0) then
        xmask_sum = xmask_sum + xintrp_mask
        imct = imct + 1
      endif
    enddo  ! azimloop

    if (bimct > 0) then
      if (verb .ge. 3) then
        print *, ' '
        print *, 'Warning summary: From sub check_land_mask,'
        print *, 'calls to sub bilin_int_uneven resulted in'
        print *, '(blocked) attempts to access points outside the'
        print *, 'bounds of a regional grid.  Total # of access'
        print *, 'attempts for this call in azimloop = ', bimct
        print *, ' '
      endif
    endif

    ! now get the mean land fraction
    if (imct > 0) then
      fract_land = xmask_sum / real(imct)

      if (fract_land < 0.50) then
        point_is_over_water = 'y'
        if (verb .ge. 3) then
          print *, ' '
          print *, '+++ Land-sea mask check: +YES+ point is over water.'
          print *, '    Land-sea mask check value: fract_land = ', fract_land
        endif
      else
        point_is_over_water = 'n'
        if (verb .ge. 3) then
          print *, ' '
          print *, '!!! Land-sea mask check: NO! point is over land.'
          print *, '    Land-sea mask check value: fract_land = ', fract_land
        endif
      endif

    else
      if (verb .ge. 3) then
        print *, ' '
        print *, '!!! NOTE: Land check: imct = 0, which means no'
        print *, '    valid points were found to do the check.'
        print *, '    ix = ', ix, ' jx = ', jx
      endif
      point_is_over_water = 'n'
      fract_land          = 99.0
    endif

    return

  end subroutine check_land_mask

  !****************************************************************************
  !*
  !*  ABSTRACT: This subroutine takes an (i,j) position input and
  !*      returns the four neighboring (i,j) points to the east, south,
  !*      west and north.  The routine checks for wrap around the GM, so
  !*      that if, for example, you are on a global 360x181 grid and you
  !*      are at point i=360, then i+1 = 361, so you need something to
  !*      adjust that back to i = 1.  Likewise, if you are at i=1 and
  !*      looking for point i-1, it will adjust it to be point 360
  !*      instead of the meaningless point 0 (i=0).
  !*
  !****************************************************************************
  subroutine get_ijplus1_check_wrap (imax, jmax, i, j, iplus1, jplus1, iminus1, jminus1, trkrinfo, igicwret)

    use trkrparms; use verbose_output

    implicit none

    type (trackstuff) :: trkrinfo
    integer           :: i, j, imax, jmax, iplus1, jplus1, iminus1, jminus1, igicwret

    igicwret = 0

    jplus1  = j + 1
    jminus1 = j - 1
    iplus1  = i + 1
    iminus1 = i - 1

    if (iplus1 > imax) then
      if (trkrinfo%gridtype == 'global') then
        iplus1 = iplus1 - imax   ! if wrapping east of GM
      else
        if (verb .ge. 1) then
          print *, ' '
          print *, '!!! ERROR: Error in get_ijplus1_check_wrap.  The'
          print *, '!!!        user-requested eastern search boundary'
          print *, '!!!        is too close to the eastern bounds of'
          print *, '!!!        this regional grid.  When we check '
          print *, '!!!        neighboring points, we are going past'
          print *, '!!!        the edge of the grid by one point. '
          print *, '!!!        Cut back your requested eastern  '
          print *, '!!!        boundary by a degree or 2 in the  '
          print *, '!!!        script and resubmit....'
          print *, '!!!         '
          print *, '!!!   imax of regional grid    = ', imax
          print *, '!!!   User-requested eastern i = ', iplus1
          print *, ' '
        endif

        igicwret = 98
        return
      endif
    endif

    if (iminus1 < 1) then
      if (trkrinfo%gridtype == 'global') then
        iminus1 = imax + iminus1  ! if wrapping west of GM
      else
        if (verb .ge. 1) then
          print *, ' '
          print *, '!!! ERROR: Error in get_ijplus1_check_wrap.  The'
          print *, '!!!        user-requested western search boundary'
          print *, '!!!        is too close to the western bounds of'
          print *, '!!!        this regional grid.  When we check '
          print *, '!!!        neighboring points, we are going past'
          print *, '!!!        the edge of the grid by one point. '
          print *, '!!!        Cut back your requested western  '
          print *, '!!!        boundary by a degree or 2 in the  '
          print *, '!!!        script and resubmit....'
          print *, '!!!         '
          print *, '!!!   User-requested western i = ', iminus1
          print *, ' '
        endif

        igicwret = 98
        return
      endif
    endif

    if (jplus1 > jmax .or. jminus1 < 1) then
      if (verb .ge. 1) then
        print *, ' '
        print *, '!!! ERROR: Error in get_ijplus1_check_wrap.  The '
        print *, '!!!     user-requested northern or southern search'
        print *, '!!!     boundary is too close to the bounds of the'
        print *, '!!!     grid.  Cut back your requested northern or'
        print *, '!!!     southern boundary by a degree or 2 in the'
        print *, '!!!     script and resubmit....'
        print *, '!!! '
        print *, '!!!   User-requested northern j = ', jminus1
        print *, '!!!   User-requested southern j = ', jplus1
        print *, '!!!   jmax of grid              = ', jmax
        print *, '    '
      endif

      igicwret = 91
      return
    endif

    return

  end subroutine get_ijplus1_check_wrap

  !****************************************************************************
  !*
  !*  ABSTRACT: This subroutine uses an order n*log(n) quick sort to sort a real (dp)
  !*      array x into increasing order. The algorithim is as follows. ind is 
  !*      initialized to the ordered sequence of indices 1,...,N and all interchanges
  !*      are applied to ind. x is divided into two portions by picking a central
  !*       element t. The first and last elements are compared with t, and 
  !*       interchanges are applied as necessary so that they three values are in
  !*       ascending order. Interchanges are then applied so that all elements
  !*       greater than t are in the upper portion of the array and all elements
  !*       less than t are in the lower portion. The upper and lower indices of one
  !*       of the portions are saved in local arrays, and the process is repeated
  !*       interatively on the other portion. When a portion is completely sorted,
  !*       the process begins again by retriving the indicies bounding another
  !*       unsorted portion.
  !*
  !*  INPUT:
  !*      n         :: length of the array x
  !*      x         :: vector of length n to be sorted
  !*      ind       :: vector of length >= n
  !*
  !*  NOTE: n and x are not altered by this routine
  !*
  !*  OUTPUT:
  !*      ind       :: parameter; sequence of indices 1,...,N permuted in the same
  !*                   fashion as x would be. Thus, the ordering on
  !*                   x is defined by y(i) = x(ind(i))
  !*
  !*  LOCAL:
  !*      iu, il    :: temporary storage for the upper and lower
  !*                   indices of portions of array x
  !*      m         :: index for iu and il
  !*      i, j      :: lower and upper indices of a portion of x
  !*      k, l      :: indices in the range i,...,j
  !*      ij        :: randomly chosen index between i and j
  !*      it, itt   :: temporary storage for interchanges in ind
  !*      indx      :: temporary index for x
  !*      r         :: psudo random number for generating ij
  !*      t         :: central element of x
  !*
  !*  Code by: Alan Miller
  !*
  !****************************************************************************
  subroutine qsort(x, ind, n)

    implicit none

    integer, parameter   :: dp = SELECTED_REAL_KIND(12, 60)
    real(dp), intent(in) :: x(n)
    integer, intent(out) :: ind(n)
    integer, intent(in)  :: n
    integer              :: iu(21), il(21) ! must be dimensioned >= log(n) where log has base 2
    integer              :: m, i, j, k, l, ij, it, itt, indx
    real                 :: r
    real(dp)             :: t

    if (n <= 0) return

    do i = 1, n ! initialize ind, m, i, j, and r
      ind(i) = i
    end do

    m = 1
    i = 1
    j = n
    r = 0.375

    ! top of loop
 20 if (i >= j) go to 70
    if (r <= 0.5898437) then
      r = r + 0.0390625
    else
      r = r - 0.21875
    end if

    ! initialize k
 30 k = i

    ! select a central element of x and save it in t
    ij = i + r * (j - i)
    it = ind(ij)
    t  = x(it)

    ! if the first element of the array is > t, interchange it with t
    indx = ind(i)
    if (x(indx) > t) then
      ind(ij) = indx
      ind(i)  = it
      it      = indx
      t       = x(it)
    endif

    ! initialize l
    l = j

    ! if the last element of the array is < t, interchange it with t
    indx = ind(j)
    if (x(indx) >= t) go to 50
    ind(ij) = indx
    ind(j)  = it
    it      = indx
    t       = x(it)

    ! if the first element of the array is > t, interchange it with t
    indx = ind(i)
    if (x(indx) <= t) go to 50
    ind(ij) = indx
    ind(i)  = it
    it      = indx
    t       = x(it)
    go to 50

    ! interchange elements k an l
 40 itt    = ind(l)
    ind(l) = ind(k)
    ind(k) = itt

    ! find an element in the upper part of the array which is not larger than t
 50 l   = l - 1
    indx = ind(l)
    if (x(indx) > t) go to 50

    ! find and element in the lower part of the array which is not smaller than t
 60 k    = k + 1
    indx = ind(k)
    if (x(indx) < t) go to 60

    ! if k <= l, interchange elements k and l
    if (k <= l) go to 40

    ! save the upper and lower subscripts of the portion of the array yet to be sorted
    if (l-i > j-k) then
      il(m) = i
      iu(m) = l
      i     = k
      m     = m + 1
      go to 80
    endif

    il(m) = k
    iu(m) = j
    j     = l
    m     = m + 1
    go to 80

    ! begin again on another unsorted portion of the array
 70 m = m - 1
    if (m == 0) return
    i = il(m)
    j = iu(m)

 80 if (j-i >= 11) go to 30
    if (i == 1) go to 20
    i = i - 1

    ! sort elements i+1,...,j --> 1 <= i < j AND j-1 < 11
 90 i = i + 1
    if (i == j) go to 70
    indx = ind(i+1)
    t    = x(indx)
    it   = indx
    indx = ind(i)
    if (x(indx) <= t) go to 90
    k = i

100 ind(k+1) = ind(k)
    k        = k - 1
    indx      = ind(k)
    if (t < x(indx)) go to 100

    ind(k+1) = it
    go to 90

  end subroutine qsort
